1	import { gatewayInstallations, orgIntegrations } from "@db/app/schema";
2	import {
3	  getDefaultSyncEvents,
4	  getProvider,
5	  gwInstallationBackfillConfigSchema,
6	  type NormalizedInstallation,
7	  type ProviderName,
8	  type ResourcePickerExecuteApiFn,
9	  sourceTypeSchema,
10	} from "@repo/app-providers";
11	import type { SourceIdentifier } from "@repo/app-validation";
12	import { createPlatformCaller } from "@repo/platform-trpc/caller";
13	import type { TRPCRouterRecord } from "@trpc/server";
14	import { TRPCError } from "@trpc/server";
15	import { log } from "@vendor/observability/log/next";
16	import { and, eq } from "drizzle-orm";
17	import yaml from "yaml";
18	import { z } from "zod";
19	import { orgScopedProcedure } from "../../trpc";
20	
21	/**
22	 * Connections Router
23	 *
24	 * Manages org-level OAuth connections (GitHub, Vercel, Linear, etc.)
25	 * Queries gw_installations directly (org-scoped).
26	 *
27	 * Proxies to memory service tRPC for token vault, OAuth, and API operations.
28	 *
29	 * Table: gatewayInstallations (lightfast_gateway_installations)
30	 * Scope: Org-scoped (active org required)
31	 */
32	
33	export const connectionsRouter = {
34	  /**
35	   * Get OAuth authorize URL from the memory service.
36	   *
37	   * Proxies the memory service authorize endpoint since browsers
38	   * can't set custom headers (X-Org-Id) during popup navigation.
39	   */
40	  getAuthorizeUrl: orgScopedProcedure
41	    .input(
42	      z.object({
43	        provider: sourceTypeSchema,
44	      })
45	    )
46	    .query(async ({ ctx, input }) => {
47	      const platform = await createPlatformCaller();
48	      return platform.connections.getAuthorizeUrl({
49	        provider: input.provider,
50	        orgId: ctx.auth.orgId,
51	        connectedBy: ctx.auth.userId,
52	      });
53	    }),
54	
55	  /**
56	   * List org's OAuth integrations (all providers)
57	   *
58	   * Returns all active OAuth integrations connected by the org.
59	   */
60	  list: orgScopedProcedure.query(async ({ ctx }) => {
61	    const installations = await ctx.db
62	      .select()
63	      .from(gatewayInstallations)
64	      .where(
65	        and(
66	          eq(gatewayInstallations.orgId, ctx.auth.orgId),
67	          eq(gatewayInstallations.status, "active")
68	        )
69	      );
70	
71	    return installations.map((inst) => ({
72	      id: inst.id,
73	      sourceType: inst.provider,
74	      isActive: true,
75	      connectedAt: inst.createdAt,
76	      lastSyncAt: inst.updatedAt,
77	    }));
78	  }),
79	
80	  /**
81	   * Disconnect an integration.
82	   *
83	   * Delegates to the memory service which triggers the durable
84	   * connection-teardown workflow (gate-first: closes ingress immediately).
85	   */
86	  disconnect: orgScopedProcedure
87	    .input(
88	      z.object({
89	        integrationId: z.string(),
90	      })
91	    )
92	    .mutation(async ({ ctx, input }) => {
93	      // Fetch installation to get provider (required for disconnect)
94	      // and enforce org scoping before calling the memory service
95	      const rows = await ctx.db
96	        .select({
97	          id: gatewayInstallations.id,
98	          provider: gatewayInstallations.provider,
99	        })
100	        .from(gatewayInstallations)
101	        .where(
102	          and(
103	            eq(gatewayInstallations.id, input.integrationId),
104	            eq(gatewayInstallations.orgId, ctx.auth.orgId)
105	          )
106	        )
107	        .limit(1);
108	
109	      const installation = rows[0];
110	      if (!installation) {
111	        throw new TRPCError({
112	          code: "NOT_FOUND",
113	          message: "Integration not found or access denied",
114	        });
115	      }
116	
117	      const platform = await createPlatformCaller();
118	      await platform.connections.disconnect({
119	        id: installation.id,
120	        provider: installation.provider,
121	      });
122	
123	      // Cascade: mark all org integrations for this installation as disconnected.
124	      // This covers all providers (Vercel, Linear, Sentry, Apollo, GitHub).
125	      // The cascade here ensures the gate closes immediately on user-triggered disconnect.
126	      const now = new Date().toISOString();
127	      await ctx.db
128	        .update(orgIntegrations)
129	        .set({
130	          status: "disconnected",
131	          statusReason: "installation_revoked",
132	          updatedAt: now,
133	        })
134	        .where(eq(orgIntegrations.installationId, input.integrationId));
135	
136	      return { success: true };
137	    }),
138	
139	  /**
140	   * Update backfill configuration for a gateway installation.
141	   *
142	   * Stores depth + entityTypes on gatewayInstallations.backfillConfig.
143	   * Used by SourceSettingsForm and as defaults for notifyBackfill().
144	   */
145	  updateBackfillConfig: orgScopedProcedure
146	    .input(
147	      z.object({
148	        installationId: z.string().min(1),
149	        backfillConfig: gwInstallationBackfillConfigSchema,
150	      })
151	    )
152	    .mutation(async ({ ctx, input }) => {
153	      const result = await ctx.db
154	        .update(gatewayInstallations)
155	        .set({ backfillConfig: input.backfillConfig })
156	        .where(
157	          and(
158	            eq(gatewayInstallations.id, input.installationId),
159	            eq(gatewayInstallations.orgId, ctx.auth.orgId)
160	          )
161	        )
162	        .returning({ id: gatewayInstallations.id });
163	
164	      if (!result[0]) {
165	        throw new TRPCError({
166	          code: "NOT_FOUND",
167	          message: "Installation not found or access denied",
168	        });
169	      }
170	
171	      return { success: true };
172	    }),
173	
174	  /**
175	   * GitHub-specific operations
176	   */
177	  github: {
178	    /**
179	     * Validate and refresh installations from GitHub API
180	     *
181	     * Re-fetches installations from GitHub using stored access token
182	     * and updates the installation's providerAccountInfo.
183	     *
184	     * Returns counts of added/removed installations.
185	     */
186	    validate: orgScopedProcedure.mutation(async ({ ctx }) => {
187	      const result = await ctx.db
188	        .select()
189	        .from(gatewayInstallations)
190	        .where(
191	          and(
192	            eq(gatewayInstallations.orgId, ctx.auth.orgId),
193	            eq(gatewayInstallations.provider, "github"),
194	            eq(gatewayInstallations.status, "active")
195	          )
196	        )
197	        .limit(1);
198	
199	      const installation = result[0];
200	
201	      if (!installation) {
202	        throw new TRPCError({
203	          code: "NOT_FOUND",
204	          message: "GitHub integration not found. Please connect GitHub first.",
205	        });
206	      }
207	
208	      const providerAccountInfo = installation.providerAccountInfo;
209	      if (providerAccountInfo?.sourceType !== "github") {
210	        throw new TRPCError({
211	          code: "INTERNAL_SERVER_ERROR",
212	          message: "Invalid provider data type",
213	        });
214	      }
215	
216	      try {
217	        const platform = await createPlatformCaller();
218	
219	        // Validate that the installation still exists on GitHub (App JWT auth via proxy)
220	        const result = await platform.proxy.execute({
221	          installationId: installation.id,
222	          endpointId: "get-app-installation",
223	          pathParams: { installation_id: installation.externalId },
224	        });
225	
226	        if (result.status !== 200) {
227	          throw new Error(
228	            `GitHub installation not found: status ${result.status}`
229	          );
230	        }
231	
232	        // Update only lastValidatedAt — display data is resolved live, not cached
233	        const existingInfo = installation.providerAccountInfo;
234	        const now = new Date().toISOString();
235	        if (existingInfo?.sourceType === "github") {
236	          await ctx.db
237	            .update(gatewayInstallations)
238	            .set({
239	              providerAccountInfo: { ...existingInfo, lastValidatedAt: now },
240	              updatedAt: now,
241	            })
242	            .where(eq(gatewayInstallations.id, installation.id));
243	        }
244	
245	        return { added: 0, removed: 0, total: 1 };
246	      } catch (error: unknown) {
247	        log.error("[connections/github] validate failed", {
248	          clerkOrgId: ctx.auth.orgId,
249	          error: error instanceof Error ? error.message : String(error),
250	        });
251	
252	        throw new TRPCError({
253	          code: "INTERNAL_SERVER_ERROR",
254	          message: "Failed to validate GitHub installation",
255	          cause: error,
256	        });
257	      }
258	    }),
259	
260	    /**
261	     * Detect repository configuration (lightfast.yml)
262	     *
263	     * Checks if the repository contains a lightfast.yml configuration file
264	     * and returns its content if found.
265	     */
266	    detectConfig: orgScopedProcedure
267	      .input(
268	        z.object({
269	          integrationId: z.string(), // gatewayInstallations.id
270	          installationId: z.string(), // GitHub App installation external ID
271	          fullName: z.string(), // "owner/repo"
272	          ref: z.string().optional(), // branch/tag/sha (defaults to default branch)
273	        })
274	      )
275	      .query(async ({ ctx, input }) => {
276	        // Verify org owns this installation
277	        const result = await ctx.db
278	          .select()
279	          .from(gatewayInstallations)
280	          .where(
281	            and(
282	              eq(gatewayInstallations.id, input.integrationId),
283	              eq(gatewayInstallations.orgId, ctx.auth.orgId)
284	            )
285	          )
286	          .limit(1);
287	
288	        const installation = result[0];
289	
290	        if (!installation) {
291	          throw new TRPCError({
292	            code: "NOT_FOUND",
293	            message: "Installation not found or access denied",
294	          });
295	        }
296	
297	        // Verify the GitHub App installation is accessible via the table column
298	        if (installation.externalId !== input.installationId) {
299	          throw new TRPCError({
300	            code: "NOT_FOUND",
301	            message:
302	              "Installation not found or not accessible to this connection",
303	          });
304	        }
305	
306	        const [owner, repo] = input.fullName.split("/");
307	        if (!(owner && repo)) {
308	          throw new TRPCError({
309	            code: "BAD_REQUEST",
310	            message: "Invalid repository name format. Expected 'owner/repo'",
311	          });
312	        }
313	
314	        try {
315	          const platform = await createPlatformCaller();
316	
317	          let ref = input.ref;
318	          if (!ref) {
319	            const repoResult = await platform.proxy.execute({
320	              installationId: input.integrationId,
321	              endpointId: "get-repo",
322	              pathParams: { owner, repo },
323	            });
324	            if (repoResult.status !== 200) {
325	              throw new TRPCError({
326	                code: "INTERNAL_SERVER_ERROR",
327	                message: "Failed to fetch repository info from GitHub",
328	              });
329	            }
330	            ref = (repoResult.data as { default_branch: string })
331	              .default_branch;
332	          }
333	
334	          if (ref && !/^[a-zA-Z0-9._/-]+$/.test(ref)) {
335	            throw new TRPCError({
336	              code: "BAD_REQUEST",
337	              message:
338	                "Invalid ref format. Only alphanumeric characters, dots, dashes, slashes, and underscores are allowed.",
339	            });
340	          }
341	
342	          const candidates = [
343	            "lightfast.yml",
344	            ".lightfast.yml",
345	            "lightfast.yaml",
346	            ".lightfast.yaml",
347	          ];
348	
349	          for (const path of candidates) {
350	            const queryParams: Record<string, string> = {};
351	            if (ref) {
352	              queryParams.ref = ref;
353	            }
354	            const fileResult = await platform.proxy.execute({
355	              installationId: input.integrationId,
356	              endpointId: "get-file-contents",
357	              pathParams: { owner, repo, path },
358	              queryParams,
359	            });
360	
361	            if (fileResult.status === 404) {
362	              continue;
363	            }
364	
365	            if (fileResult.status !== 200) {
366	              throw new TRPCError({
367	                code: "INTERNAL_SERVER_ERROR",
368	                message: "Failed to fetch file contents from GitHub",
369	              });
370	            }
371	
372	            const data = fileResult.data as {
373	              content?: string;
374	              type?: string;
375	              size?: number;
376	              sha?: string;
377	            };
378	
379	            if (
380	              !Array.isArray(data) &&
381	              data.content !== undefined &&
382	              data.type !== undefined
383	            ) {
384	              const maxSize = 50 * 1024;
385	              if (typeof data.size === "number" && data.size > maxSize) {
386	                throw new TRPCError({
387	                  code: "BAD_REQUEST",
388	                  message: `Config file too large. Maximum size is ${maxSize / 1024}KB.`,
389	                });
390	              }
391	
392	              const content = Buffer.from(data.content, "base64").toString(
393	                "utf-8"
394	              );
395	
396	              try {
397	                yaml.parse(content);
398	              } catch {
399	                throw new TRPCError({
400	                  code: "BAD_REQUEST",
401	                  message: "Invalid YAML format in config file.",
402	                });
403	              }
404	
405	              return {
406	                exists: true,
407	                path,
408	                content,
409	                sha: data.sha ?? "",
410	              };
411	            }
412	          }
413	
414	          return { exists: false };
415	        } catch (error: unknown) {
416	          log.error("[connections/github] detectConfig failed", {
417	            clerkOrgId: ctx.auth.orgId,
418	            error: error instanceof Error ? error.message : String(error),
419	          });
420	
421	          throw new TRPCError({
422	            code: "INTERNAL_SERVER_ERROR",
423	            message: "Failed to detect repository configuration",
424	            cause: error,
425	          });
426	        }
427	      }),
428	  },
429	
430	  /**
431	   * Vercel-specific operations
432	   */
433	  vercel: {
434	    /**
435	     * Disconnect Vercel integration.
436	     *
437	     * Delegates to the memory service which triggers the durable
438	     * connection-teardown workflow (gate-first: closes ingress immediately).
439	     */
440	    disconnect: orgScopedProcedure.mutation(async ({ ctx }) => {
441	      // Fetch Vercel installation to get id; enforce org scoping
442	      const rows = await ctx.db
443	        .select({ id: gatewayInstallations.id })
444	        .from(gatewayInstallations)
445	        .where(
446	          and(
447	            eq(gatewayInstallations.orgId, ctx.auth.orgId),
448	            eq(gatewayInstallations.provider, "vercel")
449	          )
450	        )
451	        .limit(1);
452	
453	      const installation = rows[0];
454	      if (!installation) {
455	        throw new TRPCError({
456	          code: "NOT_FOUND",
457	          message: "Vercel integration not found",
458	        });
459	      }
460	
461	      const platform = await createPlatformCaller();
462	      await platform.connections.disconnect({
463	        id: installation.id,
464	        provider: "vercel",
465	      });
466	
467	      // Cascade: mark all org integrations for this installation as disconnected
468	      const now = new Date().toISOString();
469	      await ctx.db
470	        .update(orgIntegrations)
471	        .set({
472	          status: "disconnected",
473	          statusReason: "installation_revoked",
474	          updatedAt: now,
475	        })
476	        .where(eq(orgIntegrations.installationId, installation.id));
477	
478	      return { success: true };
479	    }),
480	  },
481	
482	  // ── Generic Resource Picker Procedures ────────────────────────────────────
483	
484	  // ── Linked Resources (orgIntegrations) ────────────────────────────────────
485	
486	  resources: {
487	    /**
488	     * List linked resources for the current org.
489	     *
490	     * Joins orgIntegrations with gatewayInstallations to return
491	     * per-resource metadata including backfill config.
492	     */
493	    list: orgScopedProcedure.query(async ({ ctx }) => {
494	      const rows = await ctx.db
495	        .select({
496	          id: orgIntegrations.id,
497	          provider: orgIntegrations.provider,
498	          providerConfig: orgIntegrations.providerConfig,
499	          providerResourceId: orgIntegrations.providerResourceId,
500	          installationId: orgIntegrations.installationId,
501	          documentCount: orgIntegrations.documentCount,
502	          backfillConfig: gatewayInstallations.backfillConfig,
503	        })
504	        .from(orgIntegrations)
505	        .leftJoin(
506	          gatewayInstallations,
507	          eq(orgIntegrations.installationId, gatewayInstallations.id)
508	        )
509	        .where(
510	          and(
511	            eq(orgIntegrations.clerkOrgId, ctx.auth.orgId),
512	            eq(orgIntegrations.status, "active")
513	          )
514	        );
515	
516	      const list = rows.map((row) => {
517	        // ProviderConfig is a discriminated union — access common fields via cast
518	        const config = row.providerConfig as {
519	          sync?: { events?: string[] };
520	          status?: { configStatus?: string };
521	        };
522	        return {
523	          id: row.id,
524	          metadata: {
525	            provider: row.provider,
526	            sync: config.sync
527	              ? { events: config.sync.events ?? [] }
528	              : undefined,
529	            status: config.status
530	              ? { configStatus: config.status.configStatus }
531	              : undefined,
532	          },
533	          displayName: row.providerResourceId,
534	          installationId: row.installationId,
535	          documentCount: row.documentCount,
536	          backfillConfig: row.backfillConfig,
537	        };
538	      });
539	
540	      return { list };
541	    }),
542	
543	    /**
544	     * Bulk-link resources from a gateway installation to this org.
545	     *
546	     * Creates new orgIntegration rows, or reactivates disconnected ones.
547	     * Returns counts of created / reactivated entries.
548	     */
549	    bulkLink: orgScopedProcedure
550	      .input(
551	        z.object({
552	          provider: sourceTypeSchema,
553	          gwInstallationId: z.string().min(1),
554	          resources: z
555	            .array(
556	              z.object({
557	                resourceId: z.string(),
558	                resourceName: z.string().optional(),
559	              })
560	            )
561	            .min(1),
562	        })
563	      )
564	      .mutation(async ({ ctx, input }) => {
565	        // Verify the installation belongs to this org
566	        const installation = await ctx.db
567	          .select({ id: gatewayInstallations.id })
568	          .from(gatewayInstallations)
569	          .where(
570	            and(
571	              eq(gatewayInstallations.id, input.gwInstallationId),
572	              eq(gatewayInstallations.orgId, ctx.auth.orgId),
573	              eq(gatewayInstallations.status, "active")
574	            )
575	          )
576	          .limit(1)
577	          .then((rows) => rows[0]);
578	
579	        if (!installation) {
580	          throw new TRPCError({
581	            code: "NOT_FOUND",
582	            message: "Installation not found or not owned by this org",
583	          });
584	        }
585	
586	        const providerDef = getProvider(input.provider);
587	        if (!providerDef) {
588	          throw new TRPCError({
589	            code: "BAD_REQUEST",
590	            message: `Unknown provider: ${input.provider}`,
591	          });
592	        }
593	
594	        const defaultSyncEvents = getDefaultSyncEvents(
595	          input.provider as ProviderName
596	        );
597	        const providerConfig = providerDef.buildProviderConfig({
598	          defaultSyncEvents: [...defaultSyncEvents],
599	        });
600	
601	        let created = 0;
602	        let reactivated = 0;
603	
604	        for (const resource of input.resources) {
605	          const existing = await ctx.db
606	            .select({ id: orgIntegrations.id })
607	            .from(orgIntegrations)
608	            .where(
609	              and(
610	                eq(orgIntegrations.installationId, input.gwInstallationId),
611	                eq(
612	                  orgIntegrations.providerResourceId,
613	                  resource.resourceId as SourceIdentifier
614	                )
615	              )
616	            )
617	            .then((rows) => rows[0]);
618	
619	          await ctx.db
620	            .insert(orgIntegrations)
621	            .values({
622	              clerkOrgId: ctx.auth.orgId,
623	              installationId: input.gwInstallationId,
624	              provider: input.provider,
625	              providerConfig,
626	              providerResourceId: resource.resourceId as SourceIdentifier,
627	            })
628	            .onConflictDoUpdate({
629	              target: [
630	                orgIntegrations.installationId,
631	                orgIntegrations.providerResourceId,
632	              ],
633	              set: {
634	                status: "active",
635	                statusReason: null,
636	                updatedAt: new Date().toISOString(),
637	              },
638	            });
639	
640	          if (existing) {
641	            reactivated++;
642	          } else {
643	            created++;
644	          }
645	        }
646	
647	        return { created, reactivated };
648	      }),
649	  },
650	
651	  generic: {
652	    listInstallations: orgScopedProcedure
653	      .input(z.object({ provider: sourceTypeSchema }))
654	      .query(async ({ ctx, input }) => {
655	        const providerDef = getProvider(input.provider);
656	        if (!providerDef) {
657	          throw new TRPCError({
658	            code: "BAD_REQUEST",
659	            message: `Unknown provider: ${input.provider}`,
660	          });
661	        }
662	
663	        const installations = await ctx.db
664	          .select()
665	          .from(gatewayInstallations)
666	          .where(
667	            and(
668	              eq(gatewayInstallations.orgId, ctx.auth.orgId),
669	              eq(gatewayInstallations.provider, input.provider),
670	              eq(gatewayInstallations.status, "active")
671	            )
672	          );
673	
674	        if (installations.length === 0) {
675	          return {
676	            installationMode: providerDef.resourcePicker.installationMode,
677	            resourceLabel: providerDef.resourcePicker.resourceLabel,
678	            installations: [] as NormalizedInstallation[],
679	          };
680	        }
681	
682	        const platform = await createPlatformCaller();
683	
684	        const enriched = await Promise.all(
685	          installations.map(async (inst) => {
686	            const executeApi: ResourcePickerExecuteApiFn = (request) =>
687	              platform.proxy.execute({
688	                installationId: inst.id,
689	                ...request,
690	              });
691	
692	            return providerDef.resourcePicker.enrichInstallation(executeApi, {
693	              id: inst.id,
694	              externalId: inst.externalId,
695	              // ProviderDefinition loses TAccountInfo generic — contravariance on
696	              // ResourcePickerDef method params collapses the union to never | null.
697	              // Runtime value is always the correct type for this provider.
698	              providerAccountInfo: inst.providerAccountInfo as any,
699	            });
700	          })
701	        );
702	
703	        return {
704	          installationMode: providerDef.resourcePicker.installationMode,
705	          resourceLabel: providerDef.resourcePicker.resourceLabel,
706	          installations: enriched,
707	        };
708	      }),
709	
710	    listResources: orgScopedProcedure
711	      .input(
712	        z.object({
713	          provider: sourceTypeSchema,
714	          installationId: z.string(),
715	        })
716	      )
717	      .query(async ({ ctx, input }) => {
718	        const providerDef = getProvider(input.provider);
719	        if (!providerDef) {
720	          throw new TRPCError({
721	            code: "BAD_REQUEST",
722	            message: `Unknown provider: ${input.provider}`,
723	          });
724	        }
725	
726	        // Verify org owns this installation
727	        const installation = await ctx.db
728	          .select()
729	          .from(gatewayInstallations)
730	          .where(
731	            and(
732	              eq(gatewayInstallations.id, input.installationId),
733	              eq(gatewayInstallations.orgId, ctx.auth.orgId),
734	              eq(gatewayInstallations.provider, input.provider),
735	              eq(gatewayInstallations.status, "active")
736	            )
737	          )
738	          .limit(1)
739	          .then((rows) => rows[0]);
740	
741	        if (!installation) {
742	          throw new TRPCError({
743	            code: "NOT_FOUND",
744	            message: "Installation not found or not owned by this org",
745	          });
746	        }
747	
748	        const platform = await createPlatformCaller();
749	
750	        const executeApi: ResourcePickerExecuteApiFn = async (request) => {
751	          const result = await platform.proxy.execute({
752	            installationId: installation.id,
753	            ...request,
754	          });
755	          if (result.status === 401) {
756	            await ctx.db
757	              .update(gatewayInstallations)
758	              .set({ status: "error" })
759	              .where(eq(gatewayInstallations.id, installation.id));
760	            throw new TRPCError({
761	              code: "UNAUTHORIZED",
762	              message: "Provider connection expired. Please reconnect.",
763	            });
764	          }
765	          return result;
766	        };
767	
768	        const resources = await providerDef.resourcePicker.listResources(
769	          executeApi,
770	          {
771	            id: installation.id,
772	            externalId: installation.externalId,
773	            // ProviderDefinition loses TAccountInfo generic — see comment above.
774	            providerAccountInfo: installation.providerAccountInfo as any,
775	          }
776	        );
777	
778	        return { resources };
779	      }),
780	  },
781	} satisfies TRPCRouterRecord;
