21	   *
22	   * Returns user data including:
23	   * - Full name
24	   * - Email addresses
25	   * - Username
26	   * - Profile image
27	   */
28	  get: userScopedProcedure.query(async ({ ctx }) => {
29	    try {
30	      const clerk = await clerkClient();
31	      const user = await clerk.users.getUser(ctx.auth.userId);
32	
33	      return {
34	        id: user.id,
35	        firstName: user.firstName,
36	        lastName: user.lastName,
37	        fullName:
38	          user.firstName && user.lastName
39	            ? `${user.firstName} ${user.lastName}`
40	            : (user.firstName ?? user.lastName ?? null),
41	        username: user.username,
42	        primaryEmailAddress: user.primaryEmailAddress?.emailAddress ?? null,
43	        imageUrl: user.imageUrl,
44	        createdAt: new Date(user.createdAt).toISOString(),
45	      };
46	    } catch (error: unknown) {
47	      log.error("[account] get profile failed", {
48	        userId: ctx.auth.userId,
49	        error: error instanceof Error ? error.message : String(error),
50	      });
51	
52	      throw new TRPCError({
53	        code: "INTERNAL_SERVER_ERROR",
54	        message: "Failed to fetch user profile",
55	        cause: error,
