1	/**
2	 * Backfill tRPC sub-router.
3	 *
4	 * Ported from apps/backfill/src/routes/trigger.ts and apps/backfill/src/routes/estimate.ts.
5	 * All procedures use serviceProcedure (JWT auth required).
6	 *
7	 * KEY CHANGES vs backfill service:
8	 * - tRPC procedures instead of Hono routes
9	 * - Sends platform/* events instead of backfill/* events
10	 * - Direct DB queries instead of gateway HTTP client for connection lookup
11	 * - Direct provider API calls instead of gw.executeApi() for estimate
12	 */
13	
14	import { db } from "@db/app/client";
15	import { gatewayInstallations, orgIntegrations } from "@db/app/schema";
16	import {
17	  type BackfillContext,
18	  getProvider,
19	  type ProviderApi,
20	  type ProviderDefinition,
21	} from "@repo/app-providers";
22	import {
23	  backfillEstimatePayload,
24	  backfillTriggerPayload,
25	} from "@repo/app-providers/contracts";
26	import type { TRPCRouterRecord } from "@trpc/server";
27	import { TRPCError } from "@trpc/server";
28	import { and, eq } from "@vendor/db";
29	import { log } from "@vendor/observability/log/next";
30	import { z } from "zod";
31	import { inngest } from "../../inngest/client";
32	import { providerConfigs } from "../../lib/provider-configs";
33	import { getActiveTokenForInstallation } from "../../lib/token-helpers";
34	import { serviceProcedure } from "../../trpc";
35	
36	// ── Backfill Router ──────────────────────────────────────────────────────
37	
38	interface Sample {
39	  hasMore: boolean;
40	  resourceId: string;
41	  returnedCount: number;
42	}
43	
44	export const backfillRouter = {
45	  /**
46	   * Trigger a backfill run.
47	   * Sends memory/backfill.run.requested event to Inngest.
48	   * Source: POST /trigger
49	   */
50	  trigger: serviceProcedure
51	    .input(backfillTriggerPayload)
52	    .mutation(async ({ input, ctx: _ctx }) => {
53	      // Verify connection exists and is active via direct DB query
54	      const installationRows = await db
55	        .select()
56	        .from(gatewayInstallations)
57	        .where(eq(gatewayInstallations.id, input.installationId))
58	        .limit(1);
59	
60	      const installation = installationRows[0];
61	      if (!installation) {
62	        throw new TRPCError({
63	          code: "NOT_FOUND",
64	          message: "Connection not found",
65	        });
66	      }
67	
68	      if (installation.status !== "active") {
69	        throw new TRPCError({
70	          code: "BAD_REQUEST",
71	          message: `Connection not active (status: ${installation.status})`,
72	        });
73	      }
74	
75	      // Tenant isolation
76	      if (installation.orgId !== input.orgId) {
77	        throw new TRPCError({
78	          code: "FORBIDDEN",
79	          message: "org_mismatch",
80	        });
81	      }
82	
83	      try {
84	        await inngest.send({
85	          name: "platform/backfill.run.requested",
86	          data: {
87	            installationId: input.installationId,
88	            provider: input.provider,
89	            orgId: input.orgId,
90	            depth: input.depth,
91	            entityTypes: input.entityTypes,
92	            holdForReplay: input.holdForReplay,
93	            correlationId: input.correlationId,
94	          },
95	        });
96	      } catch (err) {
97	        log.error("[backfill] trigger dispatch failed", {
98	          installationId: input.installationId,
99	          provider: input.provider,
100	          orgId: input.orgId,
101	          error: err instanceof Error ? err.message : String(err),
102	        });
103	        throw new TRPCError({
104	          code: "INTERNAL_SERVER_ERROR",
105	          message: `Failed to enqueue backfill: ${err instanceof Error ? err.message : String(err)}`,
106	        });
107	      }
108	
109	      return { status: "accepted", installationId: input.installationId };
110	    }),
111	
112	  /**
113	   * Cancel a running backfill.
114	   * Sends memory/backfill.run.cancelled event to Inngest.
115	   * Source: POST /trigger/cancel
116	   */
117	  cancel: serviceProcedure
118	    .input(
119	      z.object({
120	        installationId: z.string().min(1),
121	        correlationId: z.string().max(128).optional(),
122	      })
123	    )
124	    .mutation(async ({ input }) => {
125	      // Verify installation exists
126	      const installationRows = await db
127	        .select({ id: gatewayInstallations.id })
128	        .from(gatewayInstallations)
129	        .where(eq(gatewayInstallations.id, input.installationId))
130	        .limit(1);
131	
132	      if (!installationRows[0]) {
133	        throw new TRPCError({
134	          code: "NOT_FOUND",
135	          message: "Connection not found",
136	        });
137	      }
138	
139	      try {
140	        await inngest.send({
141	          name: "platform/backfill.run.cancelled",
142	          data: {
143	            installationId: input.installationId,
144	            correlationId: input.correlationId,
145	          },
146	        });
147	      } catch (err) {
148	        log.error("[backfill] cancel dispatch failed", {
149	          installationId: input.installationId,
150	          correlationId: input.correlationId,
151	          error: err instanceof Error ? err.message : String(err),
152	        });
153	        throw new TRPCError({
154	          code: "INTERNAL_SERVER_ERROR",
155	          message: `Failed to enqueue cancellation: ${err instanceof Error ? err.message : String(err)}`,
156	        });
157	      }
158	
159	      return { status: "cancelled", installationId: input.installationId };
160	    }),
161	
162	  /**
163	   * Estimate backfill scope by probing provider API page 1 for each resource x entityType.
164	   * Source: POST /estimate
165	   *
166	   * Uses direct provider API calls instead of gw.executeApi().
167	   */
168	  estimate: serviceProcedure
169	    .input(backfillEstimatePayload)
170	    .query(async ({ input }) => {
171	      const { installationId, provider, depth, entityTypes, orgId } = input;
172	
173	      // Fetch connection from DB
174	      const installationRows = await db
175	        .select()
176	        .from(gatewayInstallations)
177	        .where(eq(gatewayInstallations.id, installationId))
178	        .limit(1);
179	
180	      const installation = installationRows[0];
181	      if (!installation) {
182	        throw new TRPCError({
183	          code: "NOT_FOUND",
184	          message: "Connection not found",
185	        });
186	      }
187	
188	      // Tenant isolation
189	      if (installation.orgId !== orgId) {
190	        throw new TRPCError({
191	          code: "FORBIDDEN",
192	          message: "org_mismatch",
193	        });
194	      }
195	
196	      // Fetch resources from orgIntegrations
197	      const resources = await db
198	        .select({
199	          providerResourceId: orgIntegrations.providerResourceId,
200	        })
201	        .from(orgIntegrations)
202	        .where(
203	          and(
204	            eq(orgIntegrations.installationId, installationId),
205	            eq(orgIntegrations.status, "active")
206	          )
207	        );
208	
209	      // Resolve provider
210	      const providerDef = getProvider(provider);
211	      if (!providerDef) {
212	        throw new TRPCError({
213	          code: "BAD_REQUEST",
214	          message: `Unknown provider: ${provider}`,
215	        });
216	      }
217	      const backfill = providerDef.backfill;
218	      if (!backfill) {
219	        throw new TRPCError({
220	          code: "BAD_REQUEST",
221	          message: `Provider "${provider}" does not support backfill`,
222	        });
223	      }
224	
225	      const resolvedEntityTypes =
226	        entityTypes && entityTypes.length > 0
227	          ? entityTypes
228	          : [...backfill.defaultEntityTypes];
229	
230	      const since = new Date(
231	        Date.now() - depth * 24 * 60 * 60 * 1000
232	      ).toISOString();
233	
234	      // Get token for API calls
235	      const config = providerConfigs[provider];
236	      let token: string;
237	      try {
238	        ({ token } = await getActiveTokenForInstallation(
239	          installation,
240	          config,
241	          providerDef as ProviderDefinition
242	        ));
243	      } catch (err) {
244	        log.error("[backfill] token acquisition failed for estimate", {
245	          installationId,
246	          provider,
247	          orgId,
248	          error: err instanceof Error ? err.message : String(err),
249	        });
250	        throw new TRPCError({
251	          code: "INTERNAL_SERVER_ERROR",
252	          message: `Failed to get token: ${err instanceof Error ? err.message : String(err)}`,
253	        });
254	      }
255	
256	      const api: ProviderApi = providerDef.api;
257	
258	      // Resolve resource names live from provider API
259	      const resourceNameRequiredForRouting = ["github", "sentry"].includes(
260	        provider
261	      );
262	      const resolvedResources = (
263	        await Promise.all(
264	          resources.map(async (r) => {
265	            try {
266	              const resourceName = await backfill.resolveResourceMeta({
267	                providerResourceId: r.providerResourceId,
268	                token,
269	              });
270	              return { providerResourceId: r.providerResourceId, resourceName };
271	            } catch (resolveErr) {
272	              log.warn("[backfill] resolveResourceMeta failed", {
273	                installationId,
274	                provider,
275	                resourceId: r.providerResourceId,
276	                error:
277	                  resolveErr instanceof Error
278	                    ? resolveErr.message
279	                    : String(resolveErr),
280	              });
281	              if (resourceNameRequiredForRouting) {
282	                // GitHub/Sentry: can't estimate without valid path segments — skip
283	                return null;
284	              }
285	              // Linear/Vercel: resourceName not used in buildRequest — fallback is safe
286	              return {
287	                providerResourceId: r.providerResourceId,
288	                resourceName: r.providerResourceId,
289	              };
290	            }
291	          })
292	        )
293	      ).filter((r): r is NonNullable<typeof r> => r !== null);
294	
295	      // Probe page 1 for each resource x entityType
296	      const probeJobs = resolvedEntityTypes.flatMap((entityType) =>
297	        resolvedResources.map(
298	          async (resource): Promise<{ entityType: string; sample: Sample }> => {
299	            const entityHandler = backfill.entityTypes[entityType];
300	            if (!entityHandler) {
301	              return {
302	                entityType,
303	                sample: {
304	                  resourceId: resource.providerResourceId,
305	                  returnedCount: 0,
306	                  hasMore: false,
307	                },
308	              };
309	            }
310	
311	            const ctx: BackfillContext = {
312	              installationId,
313	              resource: {
314	                providerResourceId: resource.providerResourceId,
315	                resourceName: resource.resourceName,
316	              },
317	              since,
318	            };
319	
320	            try {
321	              const request = entityHandler.buildRequest(ctx, null);
322	              const endpoint = api.endpoints[entityHandler.endpointId];
323	              if (!endpoint) {
324	                return {
325	                  entityType,
326	                  sample: {
327	                    resourceId: resource.providerResourceId,
328	                    returnedCount: -1,
329	                    hasMore: false,
330	                  },
331	                };
332	              }
333	
334	              // Build URL
335	              let path = endpoint.path;
336	              if (request.pathParams) {
337	                for (const [key, val] of Object.entries(request.pathParams)) {
338	                  path = path.replace(`{${key}}`, encodeURIComponent(val));
339	                }
340	              }
341	
342	              let url = `${api.baseUrl}${path}`;
343	              if (
344	                request.queryParams &&
345	                Object.keys(request.queryParams).length > 0
346	              ) {
347	                url += `?${new URLSearchParams(request.queryParams).toString()}`;
348	              }
349	
350	              const authHeader = api.buildAuthHeader
351	                ? api.buildAuthHeader(token)
352	                : `Bearer ${token}`;
353	
354	              const headers: Record<string, string> = {
355	                Authorization: authHeader,
356	                ...(api.defaultHeaders ?? {}),
357	              };
358	
359	              const fetchOptions: RequestInit = {
360	                method: endpoint.method,
361	                headers,
362	                signal: AbortSignal.timeout(endpoint.timeout ?? 30_000),
363	              };
364	
365	              if (request.body) {
366	                fetchOptions.body = JSON.stringify(request.body);
367	                headers["Content-Type"] = "application/json";
368	              }
369	
370	              const response = await fetch(url, fetchOptions);
371	
372	              if (response.status !== 200) {
373	                return {
374	                  entityType,
375	                  sample: {
376	                    resourceId: resource.providerResourceId,
377	                    returnedCount: -1,
378	                    hasMore: false,
379	                  },
380	                };
381	              }
382	
383	              const data = await response.json();
384	              const processed = entityHandler.processResponse(data, ctx, null);
385	              return {
386	                entityType,
387	                sample: {
388	                  resourceId: resource.providerResourceId,
389	                  returnedCount: processed.rawCount,
390	                  hasMore: processed.nextCursor !== null,
391	                },
392	              };
393	            } catch (probeErr) {
394	              log.warn("[backfill] estimate probe failed", {
395	                installationId,
396	                provider,
397	                resourceId: resource.providerResourceId,
398	                entityType,
399	                error:
400	                  probeErr instanceof Error
401	                    ? probeErr.message
402	                    : String(probeErr),
403	              });
404	              return {
405	                entityType,
406	                sample: {
407	                  resourceId: resource.providerResourceId,
408	                  returnedCount: -1,
409	                  hasMore: false,
410	                },
411	              };
412	            }
413	          }
414	        )
415	      );
416	
417	      const probeResults = await Promise.allSettled(probeJobs);
418	
419	      // Group results by entityType
420	      const probes: Record<
421	        string,
422	        {
423	          resources: number;
424	          samples: Sample[];
425	          estimatedItems: number;
426	          estimatedPages: number;
427	        }
428	      > = {};
429	
430	      for (const result of probeResults) {
431	        if (result.status !== "fulfilled") {
432	          continue;
433	        }
434	        const { entityType, sample } = result.value;
435	        probes[entityType] ??= {
436	          resources: resolvedResources.length,
437	          samples: [],
438	          estimatedItems: 0,
439	          estimatedPages: 0,
440	        };
441	        probes[entityType].samples.push(sample);
442	      }
443	
444	      // Compute estimates per entity type
445	      for (const probe of Object.values(probes)) {
446	        probe.estimatedItems = probe.samples.reduce(
447	          (sum, s) => sum + Math.max(0, s.returnedCount),
448	          0
449	        );
450	        const pagesWithMore = probe.samples.filter((s) => s.hasMore).length;
451	        // Conservative: items from page 1 + assume 2 more pages per resource with hasMore
