28	export const proxyRouter = {
29	  /**
30	   * List available API endpoints for a connection's provider.
31	   * Source: GET /connections/:id/proxy/endpoints
32	   *
33	   * Strips responseSchema (Zod types are not JSON-serializable).
34	   */
35	  listEndpoints: serviceProcedure
36	    .input(
37	      z.object({
38	        installationId: z.string(),
39	      })
40	    )
41	    .query(async ({ input }) => {
42	      const installation = await db.query.gatewayInstallations.findFirst({
43	        where: eq(gatewayInstallations.id, input.installationId),
44	      });
45	
46	      if (!installation) {
47	        throw new TRPCError({
48	          code: "NOT_FOUND",
49	          message: "Connection not found",
50	        });
51	      }
52	
53	      const providerDef = getProvider(installation.provider);
54	      if (!providerDef) {
55	        throw new TRPCError({
56	          code: "BAD_REQUEST",
57	          message: "Unknown provider",
58	        });
59	      }
60	
61	      // Strip responseSchema (Zod types are not serializable)
62	      const endpoints: Record<
63	        string,
64	        { method: string; path: string; description: string; timeout?: number }
65	      > = {};
66	      for (const [key, ep] of Object.entries(providerDef.api.endpoints)) {
67	        endpoints[key] = {
68	          method: ep.method,
69	          path: ep.path,
70	          description: ep.description,
71	          ...(ep.timeout ? { timeout: ep.timeout } : {}),
72	        };
73	      }
74	
75	      return {
76	        provider: installation.provider,
77	        baseUrl: providerDef.api.baseUrl,
78	        endpoints,
79	      };
80	    }),
81	
82	  /**
83	   * Pure authenticated API proxy. Zero domain knowledge.
84	   * Source: POST /connections/:id/proxy/execute
85	   *
86	   * Handles: endpoint validation, auth injection, 401 retry.
87	   * Returns: raw { status, data, headers }.
88	   */
89	  execute: serviceProcedure
90	    .input(
91	      z.object({
92	        installationId: z.string(),
93	        endpointId: z.string().min(1),
94	        pathParams: z.record(z.string(), z.string()).optional(),
95	        queryParams: z.record(z.string(), z.string()).optional(),
96	        body: z.unknown().optional(),
97	      })
98	    )
99	    .mutation(async ({ input }) => {
100	      const installation = await db.query.gatewayInstallations.findFirst({
101	        where: eq(gatewayInstallations.id, input.installationId),
102	      });
103	
104	      if (!installation) {
105	        throw new TRPCError({
106	          code: "NOT_FOUND",
107	          message: "Connection not found",
108	        });
109	      }
