127	      const config = providerConfigs[providerName];
128	
129	      // Widen to base ProviderApi for runtime-dynamic endpoint/header access.
130	      // Each provider's TApi satisfies ProviderApi -- structural widening, not a cast.
131	      const api: ProviderApi = providerDef.api;
132	
133	      // Validate endpoint exists in catalog
134	      const endpoint = api.endpoints[input.endpointId];
135	      if (!endpoint) {
