137	          code: "BAD_REQUEST",
138	          message: `Unknown endpoint: ${input.endpointId}. Available: ${Object.keys(api.endpoints).join(", ")}`,
139	        });
140	      }
141	
142	      // Get active token.
143	      // If the endpoint declares its own buildAuth, use it (e.g. GitHub App JWT for
144	      // app-level endpoints). Otherwise fall through to the default per-installation token flow.
145	      let token: string;
146	      try {
147	        if (endpoint.buildAuth) {
148	          token = await endpoint.buildAuth(config);
149	        } else {
150	          // SAFETY: getProvider() returns the full generic ProviderDefinition<TConfig, ...>
151	          // but the helper takes the base ProviderDefinition. The generic parameters are
152	          // erased at runtime -- the cast is safe because the concrete type is a supertype.
153	          ({ token } = await getActiveTokenForInstallation(
154	            installation,
155	            config,
156	            providerDef as ProviderDefinition
157	          ));
158	        }
159	      } catch (err) {
160	        log.error("[proxy] token acquisition failed", {
161	          installationId: input.installationId,
162	          provider: providerName,
163	          error: err instanceof Error ? err.message : String(err),
164	        });
165	        throw new TRPCError({
166	          code: "INTERNAL_SERVER_ERROR",
167	          message: `token_error: ${err instanceof Error ? err.message : "unknown error"}`,
168	        });
169	      }
170	
171	      // Build URL
172	      let path = endpoint.path;
173	      if (input.pathParams) {
174	        for (const [key, val] of Object.entries(input.pathParams)) {
175	          path = path.replace(`{${key}}`, encodeURIComponent(val));
176	        }
177	      }
178	
179	      let url = `${api.baseUrl}${path}`;
180	      if (input.queryParams && Object.keys(input.queryParams).length > 0) {
181	        url += `?${new URLSearchParams(input.queryParams).toString()}`;
182	      }
183	
184	      // Build headers
185	      const authHeader = api.buildAuthHeader
186	        ? api.buildAuthHeader(token)
187	        : `Bearer ${token}`;
188	
189	      const headers: Record<string, string> = {
190	        Authorization: authHeader,
191	        ...(api.defaultHeaders ?? {}),
192	      };
193	
194	      // Build fetch options
195	      const fetchOptions: RequestInit = {
196	        method: endpoint.method,
197	        headers,
198	        signal: AbortSignal.timeout(endpoint.timeout ?? 30_000),
199	      };
200	
201	      if (input.body) {
202	        fetchOptions.body = JSON.stringify(input.body);
203	        headers["Content-Type"] = "application/json";
204	      }
205	
206	      // Execute with 401 retry
207	      let response = await fetch(url, fetchOptions);
208	
209	      if (response.status === 401) {
210	        let freshToken: string | null = null;
211	        if (endpoint.buildAuth) {
212	          try {
213	            freshToken = await endpoint.buildAuth(config);
214	          } catch (retryErr) {
215	            log.warn("[proxy] auth rebuild failed during 401 retry", {
216	              installationId: input.installationId,
217	              provider: providerName,
218	              endpointId: input.endpointId,
219	              error:
220	                retryErr instanceof Error ? retryErr.message : String(retryErr),
221	            });
222	            // fall through without retry
223	          }
224	        } else {
225	          // SAFETY: getProvider() returns the full generic ProviderDefinition<TConfig, ...>
226	          // but the helper takes the base ProviderDefinition. The generic parameters are
227	          // erased at runtime -- the cast is safe because the concrete type is a supertype.
228	          freshToken = await forceRefreshToken(
229	            installation,
230	            config,
231	            providerDef as ProviderDefinition
232	          );
233	        }
234	        if (freshToken && freshToken !== token) {
235	          headers.Authorization = api.buildAuthHeader
236	            ? api.buildAuthHeader(freshToken)
237	            : `Bearer ${freshToken}`;
238	          response = await fetch(url, { ...fetchOptions, headers });
239	        }
240	      }
241	
242	      // Return raw response -- no parsing, no transformation
243	      const data = await response.json().catch((parseErr: unknown) => {
244	        log.warn("[proxy] response body parse failed", {
245	          installationId: input.installationId,
246	          provider: providerName,
247	          endpointId: input.endpointId,
248	          status: response.status,
249	          error:
250	            parseErr instanceof Error ? parseErr.message : String(parseErr),
251	        });
252	        return null;
253	      });
254	      const responseHeaders: Record<string, string> = {};
255	      response.headers.forEach((value, key) => {
256	        responseHeaders[key] = value;
257	      });
258	
259	      return {
260	        status: response.status,
261	        data,
262	        headers: responseHeaders,
263	      };
264	    }),
265	} satisfies TRPCRouterRecord;
