1	/**
2	 * Platform backfill orchestrator
3	 *
4	 * Ported from apps/backfill/src/workflows/backfill-orchestrator.ts
5	 *
6	 * KEY CHANGES vs backfill service:
7	 * - Function ID: platform/backfill.orchestrator (was backfill/run.orchestrator)
8	 * - Trigger: platform/backfill.run.requested (was backfill/run.requested)
9	 * - cancelOn: platform/backfill.run.cancelled (was backfill/run.cancelled)
10	 * - Replace createGatewayClient() HTTP calls with direct DB queries
11	 * - Replace relay.replayCatchup() with direct DB query + inngest.send("platform/webhook.received")
12	 * - step.invoke() references platformEntityWorker
13	 */
14	
15	import { db } from "@db/app/client";
16	import {
17	  gatewayBackfillRuns,
18	  gatewayInstallations,
19	  gatewayWebhookDeliveries,
20	  orgIntegrations,
21	} from "@db/app/schema";
22	import { getProvider, type ProviderDefinition } from "@repo/app-providers";
23	import { and, eq, inArray, notInArray } from "@vendor/db";
24	import { NonRetriableError } from "@vendor/inngest";
25	import { log } from "@vendor/observability/log/next";
26	import { providerConfigs } from "../../lib/provider-configs";
27	import { getActiveTokenForInstallation } from "../../lib/token-helpers";
28	import { inngest } from "../client";
29	import { platformEntityWorker } from "./platform-entity-worker";
30	
31	export const platformBackfillOrchestrator = inngest.createFunction(
32	  {
33	    id: "platform/backfill.orchestrator",
34	    name: "Platform Backfill Orchestrator",
35	    retries: 3,
36	    concurrency: [
37	      // 1 backfill per connection — prevents duplicate backfills
38	      { limit: 1, key: "event.data.installationId" },
39	      // 10 total concurrent orchestrators (each lightweight — just fan-out + wait)
40	      { limit: 10 },
41	    ],
42	    cancelOn: [
43	      {
44	        event: "platform/backfill.run.cancelled",
45	        match: "data.installationId",
46	      },
47	    ],
48	    // Orchestrator waits for all entity workers — must accommodate the longest
49	    // Worst case: 15 work units (5 repos x 3 entities), 5 concurrent, each 2hr
50	    // = 15/5 * 2hr = 6hr total. Set to 8hr for safety.
51	    timeouts: { start: "2m", finish: "8h" },
52	  },
53	  { event: "platform/backfill.run.requested" },
54	  async ({ event, step }) => {
55	    const {
56	      installationId,
57	      provider,
58	      orgId,
59	      depth,
60	      entityTypes,
61	      holdForReplay,
62	      correlationId,
63	    } = event.data;
64	
65	    log.info("[backfill-orchestrator] starting", {
66	      installationId,
67	      provider,
68	      depth,
69	      entityTypes,
70	      correlationId,
71	    });
72	
73	    if (depth <= 0) {
74	      throw new NonRetriableError(
75	        `Invalid depth: ${depth} — must be a positive number of days`
76	      );
77	    }
78	
79	    // ── Step 1: Fetch connection details from DB (replaces gateway HTTP call) ──
80	    const connection = await step.run("get-connection", async () => {
81	      const installationRows = await db
82	        .select()
83	        .from(gatewayInstallations)
84	        .where(eq(gatewayInstallations.id, installationId))
85	        .limit(1);
86	
87	      const conn = installationRows[0];
88	      if (!conn) {
89	        throw new NonRetriableError(`Connection not found: ${installationId}`);
90	      }
91	      if (conn.status !== "active") {
92	        throw new NonRetriableError(
93	          `Connection is not active: ${installationId} (status: ${conn.status})`
94	        );
95	      }
96	      // Tenant isolation: verify caller-supplied orgId matches the DB-canonical value
97	      if (conn.orgId !== orgId) {
98	        throw new NonRetriableError(
99	          `orgId mismatch: event has "${orgId}" but connection belongs to "${conn.orgId}"`
100	        );
101	      }
102	
103	      // Fetch linked resources from orgIntegrations
104	      const resources = await db
105	        .select({
106	          providerResourceId: orgIntegrations.providerResourceId,
107	        })
108	        .from(orgIntegrations)
109	        .where(
110	          and(
111	            eq(orgIntegrations.installationId, installationId),
112	            eq(orgIntegrations.status, "active")
113	          )
114	        );
115	
116	      return {
117	        id: conn.id,
118	        externalId: conn.externalId,
119	        provider: conn.provider,
120	        orgId: conn.orgId,
121	        status: conn.status,
122	        resources,
123	      };
124	    });
125	
126	    log.info("[backfill-orchestrator] connection fetched", {
127	      installationId,
128	      provider,
129	      resourceCount: connection.resources.length,
130	      correlationId,
131	    });
132	
133	    // ── Step 1b: Fetch backfill history from DB (replaces gateway HTTP call) ──
134	    const backfillHistory = await step.run("get-backfill-history", async () => {
135	      return db
136	        .select({
137	          entityType: gatewayBackfillRuns.entityType,
138	          providerResourceId: gatewayBackfillRuns.providerResourceId,
139	          since: gatewayBackfillRuns.since,
140	        })
141	        .from(gatewayBackfillRuns)
142	        .where(
143	          and(
144	            eq(gatewayBackfillRuns.installationId, installationId),
145	            eq(gatewayBackfillRuns.status, "completed")
146	          )
147	        );
148	    });
149	
150	    // ── Step 2: Resolve entity types and validate provider ──
151	    const providerDef = getProvider(provider);
152	    if (!providerDef) {
153	      throw new NonRetriableError(
154	        `No backfill provider for provider: ${provider}`
155	      );
156	    }
157	    if (!providerDef.backfill) {
158	      throw new NonRetriableError(
159	        `Provider "${provider}" does not support backfill`
160	      );
161	    }
162	
163	    const resolvedEntityTypes =
164	      entityTypes && entityTypes.length > 0
165	        ? entityTypes
166	        : [...providerDef.backfill.defaultEntityTypes];
167	
168	    // Compute `since` inside a step so it's deterministic across retries/replays
169	    const since = await step.run("compute-since", () =>
170	      new Date(Date.now() - depth * 24 * 60 * 60 * 1000).toISOString()
171	    );
172	
173	    // ── Step 2b: Resolve resource names live from provider API ──
174	    const resolvedResources = await step.run(
175	      "resolve-resource-meta",
176	      async () => {
177	        const config = providerConfigs[provider];
178	        const { token } = await getActiveTokenForInstallation(
179	          {
180	            id: connection.id,
181	            externalId: connection.externalId,
182	            provider: connection.provider,
183	          },
184	          config,
185	          providerDef as ProviderDefinition
186	        );
187	
188	        // Providers where resourceName is NOT needed for API routing can fall back
189	        const resourceNameRequiredForRouting = ["github", "sentry"].includes(
190	          provider
191	        );
192	
193	        return Promise.all(
194	          connection.resources.map(async (r) => {
195	            try {
196	              const resourceName =
197	                await providerDef.backfill!.resolveResourceMeta({
198	                  providerResourceId: r.providerResourceId,
199	                  token,
200	                });
201	              return { providerResourceId: r.providerResourceId, resourceName };
202	            } catch (err) {
203	              log.warn("[backfill] failed to resolve resource meta", {
204	                providerResourceId: r.providerResourceId,
205	                error: err instanceof Error ? err.message : String(err),
206	              });
207	              if (resourceNameRequiredForRouting) {
208	                // GitHub/Sentry: resourceName is used in buildRequest pathParams — must skip
209	                return null;
210	              }
211	              // Linear/Vercel: resourceName is only used in adapter output — fallback is safe
212	              return {
213	                providerResourceId: r.providerResourceId,
214	                resourceName: r.providerResourceId,
215	              };
216	            }
217	          })
218	        ).then((results) =>
219	          results.filter((r): r is NonNullable<typeof r> => r !== null)
220	        );
221	      }
222	    );
223	
224	    // ── Step 3: Enumerate work units (resource x entityType) ──
225	    const workUnits = resolvedResources.flatMap((resource) => {
226	      return resolvedEntityTypes.map((entityType: string) => ({
227	        entityType,
228	        resource: {
229	          providerResourceId: resource.providerResourceId,
230	          resourceName: resource.resourceName,
231	        },
232	        workUnitId: `${resource.providerResourceId}-${entityType}`,
233	      }));
234	    });
235	
236	    // ── Gap-aware filtering: skip (resource, entityType) pairs covered by prior runs ──
237	    const filteredWorkUnits = workUnits.filter((wu) => {
238	      const priorRun = backfillHistory.find(
239	        (h) =>
240	          h.entityType === wu.entityType &&
241	          h.providerResourceId === wu.resource.providerResourceId
242	      );
243	      if (!priorRun) {
244	        return true; // No prior run — must fetch
245	      }
246	      // Prior run's since ≤ requested since → already covered
247	      return new Date(priorRun.since) > new Date(since);
248	    });
249	
250	    log.info("[backfill-orchestrator] work units planned", {
251	      installationId,
252	      provider,
253	      total: workUnits.length,
254	      afterFilter: filteredWorkUnits.length,
255	      skippedByGapFilter: workUnits.length - filteredWorkUnits.length,
256	      since,
257	      correlationId,
258	    });
259	
260	    if (filteredWorkUnits.length === 0) {
261	      return {
262	        success: true,
263	        installationId,
264	        provider,
265	        workUnits: workUnits.length,
266	        skipped: workUnits.length,
267	        dispatched: 0,
268	        eventsProduced: 0,
269	        eventsDispatched: 0,
270	      };
271	    }
272	
273	    log.info("[backfill-orchestrator] dispatching entity workers", {
274	      installationId,
275	      provider,
276	      count: filteredWorkUnits.length,
277	      workUnitIds: filteredWorkUnits.map((wu) => wu.workUnitId),
278	      correlationId,
279	    });
280	
281	    // ── Step 4: Invoke entity workers directly ──
282	    const completionResults = await Promise.all(
283	      filteredWorkUnits.map(async (wu) => {
284	        try {
285	          const result = await step.invoke(`invoke-${wu.workUnitId}`, {
286	            function: platformEntityWorker,
287	            data: {
288	              installationId,
289	              provider,
290	              orgId,
291	              entityType: wu.entityType,
292	              resource: wu.resource,
293	              since,
294	              depth,
295	              holdForReplay,
296	              correlationId,
297	            },
298	            timeout: "4h",
299	          });
300	          return {
301	            entityType: wu.entityType,
302	            resourceId: wu.resource.providerResourceId,
303	            success: true,
304	            eventsProduced: result.eventsProduced,
305	            eventsDispatched: result.eventsDispatched,
306	            pagesProcessed: result.pagesProcessed,
307	          };
308	        } catch (err) {
309	          return {
310	            entityType: wu.entityType,
311	            resourceId: wu.resource.providerResourceId,
312	            success: false,
313	            eventsProduced: 0,
314	            eventsDispatched: 0,
315	            pagesProcessed: 0,
316	            error: err instanceof Error ? err.message : "entity worker failed",
317	          };
318	        }
319	      })
320	    );
321	
322	    // ── Step 5: Aggregate results ──
323	    const succeeded = completionResults.filter((r) => r.success);
324	    const failed = completionResults.filter((r) => !r.success);
325	
326	    // ── Step 6: Persist run records — one per (resource, entityType) ──
327	    if (completionResults.length > 0) {
328	      await step.run("persist-run-records", async () => {
329	        const now = new Date().toISOString();
330	        for (const r of completionResults) {
331	          const sharedFields = {
332	            since,
333	            depth,
334	            status: r.success ? "completed" : "failed",
335	            pagesProcessed: r.pagesProcessed,
336	            eventsProduced: r.eventsProduced,
337	            eventsDispatched: r.eventsDispatched,
338	            error: r.success ? null : (r.error ?? null),
339	            completedAt: now,
340	            updatedAt: now,
341	          };
342	
343	          await db
344	            .insert(gatewayBackfillRuns)
345	            .values({
346	              installationId,
347	              entityType: r.entityType,
348	              providerResourceId: r.resourceId,
349	              ...sharedFields,
350	              startedAt: now,
351	            })
352	            .onConflictDoUpdate({
353	              target: [
354	                gatewayBackfillRuns.installationId,
355	                gatewayBackfillRuns.providerResourceId,
356	                gatewayBackfillRuns.entityType,
357	              ],
358	              set: sharedFields,
359	            });
360	        }
361	      });
362	    }
363	
364	    // ── Step 7: Replay held webhooks (replaces relay.replayCatchup) ──
365	    // When holdForReplay is set, entity workers persist webhooks without delivery.
366	    // After all workers complete, drain them by querying DB directly and sending
367	    // platform/webhook.received events so they are processed in chronological order.
368	    if (holdForReplay && succeeded.length > 0) {
369	      log.info("[backfill-orchestrator] replaying held webhooks", {
370	        installationId,
371	        succeededWorkers: succeeded.length,
372	        correlationId,
373	      });
374	      await step.run("replay-held-webhooks", async () => {
375	        const BATCH_SIZE = 200;
376	        const MAX_ITERATIONS = 500; // Safety cap: 500 * 200 = 100k webhooks max
377	        let iterations = 0;
378	        const processedIds: string[] = [];
379	
380	        while (iterations < MAX_ITERATIONS) {
381	          iterations++;
382	
383	          // Query un-delivered webhooks for this installation
384	          const conditions = [
385	            eq(gatewayWebhookDeliveries.installationId, installationId),
386	            eq(gatewayWebhookDeliveries.status, "held"),
387	          ];
388	          if (processedIds.length > 0) {
389	            conditions.push(
390	              notInArray(gatewayWebhookDeliveries.id, processedIds)
391	            );
392	          }
393	
394	          const deliveries = await db
395	            .select()
396	            .from(gatewayWebhookDeliveries)
397	            .where(and(...conditions))
398	            .orderBy(gatewayWebhookDeliveries.receivedAt)
399	            .limit(BATCH_SIZE);
400	
401	          if (deliveries.length === 0) {
402	            break;
403	          }
404	
405	          // Send each delivery as a platform/webhook.received event
406	          const events = deliveries
407	            .filter((d) => d.payload)
408	            .map((d) => ({
409	              name: "platform/webhook.received" as const,
410	              data: {
411	                provider: d.provider,
412	                deliveryId: d.deliveryId,
413	                eventType: d.eventType,
414	                resourceId: null as string | null,
415	                payload: JSON.parse(d.payload!) as unknown,
416	                receivedAt: new Date(d.receivedAt).getTime(),
417	                preResolved: {
418	                  connectionId: installationId,
419	                  orgId: connection.orgId,
420	                },
421	                correlationId,
422	              },
423	            }));
424	
425	          if (events.length > 0) {
426	            await inngest.send(events);
427	          }
428	
429	          // Mark replayed deliveries so they aren't re-sent on retry (held -> enqueued)
430	          const replayedIds = deliveries.map((d) => d.id);
431	          if (replayedIds.length > 0) {
432	            await db
433	              .update(gatewayWebhookDeliveries)
434	              .set({ status: "enqueued" })
435	              .where(
436	                and(
437	                  eq(gatewayWebhookDeliveries.installationId, installationId),
438	                  inArray(gatewayWebhookDeliveries.id, replayedIds)
439	                )
440	              );
441	          }
442	
443	          // Track processed IDs to exclude from next batch
444	          for (const d of deliveries) {
445	            processedIds.push(d.id);
446	          }
447	        }
448	
449	        if (iterations >= MAX_ITERATIONS) {
450	          log.error("[backfill] replay-held-webhooks hit iteration cap", {
451	            installationId,
452	            iterations,
453	            correlationId,
454	          });
455	        }
456	      });
457	    }
458	
459	    log.info("[backfill-orchestrator] complete", {
460	      installationId,
461	      provider,
462	      completed: succeeded.length,
463	      failed: failed.length,
464	      eventsProduced: completionResults.reduce(
465	        (sum, r) => sum + r.eventsProduced,
466	        0
467	      ),
468	      eventsDispatched: completionResults.reduce(
469	        (sum, r) => sum + r.eventsDispatched,
470	        0
471	      ),
472	      correlationId,
473	    });
474	
475	    return {
476	      success: failed.length === 0,
477	      installationId,
478	      provider,
479	      workUnits: workUnits.length,
480	      skipped: workUnits.length - filteredWorkUnits.length,
481	      dispatched: filteredWorkUnits.length,
482	      completed: succeeded.length,
483	      failed: failed.length,
484	      eventsProduced: completionResults.reduce(
485	        (sum, r) => sum + r.eventsProduced,
486	        0
487	      ),
488	      eventsDispatched: completionResults.reduce(
489	        (sum, r) => sum + r.eventsDispatched,
490	        0
491	      ),
492	      results: completionResults,
493	    };
494	  }
495	);
