307	        `dispatch-${entityType}-p${pageNum}`,
308	        async () => {
309	          const BATCH_SIZE = 5;
310	          const events = fetchResult.events;
311	          let count = 0;
312	
313	          for (let i = 0; i < events.length; i += BATCH_SIZE) {
314	            const batch = events.slice(i, i + BATCH_SIZE);
315	            if (batch.length === 0) {
316	              continue;
317	            }
318	
