325	                    provider,
326	                    deliveryId: webhookEvent.deliveryId,
327	                    eventType: webhookEvent.eventType,
328	                    installationId,
329	                    status: "held" as const,
330	                    payload: JSON.stringify(webhookEvent.payload),
331	                    receivedAt: new Date().toISOString(),
332	                  }))
333	                )
334	                .onConflictDoNothing();
335	            } else {
336	              // Send events to Inngest immediately
337	              await inngest.send(
338	                batch.map((webhookEvent) => ({
339	                  name: "platform/webhook.received" as const,
340	                  data: {
341	                    provider,
342	                    deliveryId: webhookEvent.deliveryId,
343	                    eventType: webhookEvent.eventType,
344	                    resourceId: null,
345	                    payload: webhookEvent.payload,
346	                    receivedAt: Date.now(),
347	                    preResolved: {
348	                      connectionId: installationId,
349	                      orgId,
350	                    },
351	                    correlationId,
352	                  },
353	                }))
354	              );
355	            }
356	            count += batch.length;
357	          }
358	          return count;
359	        }
360	      );
361	
362	      log.info("[entity-worker] page dispatched", {
363	        installationId,
364	        entityType,
365	        resource: resource.providerResourceId,
366	        page: pageNum,
367	        dispatched,
368	        correlationId,
369	      });
370	
371	      eventsDispatched += dispatched;
372	
373	      // Rate limit sleep if near threshold (dynamic, based on response headers)
374	      if (fetchResult.rateLimit) {
375	        const { remaining, resetAt, limit } = fetchResult.rateLimit;
376	        if (remaining < limit * 0.1) {
377	          const sleepMs = Math.max(0, new Date(resetAt).getTime() - Date.now());
378	          if (sleepMs > 0) {
379	            log.info("[entity-worker] rate limit sleep", {
380	              installationId,
381	              entityType,
382	              resource: resource.providerResourceId,
383	              sleepMs,
384	              resetAt,
385	              correlationId,
386	            });
387	            await step.sleep(
388	              `rate-limit-${entityType}-p${pageNum}`,
389	              `${Math.ceil(sleepMs / 1000)}s`
390	            );
391	          }
392	        }
393	      }
394	
395	      if (!fetchResult.nextCursor) {
396	        break;
397	      }
398	      if (pageNum >= MAX_PAGES) {
399	        log.warn(`[backfill] entity-worker hit MAX_PAGES cap (${MAX_PAGES})`, {
400	          installationId,
401	          entityType,
402	          resource: resource.providerResourceId,
403	          correlationId,
404	        });
405	        break;
406	      }
407	      cursor = fetchResult.nextCursor;
408	      pageNum++;
409	    }
410	
411	    log.info("[entity-worker] complete", {
412	      installationId,
413	      provider,
414	      entityType,
415	      resource: resource.providerResourceId,
416	      eventsProduced,
417	      eventsDispatched,
418	      pagesProcessed: pageNum,
419	      correlationId,
420	    });
421	
422	    return {
423	      entityType,
424	      resource: resource.providerResourceId,
425	      eventsProduced,
426	      eventsDispatched,
427	      pagesProcessed: pageNum,
428	    };
429	  }
430	);
