1	/**
2	 * Platform service tRPC initialization.
3	 *
4	 * Auth model: service-to-service JWT (not Clerk).
5	 * All callers are internal services (app, platform, inngest, cron).
6	 */
7	import { initTRPC, TRPCError } from "@trpc/server";
8	import { log } from "@vendor/observability/log/next";
9	import { createObservabilityMiddleware } from "@vendor/observability/trpc";
10	import superjson from "superjson";
11	import { ZodError } from "zod";
12	
13	import { verifyServiceJWT } from "./lib/jwt";
14	
15	// -- Auth Context -------------------------------------------------------------
16	
17	/**
18	 * Discriminated union for platform service authentication.
19	 * Every request resolves to exactly one variant.
20	 */
21	export type PlatformAuthContext =
22	  | { type: "service"; caller: string }
23	  | { type: "webhook"; provider: string }
24	  | { type: "inngest" }
25	  | { type: "cron" }
26	  | { type: "unauthenticated" };
27	
28	// -- Context Creation ---------------------------------------------------------
29	
30	/**
31	 * Create tRPC context for platform service requests.
32	 *
33	 * Auth resolution order:
34	 * 1. Bearer JWT in Authorization header -> service auth
35	 * 2. x-trpc-source header for internal identification
36	 * 3. Unauthenticated fallback
37	 */
38	export const createPlatformTRPCContext = async (opts: { headers: Headers }) => {
39	  const source = opts.headers.get("x-trpc-source") ?? "unknown";
40	
41	  // Check for service JWT in Authorization header
42	  const authHeader = opts.headers.get("authorization");
43	  if (authHeader?.startsWith("Bearer ")) {
44	    const token = authHeader.replace("Bearer ", "");
45	
46	    try {
47	      const verified = await verifyServiceJWT(token);
48	      log.info("[trpc] platform service request", {
49	        source,
