1	#!/usr/bin/env npx tsx
2	
3	/**
4	 * Dataset Verification (Pre-flight Check)
5	 *
6	 * Validates all sandbox datasets for:
7	 * - Required fields on every event
8	 * - Test data markers (:test: suffix, testData metadata)
9	 * - Chronological timeline ordering
10	 * - Cross-source reference consistency (SHAs, issue numbers, identifiers)
11	 * - Title format correctness per source type
12	 * - Source distribution sanity
13	 *
14	 * Usage:
15	 *   pnpm --filter @repo/app-test-data verify
16	 *   npx tsx src/cli/verify-datasets.ts [dataset-name]
17	 */
18	
19	import { EVENT_REGISTRY } from "@repo/app-providers";
20	import type { PostTransformEvent } from "@repo/app-providers/contracts";
21	import { listDatasets, loadDataset } from "../loader/index.js";
22	
23	interface VerifyResult {
24	  dataset: string;
25	  errors: string[];
26	  eventCount: number;
27	  sources: Record<string, number>;
28	  warnings: string[];
29	}
30	
31	function verifyDataset(name: string): VerifyResult {
32	  const result: VerifyResult = {
33	    dataset: name,
34	    eventCount: 0,
35	    errors: [],
36	    warnings: [],
37	    sources: {},
38	  };
39	
40	  let ds;
41	  try {
42	    ds = loadDataset(name);
43	  } catch (err: unknown) {
44	    const message = err instanceof Error ? err.message : String(err);
45	    result.errors.push(`Failed to load: ${message}`);
46	    return result;
47	  }
48	
49	  result.eventCount = ds.events.length;
50	
51	  // === Required fields ===
52	  for (let i = 0; i < ds.events.length; i++) {
53	    const e = ds.events[i];
54	    if (!e) {
55	      continue;
56	    }
57	    const prefix = `event[${i}]`;
58	
59	    // Cast to partial to validate fields that the type claims are required
60	    const raw = e as Partial<PostTransformEvent>;
61	    if (!raw.provider) {
62	      result.errors.push(`${prefix}: missing provider`);
63	    }
64	    if (!raw.eventType) {
65	      result.errors.push(`${prefix}: missing eventType`);
66	    }
67	    if (!raw.sourceId) {
68	      result.errors.push(`${prefix}: missing sourceId`);
69	    }
70	    if (!raw.title?.length) {
71	      result.errors.push(`${prefix}: missing or empty title`);
72	    }
73	    if (!raw.body?.length) {
74	      result.errors.push(`${prefix}: missing or empty body`);
75	    }
76	
77	    // Test data markers
78	    if (!e.sourceId.includes(":test:")) {
79	      result.errors.push(
80	        `${prefix}: sourceId missing :test: suffix (got: ${e.sourceId})`
81	      );
82	    }
83	    if (!e.attributes.testData) {
84	      result.errors.push(`${prefix}: missing testData: true in attributes`);
85	    }
86	
87	    // Track source distribution
88	    result.sources[e.provider] = (result.sources[e.provider] ?? 0) + 1;
89	  }
90	
91	  // === Title format checks (derived from EVENT_REGISTRY labels) ===
92	  // Uses startsWith("[{label}") to handle action-suffixed titles
93	  // e.g., registry label "Metric Alert" matches both "[Metric Alert Triggered]" and "[Metric Alert Resolved]"
94	  const titlePrefixCache = new Map<string, string[]>();
95	  function getTitlePrefixes(source: string): string[] {
96	    const cached = titlePrefixCache.get(source);
97	    if (cached !== undefined) {
98	      return cached;
99	    }
100	    const prefixes = [
101	      ...new Set(
102	        Object.values(EVENT_REGISTRY)
103	          .filter((e) => e.source === source)
104	          .map((e) => `[${e.label}`)
105	      ),
106	    ];
107	    titlePrefixCache.set(source, prefixes);
108	    return prefixes;
109	  }
110	
111	  for (let i = 0; i < ds.events.length; i++) {
112	    const e = ds.events[i];
113	    if (!e) {
114	      continue;
115	    }
116	    const prefix = `event[${i}]`;
117	    const validPrefixes = getTitlePrefixes(e.provider);
118	
119	    if (
120	      validPrefixes.length > 0 &&
121	      !validPrefixes.some((p) => e.title.startsWith(p))
122	    ) {
123	      result.errors.push(
124	        `${prefix}: ${e.provider} title has unexpected format: "${e.title.slice(0, 50)}"`
125	      );
126	    }
127	  }
128	
129	  // === Chronological ordering ===
130	  const timestamps = ds.events
131	    .map((e, i) => ({
132	      index: i,
133	      time: e.occurredAt ? new Date(e.occurredAt).getTime() : Number.NaN,
134	      raw: e.occurredAt,
135	    }))
136	    .filter((t) => !Number.isNaN(t.time));
137	
138	  for (let i = 1; i < timestamps.length; i++) {
139	    const prev = timestamps[i - 1];
140	    const curr = timestamps[i];
141	    if (prev && curr && curr.time < prev.time) {
142	      result.errors.push(
143	        `Timeline out of order: event[${prev.index}] (${prev.raw}) > event[${curr.index}] (${curr.raw})`
144	      );
145	    }
146	  }
147	
148	  // === Cross-source reference consistency ===
149	  verifyCrossReferences(ds.events, result);
150	
151	  return result;
152	}
153	
154	/**
155	 * Extract identifiers mentioned across all events and verify consistency
156	 */
157	function verifyCrossReferences(
158	  events: PostTransformEvent[],
159	  result: VerifyResult
160	): void {
161	  // Collect all identifiers mentioned in titles, bodies, and references
162	  const allText = events
163	    .map((e) => `${e.title} ${e.body} ${JSON.stringify(e.relations)}`)
164	    .join(" ");
165	
166	  // Extract SHA patterns (16+ hex chars that appear in multiple events)
167	  const shaPattern = /\b([a-f0-9]{16,40})\b/gi;
168	  const shaMatches = allText.match(shaPattern) ?? [];
169	  const shaCounts = new Map<string, number>();
170	  for (const sha of shaMatches) {
171	    shaCounts.set(sha, (shaCounts.get(sha) ?? 0) + 1);
172	  }
173	
174	  // SHAs that appear in multiple places should be consistent
175	  const crossRefShas = [...shaCounts.entries()].filter(
176	    ([, count]) => count >= 2
177	  );
178	  if (crossRefShas.length > 0) {
179	    for (const [sha] of crossRefShas) {
180	      const eventsWithSha = events.filter(
181	        (e) =>
182	          e.title.includes(sha) ||
183	          e.body.includes(sha) ||
184	          JSON.stringify(e.relations).includes(sha) ||
185	          JSON.stringify(e.attributes).includes(sha)
186	      );
187	      if (eventsWithSha.length < 2) {
188	        result.warnings.push(
189	          `SHA ${sha.slice(0, 12)}... appears in text but only ${eventsWithSha.length} event(s) reference it in structured data`
190	        );
191	      }
192	    }
193	  }
194	
195	  // Extract issue/PR number patterns like #NNN
196	  const issuePattern = /#(\d{2,4})\b/g;
197	  const issueNumbers = new Set<string>();
198	  let match;
199	  while ((match = issuePattern.exec(allText)) !== null) {
200	    const num = match[1];
201	    if (num) {
202	      issueNumbers.add(num);
203	    }
204	  }
205	
206	  // For each issue number, verify it appears in at least 2 events (cross-referenced)
207	  for (const num of issueNumbers) {
208	    const eventsWithNum = events.filter(
209	      (e) =>
210	        e.title.includes(`#${num}`) ||
211	        e.body.includes(`#${num}`) ||
212	        JSON.stringify(e.attributes).includes(`"${num}"`)
213	    );
214	    if (eventsWithNum.length < 2) {
215	      result.warnings.push(
216	        `Issue/PR #${num} only referenced in ${eventsWithNum.length} event(s) - may lack cross-source linking`
217	      );
218	    }
219	  }
220	
221	  // Extract Linear identifiers like LF-NNN
222	  const linearPattern = /\b([A-Z]{2,}-\d+)\b/g;
223	  const linearIds = new Set<string>();
224	  while ((match = linearPattern.exec(allText)) !== null) {
225	    const id = match[1];
226	    if (id) {
227	      linearIds.add(id);
228	    }
229	  }
230	
231	  for (const id of linearIds) {
232	    const eventsWithId = events.filter(
233	      (e) =>
234	        e.title.includes(id) ||
235	        e.body.includes(id) ||
236	        JSON.stringify(e.relations).includes(id)
237	    );
238	    if (eventsWithId.length < 2) {
239	      result.warnings.push(
240	        `Linear identifier ${id} only referenced in ${eventsWithId.length} event(s)`
241	      );
242	    }
243	  }
244	
245	  // Extract Sentry short IDs like NEURAL-847
246	  const sentryPattern = /\b([A-Z]+-\d{3,})\b/g;
247	  const sentryIds = new Set<string>();
248	  while ((match = sentryPattern.exec(allText)) !== null) {
249	    const id = match[1];
250	    // Filter out Linear identifiers (already tracked)
251	    if (id && !linearIds.has(id)) {
252	      sentryIds.add(id);
253	    }
254	  }
255	
256	  for (const id of sentryIds) {
257	    const eventsWithId = events.filter(
258	      (e) =>
259	        e.title.includes(id) ||
260	        e.body.includes(id) ||
261	        JSON.stringify(e.relations).includes(id) ||
262	        JSON.stringify(e.attributes).includes(id)
263	    );
264	    if (eventsWithId.length < 2) {
265	      result.warnings.push(
266	        `Sentry identifier ${id} only referenced in ${eventsWithId.length} event(s)`
267	      );
268	    }
269	  }
270	}
271	
272	// === Main ===
273	function main() {
274	  const targetDataset = process.argv[2];
275	  const names = targetDataset ? [targetDataset] : listDatasets();
276	
277	  console.log(`\nVerifying ${names.length} dataset(s)...\n`);
278	
279	  let totalErrors = 0;
280	  let totalWarnings = 0;
281	
282	  for (const name of names) {
283	    const result = verifyDataset(name);
284	
285	    const status =
286	      result.errors.length === 0
287	        ? "\x1b[32mPASS\x1b[0m"
288	        : "\x1b[31mFAIL\x1b[0m";
289	    console.log(`${status} ${result.dataset} (${result.eventCount} events)`);
290	
291	    if (Object.keys(result.sources).length > 0) {
292	      const sourceSummary = Object.entries(result.sources)
293	        .map(([s, c]) => `${s}:${c}`)
294	        .join(", ");
295	      console.log(`     Sources: ${sourceSummary}`);
296	    }
297	
298	    for (const err of result.errors) {
299	      console.log(`     \x1b[31mERROR\x1b[0m ${err}`);
300	    }
301	    for (const warn of result.warnings) {
302	      console.log(`     \x1b[33mWARN\x1b[0m  ${warn}`);
303	    }
304	
305	    totalErrors += result.errors.length;
306	    totalWarnings += result.warnings.length;
307	    console.log();
308	  }
309	
