132	      name,
133	      system,
134	      tools,
135	      createRuntimeContext,
136	      cache,
137	    };
138	
139	    // Store Vercel AI SDK configuration
140	    this.vercelConfig = vercelConfig as VercelAIConfig<ToolSet>;
141	  }
