149	  get model(): LanguageModel {
150	    return this.vercelConfig.model;
151	  }
152	
153	  /**
154	   * Builds parameters for streamText for the given messages and context
155	   * Returns an object that can be directly passed to streamText
156	   * Does not actually call streamText - that's handled by runtime.ts
157	   */
158	  buildStreamParams<
159	    TMessage extends UIMessage = UIMessage,
160	    TRequestContext = {},
161	    TMemoryContext = {},
162	  >({
163	    sessionId,
164	    messages,
165	    memory: _memory,
166	    resourceId,
167	    systemContext,
168	    requestContext,
169	    dataStream,
170	  }: StreamOptions<TMessage, TRequestContext, TMemoryContext>): Parameters<
171	    typeof streamText
172	  >[0] {
173	    // IMPORTANT: Do NOT refactor to `messages?.length === 0` — optional chaining returns
174	    // undefined for null/undefined, which !== 0, silently bypassing this guard.
175	    if (!messages || messages.length === 0) {
176	      throw new NoMessagesError();
177	    }
178	
179	    // Create agent-specific runtime context if provided
180	    let agentContext: TRuntimeContext | {} = {};
181	    if (this.lightfastConfig.createRuntimeContext) {
182	      try {
183	        agentContext = this.lightfastConfig.createRuntimeContext({
184	          sessionId,
185	          resourceId,
186	        });
187	      } catch (error) {
188	        throw new ContextCreationError(
189	          "runtime",
190	          error instanceof Error ? error.message : String(error),
191	          error instanceof Error ? error : undefined
192	        );
193	      }
194	    }
195	
196	    // Merge all context levels: system -> request -> agent -> dataStream
197	    // The merged context is what tools actually receive
198	    const mergedContext: SystemContext &
199	      TRequestContext &
200	      TRuntimeContext & { dataStream?: UIMessageStreamWriter<TMessage> } = {
201	      ...systemContext,
202	      ...requestContext,
203	      ...agentContext,
204	      ...(dataStream && { dataStream }), // Add dataStream if provided
205	    } as SystemContext &
206	      TRequestContext &
207	      TRuntimeContext & { dataStream?: UIMessageStreamWriter<TMessage> };
208	
209	    // Resolve tool factories into actual tools by injecting merged context
210	    const resolvedTools: ToolSet = {};
211	    if (this.lightfastConfig.tools) {
212	      const tools =
213	        typeof this.lightfastConfig.tools === "function"
214	          ? this.lightfastConfig.tools(mergedContext as TRuntimeContext)
215	          : this.lightfastConfig.tools;
216	
217	      // Validate tools is a valid object
218	      if (!tools || typeof tools !== "object") {
219	        throw new ToolExecutionError(
220	          "tools",
221	          "Tools resolution returned null, undefined, or non-object value"
222	        );
223	      }
224	
225	      for (const [name, factory] of Object.entries(tools)) {
226	        try {
227	          resolvedTools[name] = factory(
228	            mergedContext as unknown as RuntimeContext<TRuntimeContext>
229	          );
230	        } catch (error) {
231	          throw new ToolExecutionError(
232	            name,
233	            `Failed to resolve tool factory '${name}': ${error instanceof Error ? error.message : String(error)}`,
234	            error instanceof Error ? error : undefined
235	          );
236	        }
237	      }
238	    }
239	
240	    // Ensure model is set
241	    if (!this.vercelConfig.model) {
242	      throw new AgentConfigurationError("model", "Model must be configured");
243	    }
244	
245	    // Convert system config to messages with cache control
246	    let systemMessages: ModelMessage[] = [];
247	    let modelMessages: ModelMessage[];
248	
249	    if (this.lightfastConfig.cache) {
250	      try {
251	        // Use provider cache implementation
252	        systemMessages = this.lightfastConfig.cache.applySystemCaching(
253	          this.lightfastConfig.system
254	        );
255	
256	        // Convert messages to model messages
257	        const baseModelMessages = convertToModelMessages(messages, {
258	          tools: resolvedTools,
259	        });
260	
261	        // Apply message caching
262	        modelMessages = this.lightfastConfig.cache.applyMessageCaching(
263	          baseModelMessages,
264	          messages
265	        );
266	      } catch (error) {
267	        throw new CacheOperationError(
268	          "system and message caching",
269	          error instanceof Error ? error.message : String(error),
270	          error instanceof Error ? error : undefined
271	        );
272	      }
273	    } else {
274	      try {
275	        // No cache provider - use simple system message
276	        systemMessages.push({
277	          role: "system",
278	          content: this.lightfastConfig.system,
279	        });
280	
281	        // Convert messages without caching
282	        modelMessages = convertToModelMessages(messages, {
283	          tools: resolvedTools,
284	        });
285	      } catch (error) {
286	        throw new MessageConversionError(
287	          "convert to model messages",
288	          error instanceof Error ? error.message : String(error),
289	          error instanceof Error ? error : undefined
290	        );
291	      }
292	    }
293	
294	    // Prepend system messages to the model messages
295	    // This way we maintain proper typing
296	    const allModelMessages = [...systemMessages, ...modelMessages];
297	
298	    // Return the parameters for streamText
299	    // The actual streaming is handled by runtime.ts
300	    return {
301	      // Spread all Vercel AI SDK config
302	      ...this.vercelConfig,
303	      // Override with our specific runtime values
304	      messages: allModelMessages,
305	      tools: resolvedTools,
306	    } as Parameters<typeof streamText>[0];
307	  }
308	
309	  // Expose config for testing or inspection
310	  get config(): LightfastConfig<TRuntimeContext, TTools> &
311	    VercelAIConfig<ToolSet> {
312	    return {
313	      ...this.lightfastConfig,
314	      ...this.vercelConfig,
315	    };
316	  }
317	}
318	
319	/**
320	 * Factory function to create an agent with proper type inference
321	 * All tools must be created using createTool() which returns ToolFactory functions
322	 */
323	export function createAgent<
324	  TRuntimeContext = {},
325	  TTools extends ToolFactorySet<
326	    RuntimeContext<TRuntimeContext>
327	  > = ToolFactorySet<RuntimeContext<TRuntimeContext>>,
328	>(
329	  options: AgentOptions<TRuntimeContext, TTools>
330	): Agent<TRuntimeContext, TTools> {
331	  return new Agent(options);
332	}
