1	/**
2	 * Pinecone client wrapper built on the official SDK.
3	 *
4	 * Provides typed vector operations and index name helpers tailored to our store model.
5	 */
6	
7	import type { RecordMetadata } from "@pinecone-database/pinecone";
8	import { Pinecone } from "@pinecone-database/pinecone";
9	
10	import { env } from "./env";
11	import {
12	  PineconeConnectionError,
13	  PineconeError,
14	  PineconeInvalidRequestError,
15	  PineconeNotFoundError,
16	  PineconeRateLimitError,
17	} from "./errors";
18	import type {
19	  FetchResponse,
20	  QueryRequest,
21	  QueryResponse,
22	  UpdateRequest,
23	  UpsertRequest,
24	  UpsertResponse,
25	} from "./types";
26	
27	export class PineconeClient {
28	  private readonly client: Pinecone;
29	
30	  constructor() {
31	    this.client = new Pinecone({
32	      apiKey: env.PINECONE_API_KEY,
33	    });
34	  }
35	
36	  /**
37	   * Create a new Pinecone index (serverless)
38	   *
39	   * All parameters are required - caller must provide explicit configuration.
40	   * Use application-level wrapper (@repo/app-pinecone) for defaults.
41	   *
42	   * @param indexName - Name of the index to create
43	   * @param dimension - Embedding dimension
44	   * @param options - Required configuration
45	   */
46	  async createIndex(
47	    indexName: string,
48	    dimension: number,
49	    options: {
50	      metric: "cosine" | "euclidean" | "dotproduct";
51	      cloud: "aws" | "gcp" | "azure";
52	      region: string;
53	    }
54	  ): Promise<void> {
55	    try {
56	      await this.client.createIndex({
57	        name: indexName,
58	        dimension,
59	        metric: options.metric,
60	        spec: {
61	          serverless: {
62	            cloud: options.cloud,
63	            region: options.region,
64	          },
65	        },
66	        suppressConflicts: true,
67	        waitUntilReady: true,
68	      });
69	    } catch (error) {
70	      this.handleError(error);
71	    }
72	  }
73	
74	  /**
75	   * Check if an index exists
76	   *
77	   * @param indexName - Name of the index to check
78	   * @returns true if index exists, false otherwise
79	   */
80	  async indexExists(indexName: string): Promise<boolean> {
81	    try {
82	      const indexes = await this.client.listIndexes();
83	      const indexList = indexes.indexes ?? [];
84	      return indexList.some((index) => index.name === indexName);
85	    } catch (error) {
86	      // If list fails, assume index doesn't exist
87	      console.warn(`Failed to check index existence: ${String(error)}`);
88	      return false;
89	    }
90	  }
91	
92	  /**
93	   * Delete a Pinecone index
94	   */
95	  async deleteIndex(indexName: string): Promise<void> {
96	    try {
97	      await this.client.deleteIndex(indexName);
98	    } catch (error) {
99	      this.handleError(error);
100	    }
101	  }
102	
103	  /**
104	   * Upsert vectors into an index
105	   *
106	   * Generic method - works with any metadata type extending RecordMetadata
107	   *
108	   * @param indexName - Name of the index
109	   * @param request - Upsert request with vectors and metadata
110	   * @param batchSize - Number of vectors to upsert per batch
111	   * @param namespace - Optional namespace for data isolation
112	   */
113	  async upsertVectors<T extends RecordMetadata = RecordMetadata>(
114	    indexName: string,
115	    request: UpsertRequest<T>,
116	    batchSize = 100,
117	    namespace?: string
118	  ): Promise<UpsertResponse> {
119	    const index = this.client.index(indexName);
120	    const targetNamespace = namespace ? index.namespace(namespace) : index;
121	
122	    try {
123	      for (let i = 0; i < request.ids.length; i += batchSize) {
124	        const ids = request.ids.slice(i, i + batchSize);
125	        const vectors = request.vectors.slice(i, i + batchSize);
126	        const metadata = request.metadata.slice(i, i + batchSize);
127	
128	        const records = vectors.map((values, offset) => {
129	          const id = ids[offset];
130	          const meta = metadata[offset];
131	          if (id === undefined || meta === undefined) {
132	            throw new PineconeInvalidRequestError(
133	              `Missing id or metadata at offset ${String(offset)}`
134	            );
135	          }
136	          return { id, values, metadata: meta };
137	        });
138	
139	        await targetNamespace.upsert(records);
140	      }
141	
142	      return { upsertedCount: request.ids.length };
143	    } catch (error) {
144	      this.handleError(error);
145	    }
146	  }
147	
148	  /**
149	   * Delete vectors by IDs
150	   *
151	   * @param indexName - Name of the index
152	   * @param vectorIds - Array of vector IDs to delete
153	   * @param batchSize - Number of vectors to delete per batch
154	   * @param namespace - Optional namespace for data isolation
155	   */
156	  async deleteVectors(
157	    indexName: string,
158	    vectorIds: string[],
159	    batchSize = 100,
160	    namespace?: string
161	  ): Promise<void> {
162	    if (vectorIds.length === 0) {
163	      return;
164	    }
165	
166	    const index = this.client.index(indexName);
167	    const targetNamespace = namespace ? index.namespace(namespace) : index;
168	
169	    try {
170	      for (let i = 0; i < vectorIds.length; i += batchSize) {
171	        const batch = vectorIds.slice(i, i + batchSize);
172	        await targetNamespace.deleteMany(batch);
173	      }
174	    } catch (error) {
175	      this.handleError(error);
176	    }
177	  }
178	
179	  /**
180	   * Delete vectors matching a metadata filter
181	   *
182	   * @param indexName - Name of the index
183	   * @param filter - Metadata filter object
184	   * @param namespace - Optional namespace for data isolation
185	   */
186	  async deleteByMetadata(
187	    indexName: string,
188	    filter: object,
189	    namespace?: string
190	  ): Promise<void> {
191	    const index = this.client.index(indexName);
192	    const targetNamespace = namespace ? index.namespace(namespace) : index;
193	
194	    try {
195	      await targetNamespace.deleteMany(filter);
196	    } catch (error) {
197	      this.handleError(error);
198	    }
199	  }
200	
201	  /**
202	   * Configure index level settings (deletion protection, tags, etc.)
203	   */
204	  async configureIndex(
205	    indexName: string,
206	    options: {
207	      deletionProtection?: "enabled" | "disabled";
208	      tags?: Record<string, string>;
209	      spec?: unknown;
210	    }
211	  ): Promise<void> {
212	    try {
213	      await this.client.configureIndex(indexName, {
214	        deletionProtection: options.deletionProtection,
215	        spec: options.spec as never,
216	        tags: options.tags,
217	      });
218	    } catch (error) {
219	      this.handleError(error);
220	    }
221	  }
222	
223	  /**
224	   * Query similar vectors
225	   *
226	   * Generic method - works with any metadata type extending RecordMetadata
227	   *
228	   * @param indexName - Name of the index
229	   * @param request - Query request with vector and filters
230	   * @param namespace - Optional namespace for data isolation
231	   */
232	  async query<T extends RecordMetadata = RecordMetadata>(
233	    indexName: string,
234	    request: QueryRequest,
235	    namespace?: string
236	  ): Promise<QueryResponse<T>> {
237	    const index = this.client.index(indexName);
238	    const targetNamespace = namespace ? index.namespace(namespace) : index;
239	
240	    try {
241	      const results = await targetNamespace.query({
242	        vector: request.vector,
243	        topK: request.topK,
244	        filter: request.filter,
245	        includeMetadata: request.includeMetadata ?? true,
246	      });
247	
248	      return {
249	        matches: results.matches.map((match) => ({
250	          id: match.id,
251	          score: match.score ?? 0,
252	          metadata: match.metadata as T,
253	        })),
254	      };
255	    } catch (error) {
256	      this.handleError(error);
257	    }
258	  }
259	
260	  /**
261	   * Fetch vectors by IDs
262	   *
263	   * @param indexName - Name of the index
264	   * @param vectorIds - Array of vector IDs to fetch
265	   * @param namespace - Optional namespace for data isolation
266	   */
267	  async fetchVectors<T extends RecordMetadata = RecordMetadata>(
268	    indexName: string,
269	    vectorIds: string[],
270	    namespace?: string
271	  ): Promise<FetchResponse<T>> {
272	    if (vectorIds.length === 0) {
273	      return { records: {} };
274	    }
275	
276	    const index = this.client.index(indexName);
277	    const targetNamespace = namespace ? index.namespace(namespace) : index;
278	
279	    try {
280	      const result = await targetNamespace.fetch(vectorIds);
281	
282	      const records: FetchResponse<T>["records"] = {};
283	      for (const [id, record] of Object.entries(result.records)) {
284	        if (record.values) {
285	          records[id] = {
286	            id: record.id,
287	            values: record.values,
288	            metadata: record.metadata as T,
289	          };
290	        }
291	      }
292	
293	      return { records };
294	    } catch (error) {
295	      this.handleError(error);
296	    }
297	  }
298	
299	  /**
300	   * Update a vector's metadata
301	   *
302	   * @param indexName - Name of the index
303	   * @param request - Update request with vector ID and metadata
304	   * @param namespace - Optional namespace for data isolation
305	   */
306	  async updateVectorMetadata<T extends RecordMetadata = RecordMetadata>(
307	    indexName: string,
308	    request: UpdateRequest<T>,
309	    namespace?: string
310	  ): Promise<void> {
311	    const index = this.client.index(indexName);
312	    const targetNamespace = namespace ? index.namespace(namespace) : index;
313	
314	    try {
315	      await targetNamespace.update({
316	        id: request.id,
317	        metadata: request.metadata,
318	      });
319	    } catch (error) {
320	      this.handleError(error);
321	    }
322	  }
323	
324	  /**
325	   * Handle and transform errors
326	   */
327	  private handleError(error: unknown): never {
328	    if (error instanceof PineconeError) {
329	      throw error;
330	    }
331	
332	    const message = error instanceof Error ? error.message : String(error);
333	    const lowerMessage = message.toLowerCase();
334	
335	    if (lowerMessage.includes("rate limit") || lowerMessage.includes("429")) {
336	      throw new PineconeRateLimitError("Rate limit exceeded", error);
337	    }
338	
339	    if (lowerMessage.includes("not found") || lowerMessage.includes("404")) {
340	      throw new PineconeNotFoundError("Index or resource not found", error);
341	    }
342	
343	    if (
344	      lowerMessage.includes("invalid") ||
345	      lowerMessage.includes("dimension") ||
346	      lowerMessage.includes("400")
347	    ) {
348	      throw new PineconeInvalidRequestError("Invalid request", error);
349	    }
350	
