import { gatewayInstallations, orgIntegrations } from "@db/app/schema";
import {
  getDefaultSyncEvents,
  getProvider,
  gwInstallationBackfillConfigSchema,
  type NormalizedInstallation,
  type ProviderName,
  type ResourcePickerExecuteApiFn,
  sourceTypeSchema,
} from "@repo/app-providers";
import type { SourceIdentifier } from "@repo/app-validation";
import { createPlatformCaller } from "@repo/platform-trpc/caller";
import type { TRPCRouterRecord } from "@trpc/server";
import { TRPCError } from "@trpc/server";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { and, eq } from "drizzle-orm";
import yaml from "yaml";
import { z } from "zod";
import { orgScopedProcedure } from "../../trpc";

/**
 * Connections Router
 *
 * Manages org-level OAuth connections (GitHub, Vercel, Linear, etc.)
 * Queries gw_installations directly (org-scoped).
 *
 * Proxies to memory service tRPC for token vault, OAuth, and API operations.
 *
 * Table: gatewayInstallations (lightfast_gateway_installations)
 * Scope: Org-scoped (active org required)
 */

export const connectionsRouter = {
  /**
   * Get OAuth authorize URL from the memory service.
   *
   * Proxies the memory service authorize endpoint since browsers
   * can't set custom headers (X-Org-Id) during popup navigation.
   */
  getAuthorizeUrl: orgScopedProcedure
    .input(
      z.object({
        provider: sourceTypeSchema,
      })
    )
    .query(async ({ ctx, input }) => {
      const platform = await createPlatformCaller();
      return platform.connections.getAuthorizeUrl({
        provider: input.provider,
        orgId: ctx.auth.orgId,
        connectedBy: ctx.auth.userId,
      });
    }),

  /**
   * List org's OAuth integrations (all providers)
   *
   * Returns all active OAuth integrations connected by the org.
   */
  list: orgScopedProcedure.query(async ({ ctx }) => {
    const installations = await ctx.db
      .select()
      .from(gatewayInstallations)
      .where(
        and(
          eq(gatewayInstallations.orgId, ctx.auth.orgId),
          eq(gatewayInstallations.status, "active")
        )
      );

    return installations.map((inst) => ({
      id: inst.id,
      sourceType: inst.provider,
      isActive: true,
      connectedAt: inst.createdAt,
      lastSyncAt: inst.updatedAt,
    }));
  }),

  /**
   * Disconnect an integration.
   *
   * Delegates to the memory service which triggers the durable
   * connection-teardown workflow (gate-first: closes ingress immediately).
   */
  disconnect: orgScopedProcedure
    .input(
      z.object({
        integrationId: z.string(),
      })
    )
    .mutation(async ({ ctx, input }) => {
      // Fetch installation to get provider (required for disconnect)
      // and enforce org scoping before calling the memory service
      const rows = await ctx.db
        .select({
          id: gatewayInstallations.id,
          provider: gatewayInstallations.provider,
        })
        .from(gatewayInstallations)
        .where(
          and(
            eq(gatewayInstallations.id, input.integrationId),
            eq(gatewayInstallations.orgId, ctx.auth.orgId)
          )
        )
        .limit(1);

      const installation = rows[0];
      if (!installation) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "Integration not found or access denied",
        });
      }

      const platform = await createPlatformCaller();
      await platform.connections.disconnect({
        id: installation.id,
        provider: installation.provider,
      });

      // Cascade: mark all org integrations for this installation as disconnected.
      // This covers all providers (Vercel, Linear, Sentry, Apollo, GitHub).
      // The cascade here ensures the gate closes immediately on user-triggered disconnect.
      const now = new Date().toISOString();
      await ctx.db
        .update(orgIntegrations)
        .set({
          status: "disconnected",
          statusReason: "installation_revoked",
          updatedAt: now,
        })
        .where(eq(orgIntegrations.installationId, input.integrationId));

      return { success: true };
    }),

  /**
   * Update backfill configuration for a gateway installation.
   *
   * Stores depth + entityTypes on gatewayInstallations.backfillConfig.
   * Used by SourceSettingsForm and as defaults for notifyBackfill().
   */
  updateBackfillConfig: orgScopedProcedure
    .input(
      z.object({
        installationId: z.string().min(1),
        backfillConfig: gwInstallationBackfillConfigSchema,
      })
    )
    .mutation(async ({ ctx, input }) => {
      const result = await ctx.db
        .update(gatewayInstallations)
        .set({ backfillConfig: input.backfillConfig })
        .where(
          and(
            eq(gatewayInstallations.id, input.installationId),
            eq(gatewayInstallations.orgId, ctx.auth.orgId)
          )
        )
        .returning({ id: gatewayInstallations.id });

      if (!result[0]) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "Installation not found or access denied",
        });
      }

      return { success: true };
    }),

  /**
   * GitHub-specific operations
   */
  github: {
    /**
     * Validate and refresh installations from GitHub API
     *
     * Re-fetches installations from GitHub using stored access token
     * and updates the installation's providerAccountInfo.
     *
     * Returns counts of added/removed installations.
     */
    validate: orgScopedProcedure.mutation(async ({ ctx }) => {
      const result = await ctx.db
        .select()
        .from(gatewayInstallations)
        .where(
          and(
            eq(gatewayInstallations.orgId, ctx.auth.orgId),
            eq(gatewayInstallations.provider, "github"),
            eq(gatewayInstallations.status, "active")
          )
        )
        .limit(1);

      const installation = result[0];

      if (!installation) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "GitHub integration not found. Please connect GitHub first.",
        });
      }

      const providerAccountInfo = installation.providerAccountInfo;
      if (providerAccountInfo?.sourceType !== "github") {
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Invalid provider data type",
        });
      }

      try {
        const platform = await createPlatformCaller();

        // Validate that the installation still exists on GitHub (App JWT auth via proxy)
        const result = await platform.proxy.execute({
          installationId: installation.id,
          endpointId: "get-app-installation",
          pathParams: { installation_id: installation.externalId },
        });

        if (result.status !== 200) {
          throw new Error(
            `GitHub installation not found: status ${result.status}`
          );
        }

        // Update only lastValidatedAt — display data is resolved live, not cached
        const existingInfo = installation.providerAccountInfo;
        const now = new Date().toISOString();
        if (existingInfo?.sourceType === "github") {
          await ctx.db
            .update(gatewayInstallations)
            .set({
              providerAccountInfo: { ...existingInfo, lastValidatedAt: now },
              updatedAt: now,
            })
            .where(eq(gatewayInstallations.id, installation.id));
        }

        return { added: 0, removed: 0, total: 1 };
      } catch (error: unknown) {
        log.error("[connections/github] validate failed", {
          clerkOrgId: ctx.auth.orgId,
          error: error instanceof Error ? error.message : String(error),
        });

        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to validate GitHub installation",
          cause: error,
        });
      }
    }),

    /**
     * Detect repository configuration (lightfast.yml)
     *
     * Checks if the repository contains a lightfast.yml configuration file
     * and returns its content if found.
     */
    detectConfig: orgScopedProcedure
      .input(
        z.object({
          integrationId: z.string(), // gatewayInstallations.id
          installationId: z.string(), // GitHub App installation external ID
          fullName: z.string(), // "owner/repo"
          ref: z.string().optional(), // branch/tag/sha (defaults to default branch)
        })
      )
      .query(async ({ ctx, input }) => {
        // Verify org owns this installation
        const result = await ctx.db
          .select()
          .from(gatewayInstallations)
          .where(
            and(
              eq(gatewayInstallations.id, input.integrationId),
              eq(gatewayInstallations.orgId, ctx.auth.orgId)
            )
          )
          .limit(1);

        const installation = result[0];

        if (!installation) {
          throw new TRPCError({
            code: "NOT_FOUND",
            message: "Installation not found or access denied",
          });
        }

        // Verify the GitHub App installation is accessible via the table column
        if (installation.externalId !== input.installationId) {
          throw new TRPCError({
            code: "NOT_FOUND",
            message:
              "Installation not found or not accessible to this connection",
          });
        }

        const [owner, repo] = input.fullName.split("/");
        if (!(owner && repo)) {
          throw new TRPCError({
            code: "BAD_REQUEST",
            message: "Invalid repository name format. Expected 'owner/repo'",
          });
        }

        try {
          const platform = await createPlatformCaller();

          let ref = input.ref;
          if (!ref) {
            const repoResult = await platform.proxy.execute({
              installationId: input.integrationId,
              endpointId: "get-repo",
              pathParams: { owner, repo },
            });
            if (repoResult.status !== 200) {
              throw new TRPCError({
                code: "INTERNAL_SERVER_ERROR",
                message: "Failed to fetch repository info from GitHub",
              });
            }
            ref = (repoResult.data as { default_branch: string })
              .default_branch;
          }

          if (ref && !/^[a-zA-Z0-9._/-]+$/.test(ref)) {
            throw new TRPCError({
              code: "BAD_REQUEST",
              message:
                "Invalid ref format. Only alphanumeric characters, dots, dashes, slashes, and underscores are allowed.",
            });
          }

          const candidates = [
            "lightfast.yml",
            ".lightfast.yml",
            "lightfast.yaml",
            ".lightfast.yaml",
          ];

          for (const path of candidates) {
            const queryParams: Record<string, string> = {};
            if (ref) {
              queryParams.ref = ref;
            }
            const fileResult = await platform.proxy.execute({
              installationId: input.integrationId,
              endpointId: "get-file-contents",
              pathParams: { owner, repo, path },
              queryParams,
            });

            if (fileResult.status === 404) {
              continue;
            }

            if (fileResult.status !== 200) {
              throw new TRPCError({
                code: "INTERNAL_SERVER_ERROR",
                message: "Failed to fetch file contents from GitHub",
              });
            }

            const data = fileResult.data as {
              content?: string;
              type?: string;
              size?: number;
              sha?: string;
            };

            if (
              !Array.isArray(data) &&
              data.content !== undefined &&
              data.type !== undefined
            ) {
              const maxSize = 50 * 1024;
              if (typeof data.size === "number" && data.size > maxSize) {
                throw new TRPCError({
                  code: "BAD_REQUEST",
                  message: `Config file too large. Maximum size is ${maxSize / 1024}KB.`,
                });
              }

              const content = Buffer.from(data.content, "base64").toString(
                "utf-8"
              );

              try {
                yaml.parse(content);
              } catch {
                throw new TRPCError({
                  code: "BAD_REQUEST",
                  message: "Invalid YAML format in config file.",
                });
              }

              return {
                exists: true,
                path,
                content,
                sha: data.sha ?? "",
              };
            }
          }

          return { exists: false };
        } catch (error: unknown) {
          log.error("[connections/github] detectConfig failed", {
            clerkOrgId: ctx.auth.orgId,
            error: error instanceof Error ? error.message : String(error),
          });

          throw new TRPCError({
            code: "INTERNAL_SERVER_ERROR",
            message: "Failed to detect repository configuration",
            cause: error,
          });
        }
      }),
  },

  /**
   * Vercel-specific operations
   */
  vercel: {
    /**
     * Disconnect Vercel integration.
     *
     * Delegates to the memory service which triggers the durable
     * connection-teardown workflow (gate-first: closes ingress immediately).
     */
    disconnect: orgScopedProcedure.mutation(async ({ ctx }) => {
      // Fetch Vercel installation to get id; enforce org scoping
      const rows = await ctx.db
        .select({ id: gatewayInstallations.id })
        .from(gatewayInstallations)
        .where(
          and(
            eq(gatewayInstallations.orgId, ctx.auth.orgId),
            eq(gatewayInstallations.provider, "vercel")
          )
        )
        .limit(1);

      const installation = rows[0];
      if (!installation) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "Vercel integration not found",
        });
      }

      const platform = await createPlatformCaller();
      await platform.connections.disconnect({
        id: installation.id,
        provider: "vercel",
      });

      // Cascade: mark all org integrations for this installation as disconnected
      const now = new Date().toISOString();
      await ctx.db
        .update(orgIntegrations)
        .set({
          status: "disconnected",
          statusReason: "installation_revoked",
          updatedAt: now,
        })
        .where(eq(orgIntegrations.installationId, installation.id));

      return { success: true };
    }),
  },

  // ── Generic Resource Picker Procedures ────────────────────────────────────

  // ── Linked Resources (orgIntegrations) ────────────────────────────────────

  resources: {
    /**
     * List linked resources for the current org.
     *
     * Joins orgIntegrations with gatewayInstallations to return
     * per-resource metadata including backfill config.
     */
    list: orgScopedProcedure.query(async ({ ctx }) => {
      const rows = await ctx.db
        .select({
          id: orgIntegrations.id,
          provider: orgIntegrations.provider,
          providerConfig: orgIntegrations.providerConfig,
          providerResourceId: orgIntegrations.providerResourceId,
          installationId: orgIntegrations.installationId,
          documentCount: orgIntegrations.documentCount,
          backfillConfig: gatewayInstallations.backfillConfig,
        })
        .from(orgIntegrations)
        .leftJoin(
          gatewayInstallations,
          eq(orgIntegrations.installationId, gatewayInstallations.id)
        )
        .where(
          and(
            eq(orgIntegrations.clerkOrgId, ctx.auth.orgId),
            eq(orgIntegrations.status, "active")
          )
        );

      const list = rows.map((row) => {
        // ProviderConfig is a discriminated union — access common fields via cast
        const config = row.providerConfig as {
          sync?: { events?: string[] };
          status?: { configStatus?: string };
        };
        return {
          id: row.id,
          metadata: {
            provider: row.provider,
            sync: config.sync
              ? { events: config.sync.events ?? [] }
              : undefined,
            status: config.status
              ? { configStatus: config.status.configStatus }
              : undefined,
          },
          displayName: row.providerResourceId,
          installationId: row.installationId,
          documentCount: row.documentCount,
          backfillConfig: row.backfillConfig,
        };
      });

      return { list };
    }),

    /**
     * Bulk-link resources from a gateway installation to this org.
     *
     * Creates new orgIntegration rows, or reactivates disconnected ones.
     * Returns counts of created / reactivated entries.
     */
    bulkLink: orgScopedProcedure
      .input(
        z.object({
          provider: sourceTypeSchema,
          gwInstallationId: z.string().min(1),
          resources: z
            .array(
              z.object({
                resourceId: z.string(),
                resourceName: z.string().optional(),
              })
            )
            .min(1),
        })
      )
      .mutation(async ({ ctx, input }) => {
        // Verify the installation belongs to this org
        const installation = await ctx.db
          .select({ id: gatewayInstallations.id })
          .from(gatewayInstallations)
          .where(
            and(
              eq(gatewayInstallations.id, input.gwInstallationId),
              eq(gatewayInstallations.orgId, ctx.auth.orgId),
              eq(gatewayInstallations.status, "active")
            )
          )
          .limit(1)
          .then((rows) => rows[0]);

        if (!installation) {
          throw new TRPCError({
            code: "NOT_FOUND",
            message: "Installation not found or not owned by this org",
          });
        }

        const providerDef = getProvider(input.provider);
        if (!providerDef) {
          throw new TRPCError({
            code: "BAD_REQUEST",
            message: `Unknown provider: ${input.provider}`,
          });
        }

        const defaultSyncEvents = getDefaultSyncEvents(
          input.provider as ProviderName
        );
        const providerConfig = providerDef.buildProviderConfig({
          defaultSyncEvents: [...defaultSyncEvents],
        });

        let created = 0;
        let reactivated = 0;

        for (const resource of input.resources) {
          const existing = await ctx.db
            .select({ id: orgIntegrations.id })
            .from(orgIntegrations)
            .where(
              and(
                eq(orgIntegrations.installationId, input.gwInstallationId),
                eq(
                  orgIntegrations.providerResourceId,
                  resource.resourceId as SourceIdentifier
                )
              )
            )
            .then((rows) => rows[0]);

          await ctx.db
            .insert(orgIntegrations)
            .values({
              clerkOrgId: ctx.auth.orgId,
              installationId: input.gwInstallationId,
              provider: input.provider,
              providerConfig,
              providerResourceId: resource.resourceId as SourceIdentifier,
            })
            .onConflictDoUpdate({
              target: [
                orgIntegrations.installationId,
                orgIntegrations.providerResourceId,
              ],
              set: {
                status: "active",
                statusReason: null,
                updatedAt: new Date().toISOString(),
              },
            });

          if (existing) {
            reactivated++;
          } else {
            created++;
          }
        }

        return { created, reactivated };
      }),
  },

  generic: {
    listInstallations: orgScopedProcedure
      .input(z.object({ provider: sourceTypeSchema }))
      .query(async ({ ctx, input }) => {
        const providerDef = getProvider(input.provider);
        if (!providerDef) {
          throw new TRPCError({
            code: "BAD_REQUEST",
            message: `Unknown provider: ${input.provider}`,
          });
        }

        const installations = await ctx.db
          .select()
          .from(gatewayInstallations)
          .where(
            and(
              eq(gatewayInstallations.orgId, ctx.auth.orgId),
              eq(gatewayInstallations.provider, input.provider),
              eq(gatewayInstallations.status, "active")
            )
          );

        if (installations.length === 0) {
          return {
            installationMode: providerDef.resourcePicker.installationMode,
            resourceLabel: providerDef.resourcePicker.resourceLabel,
            installations: [] as NormalizedInstallation[],
          };
        }

        const platform = await createPlatformCaller();

        const enriched = await Promise.all(
          installations.map(async (inst) => {
            const executeApi: ResourcePickerExecuteApiFn = (request) =>
              platform.proxy.execute({
                installationId: inst.id,
                ...request,
              });

            return providerDef.resourcePicker.enrichInstallation(executeApi, {
              id: inst.id,
              externalId: inst.externalId,
              // ProviderDefinition loses TAccountInfo generic — contravariance on
              // ResourcePickerDef method params collapses the union to never | null.
              // Runtime value is always the correct type for this provider.
              providerAccountInfo: inst.providerAccountInfo as any,
            });
          })
        );

        return {
          installationMode: providerDef.resourcePicker.installationMode,
          resourceLabel: providerDef.resourcePicker.resourceLabel,
          installations: enriched,
        };
      }),

    listResources: orgScopedProcedure
      .input(
        z.object({
          provider: sourceTypeSchema,
          installationId: z.string(),
        })
      )
      .query(async ({ ctx, input }) => {
        const providerDef = getProvider(input.provider);
        if (!providerDef) {
          throw new TRPCError({
            code: "BAD_REQUEST",
            message: `Unknown provider: ${input.provider}`,
          });
        }

        // Verify org owns this installation
        const installation = await ctx.db
          .select()
          .from(gatewayInstallations)
          .where(
            and(
              eq(gatewayInstallations.id, input.installationId),
              eq(gatewayInstallations.orgId, ctx.auth.orgId),
              eq(gatewayInstallations.provider, input.provider),
              eq(gatewayInstallations.status, "active")
            )
          )
          .limit(1)
          .then((rows) => rows[0]);

        if (!installation) {
          throw new TRPCError({
            code: "NOT_FOUND",
            message: "Installation not found or not owned by this org",
          });
        }

        const platform = await createPlatformCaller();

        const executeApi: ResourcePickerExecuteApiFn = async (request) => {
          const result = await platform.proxy.execute({
            installationId: installation.id,
            ...request,
          });
          if (result.status === 401) {
            await ctx.db
              .update(gatewayInstallations)
              .set({ status: "error" })
              .where(eq(gatewayInstallations.id, installation.id));
            throw new TRPCError({
              code: "UNAUTHORIZED",
              message: "Provider connection expired. Please reconnect.",
            });
          }
          return result;
        };

        const resources = await providerDef.resourcePicker.listResources(
          executeApi,
          {
            id: installation.id,
            externalId: installation.externalId,
            // ProviderDefinition loses TAccountInfo generic — see comment above.
            providerAccountInfo: installation.providerAccountInfo as any,
          }
        );

        return { resources };
      }),
  },
} satisfies TRPCRouterRecord;

import { clerkOrgSlugSchema } from "@repo/app-validation";
import type { TRPCRouterRecord } from "@trpc/server";
import { TRPCError } from "@trpc/server";
import { clerkClient } from "@vendor/clerk/server";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { z } from "zod";

import { userScopedProcedure, verifyOrgMembership } from "../../trpc";

/**
 * Organization router - Clerk-based organization management
 *
 * Phase 1.6: Organizations are managed entirely in Clerk (source of truth)
 * No database table for organizations - Clerk handles all org data
 */
export const organizationRouter = {
  /**
   * List user's organizations from Clerk
   *
   * Returns all organizations the authenticated user belongs to.
   * Used by org-switcher component in the header.
   */
  listUserOrganizations: userScopedProcedure.query(async ({ ctx }) => {
    // userScopedProcedure guarantees clerk-pending or clerk-active
    const userId = ctx.auth.userId;
    const clerk = await clerkClient();

    // Get all organizations the user belongs to from Clerk
    const { data: memberships } =
      await clerk.users.getOrganizationMembershipList({
        userId,
      });

    // Return Clerk organization data directly
    return memberships.map((membership) => {
      const clerkOrg = membership.organization;

      return {
        id: clerkOrg.id, // Clerk org ID
        slug: clerkOrg.slug,
        name: clerkOrg.name,
        role: membership.role,
        imageUrl: clerkOrg.imageUrl,
      };
    });
  }),

  /**
   * Create organization
   * Creates a new Clerk organization with the user as admin
   *
   * Used by team creation flow at /account/teams/new
   * Does NOT create a default project - user sets up integrations separately
   */
  create: userScopedProcedure
    .input(
      z.object({
        slug: clerkOrgSlugSchema,
      })
    )
    .mutation(async ({ ctx, input }) => {
      // userScopedProcedure guarantees clerk-pending or clerk-active
      log.info("[organization] create", {
        slug: input.slug,
        userId: ctx.auth.userId,
        authType: ctx.auth.type,
      });

      const clerk = await clerkClient();

      try {
        // Create Clerk organization (slug used for both name and slug)
        const clerkOrg = await clerk.organizations.createOrganization({
          name: input.slug,
          slug: input.slug,
          createdBy: ctx.auth.userId,
        });

        log.info("[organization] create success", {
          organizationId: clerkOrg.id,
          slug: clerkOrg.slug,
        });

        return {
          organizationId: clerkOrg.id,
          slug: clerkOrg.slug || input.slug,
        };
      } catch (error: unknown) {
        log.error("[organization] create failed", {
          slug: input.slug,
          userId: ctx.auth.userId,
          error: error instanceof Error ? error.message : String(error),
          errorDetails: error,
        });

        // Check for specific Clerk errors
        if (error && typeof error === "object" && "errors" in error) {
          const clerkError = error as {
            errors?: { code: string; message: string }[];
          };

          log.error("[organization] clerk error details", {
            errors: clerkError.errors,
          });

          if (
            clerkError.errors?.[0]?.code === "duplicate_record" ||
            clerkError.errors?.[0]?.code === "form_identifier_exists" ||
            clerkError.errors?.[0]?.message.includes("already exists") ||
            clerkError.errors?.[0]?.message.includes("slug is taken")
          ) {
            throw new TRPCError({
              code: "CONFLICT",
              message: `An organization with the name "${input.slug}" already exists`,
            });
          }
        }

        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to create organization",
          cause: error,
        });
      }
    }),

  /**
   * Update organization name
   * Used by team settings page to update the organization name/slug in Clerk
   *
   * Only organization admins can update the organization name
   */
  updateName: userScopedProcedure
    .input(
      z.object({
        slug: z.string().min(1, "Organization slug is required"),
        name: clerkOrgSlugSchema,
      })
    )
    .mutation(async ({ ctx, input }) => {
      // userScopedProcedure guarantees clerk-pending or clerk-active
      const clerk = await clerkClient();

      try {
        // Get organization by slug
        const org = await clerk.organizations.getOrganization({
          slug: input.slug,
        });

        // Verify user has admin access to the organization
        await verifyOrgMembership({
          clerkOrgId: org.id,
          userId: ctx.auth.userId,
          requireAdmin: true,
        });

        // Update organization in Clerk
        await clerk.organizations.updateOrganization(org.id, {
          name: input.name,
          slug: input.name, // Clerk uses slug for URL-safe names
        });

        log.info("[organization] updateName success", {
          organizationId: org.id,
          slug: input.name,
          userId: ctx.auth.userId,
        });

        return {
          success: true,
          id: org.id, // Return org ID for setActive calls
          name: input.name,
        };
      } catch (error: unknown) {
        // Re-throw TRPCError as-is
        if (error instanceof TRPCError) {
          throw error;
        }

        log.error("[organization] updateName failed", {
          slug: input.slug,
          userId: ctx.auth.userId,
          error: error instanceof Error ? error.message : String(error),
        });

        // Check for specific Clerk errors
        if (error && typeof error === "object" && "errors" in error) {
          const clerkError = error as {
            errors?: { code: string; message: string }[];
          };

          if (
            clerkError.errors?.[0]?.code === "duplicate_record" ||
            clerkError.errors?.[0]?.code === "form_identifier_exists" ||
            clerkError.errors?.[0]?.message.includes("already exists") ||
            clerkError.errors?.[0]?.message.includes("slug is taken")
          ) {
            throw new TRPCError({
              code: "CONFLICT",
              message: `An organization with the name "${input.name}" already exists`,
            });
          }
        }

        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to update organization",
          cause: error,
        });
      }
    }),
} satisfies TRPCRouterRecord;

import type { TRPCRouterRecord } from "@trpc/server";
import { TRPCError } from "@trpc/server";
import { clerkClient } from "@vendor/clerk/server";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { userScopedProcedure } from "../../trpc";

/**
 * Account Router
 *
 * Manages user account profile information from Clerk.
 * This router contains only non-table-based operations.
 *
 * Table-based operations have been moved to:
 * - API Keys: org-api-keys router (org-scoped)
 * - Integrations: user-sources router
 */

export const accountRouter = {
  /**
   * Get user profile information from Clerk
   *
   * Returns user data including:
   * - Full name
   * - Email addresses
   * - Username
   * - Profile image
   */
  get: userScopedProcedure.query(async ({ ctx }) => {
    try {
      const clerk = await clerkClient();
      const user = await clerk.users.getUser(ctx.auth.userId);

      return {
        id: user.id,
        firstName: user.firstName,
        lastName: user.lastName,
        fullName:
          user.firstName && user.lastName
            ? `${user.firstName} ${user.lastName}`
            : (user.firstName ?? user.lastName ?? null),
        username: user.username,
        primaryEmailAddress: user.primaryEmailAddress?.emailAddress ?? null,
        imageUrl: user.imageUrl,
        createdAt: new Date(user.createdAt).toISOString(),
      };
    } catch (error: unknown) {
      log.error("[account] get profile failed", {
        userId: ctx.auth.userId,
        error: error instanceof Error ? error.message : String(error),
      });

      throw new TRPCError({
        code: "INTERNAL_SERVER_ERROR",
        message: "Failed to fetch user profile",
        cause: error,
      });
    }
  }),
} satisfies TRPCRouterRecord;

/**
 * Activity Recording Workflow
 *
 * Batched activity recording workflow for efficient database writes.
 * Receives activity events from helper functions and batch inserts them
 * for better performance and reduced database load.
 *
 * Triggered by: app/activity.record events (Tier 2 user actions)
 * Batching: Up to 100 events per batch, 10s timeout per org
 * Performance: 50-100x faster than individual inserts
 *
 * @see /docs/implementation/user-activity-tracking.md
 */

import { db } from "@db/app/client";
import { orgUserActivities } from "@db/app/schema";
import type { ActivityMetadata } from "@repo/app-validation";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { inngest } from "../../client/client";

/**
 * Record Activity Workflow
 *
 * Processes batched activity events and inserts them into the database.
 * Uses Inngest's batch feature for efficient processing.
 */
export const recordActivity = inngest.createFunction(
  {
    id: "app/record-activity",
    name: "Record Activity",
    description: "Batch record user activities for efficient database writes",
    retries: 3,

    // Batch configuration for optimal performance
    batchEvents: {
      maxSize: 100, // Process up to 100 events at once
      timeout: "10s", // Wait max 10s before processing partial batch
      key: "event.data.clerkOrgId", // Batch per org
    },

    timeouts: {
      start: "30s",
      finish: "2m",
    },
  },
  { event: "app/activity.record" },
  async ({ events, step }) => {
    // Guard: Inngest's batchEvents config should never deliver an empty array,
    // but defend against it to avoid a Postgres error on INSERT with no values.
    if (events.length === 0) {
      log.warn("Received empty activity batch, skipping");
      return {
        success: true,
        clerkOrgId: undefined,
        batchSize: 0,
        insertedCount: 0,
        timestamp: new Date().toISOString(),
      };
    }

    const batchSize = events.length;
    // Safe after the length guard above
    const clerkOrgId = events[0].data.clerkOrgId;

    log.info("Processing activity batch", {
      batchSize,
      clerkOrgId,
      firstEventTimestamp: events[0].ts,
      lastEventTimestamp: events.at(-1)?.ts,
    });

    // Step 1: Prepare activity records
    const activityRecords = await step.run("activity.prepare-records", () => {
      return events.map((event) => {
        const { data } = event;

        return {
          clerkOrgId: data.clerkOrgId,
          category: data.category,
          action: data.action,
          entityType: data.entityType,
          entityId: data.entityId,
          // Cast metadata to preserve type safety after deserialization
          // Metadata is REQUIRED for all activities
          metadata: data.metadata as ActivityMetadata,
          relatedActivityId: data.relatedActivityId ?? null,
        };
      });
    });

    // Step 2: Batch insert activities
    const insertResult = await step.run("activity.batch-insert", async () => {
      try {
        // Use Drizzle's batch insert for optimal performance
        const result = await db
          .insert(orgUserActivities)
          .values(activityRecords)
          .returning({ id: orgUserActivities.id });

        log.info("Activity batch inserted", {
          clerkOrgId,
          insertedCount: result.length,
          batchSize,
        });

        return {
          success: true,
          insertedCount: result.length,
          insertedIds: result.map((r) => r.id),
        };
      } catch (error) {
        log.error("Failed to insert activity batch", {
          clerkOrgId,
          batchSize,
          error: error instanceof Error ? error.message : String(error),
        });

        throw error;
      }
    });

    return {
      success: true,
      clerkOrgId,
      batchSize,
      insertedCount: insertResult.insertedCount,
      timestamp: new Date().toISOString(),
    };
  }
);

