toolUseResult.originalFile:
/**
 * Platform service tRPC initialization.
 *
 * Auth model: service-to-service JWT (not Clerk).
 * All callers are internal services (app, platform, inngest, cron).
 */
import { initTRPC, TRPCError } from "@trpc/server";
import { log } from "@vendor/observability/log/next";
import { createObservabilityMiddleware } from "@vendor/observability/trpc";
import superjson from "superjson";
import { ZodError } from "zod";

import { verifyServiceJWT } from "./lib/jwt";

// -- Auth Context -------------------------------------------------------------

/**
 * Discriminated union for platform service authentication.
 * Every request resolves to exactly one variant.
 */
export type PlatformAuthContext =
  | { type: "service"; caller: string }
  | { type: "webhook"; provider: string }
  | { type: "inngest" }
  | { type: "cron" }
  | { type: "unauthenticated" };

// -- Context Creation ---------------------------------------------------------

/**
 * Create tRPC context for platform service requests.
 *
 * Auth resolution order:
 * 1. Bearer JWT in Authorization header -> service auth
 * 2. x-trpc-source header for internal identification
 * 3. Unauthenticated fallback
 */
export const createPlatformTRPCContext = async (opts: { headers: Headers }) => {
  const source = opts.headers.get("x-trpc-source") ?? "unknown";

  // Check for service JWT in Authorization header
  const authHeader = opts.headers.get("authorization");
  if (authHeader?.startsWith("Bearer ")) {
    const token = authHeader.replace("Bearer ", "");

    try {
      const verified = await verifyServiceJWT(token);
      log.info("[trpc] platform service request", {
        source,
        auth: "service",
        caller: verified.caller,
      });
      return {
        auth: {
          type: "service" as const,
          caller: verified.caller,
        },
        headers: opts.headers,
      };
    } catch (error) {
      log.warn("[trpc] JWT verification error", {
        source,
        error: error instanceof Error ? error.message : String(error),
      });
    }
  }

  // No authentication
  log.info("[trpc] platform service request", {
    source,
    auth: "unauthenticated",
  });
  return {
    auth: { type: "unauthenticated" as const },
    headers: opts.headers,
  };
};

// -- tRPC Initialization ------------------------------------------------------

const isProduction = process.env.NODE_ENV === "production";

const t = initTRPC.context<typeof createPlatformTRPCContext>().create({
  transformer: superjson,
  errorFormatter: ({ shape, error }) => {
    const shouldSanitize =
      isProduction && error.code === "INTERNAL_SERVER_ERROR";

    return {
      ...shape,
      message: shouldSanitize ? "An unexpected error occurred" : shape.message,
      data: {
        ...shape.data,
        zodError:
          error.cause instanceof ZodError ? error.cause.flatten() : null,
      },
    };
  },
});

// -- Middleware ----------------------------------------------------------------

const observabilityMiddleware = t.middleware(
  createObservabilityMiddleware({
    isDev: t._config.isDev,
    extractAuth: (ctx) => ({
      ...(ctx.auth.type === "service" && { caller: ctx.auth.caller }),
    }),
  })
);

// -- Router & Procedure Exports -----------------------------------------------

export const createTRPCRouter = t.router;
export const createCallerFactory = t.createCallerFactory;

/**
 * Public procedure -- no auth required.
 * Use for health checks or publicly accessible endpoints.
 */
export const publicProcedure = t.procedure.use(observabilityMiddleware);

/**
 * Service procedure -- requires valid service JWT.
 * Used by app or other internal services calling platform.
 *
 * Guarantees `ctx.auth.type === "service"` and `ctx.auth.caller` is available.
 */
export const serviceProcedure = t.procedure
  .use(observabilityMiddleware)
  .use(({ ctx, next }) => {
    if (ctx.auth.type !== "service") {
      throw new TRPCError({
        code: "UNAUTHORIZED",
        message:
          "Service authentication required. Provide a valid service JWT in the Authorization header.",
      });
    }

    return next({
      ctx: {
        ...ctx,
        auth: ctx.auth as Extract<PlatformAuthContext, { type: "service" }>,
      },
    });
  });

/**
 * Admin procedure -- requires service JWT from an admin caller.
 * Used for administrative operations (reindex, purge, etc.).
 *
 * Restricts `ctx.auth.caller` to "admin" only.
 */
export const adminProcedure = t.procedure
  .use(observabilityMiddleware)
  .use(({ ctx, next }) => {
    if (ctx.auth.type !== "service") {
      throw new TRPCError({
        code: "UNAUTHORIZED",
        message: "Service authentication required.",
      });
    }

    if (ctx.auth.caller !== "admin") {
      throw new TRPCError({
        code: "FORBIDDEN",
        message:
          "Admin access required. This endpoint is restricted to admin callers.",
      });
    }

    return next({
      ctx: {
        ...ctx,
        auth: ctx.auth as Extract<PlatformAuthContext, { type: "service" }>,
      },
    });
  });

/**
 * Connection lifecycle (teardown) function
 *
 * Ported from apps/gateway/src/workflows/connection-teardown.ts
 *
 * KEY CHANGES vs gateway service:
 * - Upstash Workflow context.run() → Inngest step.run()
 * - Function ID: platform/connection.lifecycle
 * - Trigger: platform/connection.lifecycle event (was Upstash Workflow trigger)
 * - Cancel backfill: fires Inngest event instead of QStash publish
 * - All 5 steps preserved: close-gate, cancel-backfill, revoke-token, cleanup-cache, remove-resources
 */

import { db } from "@db/app/client";
import {
  gatewayInstallations,
  gatewayLifecycleLogs,
  gatewayTokens,
  orgIntegrations,
} from "@db/app/schema";
import type { SourceType } from "@repo/app-providers";
import { getProvider } from "@repo/app-providers";
import { decrypt } from "@repo/lib";
import { eq } from "@vendor/db";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { getEncryptionKey } from "../../lib/encryption";
import { providerConfigs } from "../../lib/provider-configs";
import { inngest } from "../client";

export const connectionLifecycle = inngest.createFunction(
  {
    id: "platform/connection.lifecycle",
    name: "Connection Lifecycle (Teardown)",
    retries: 3,
    concurrency: [
      // 1 teardown per connection at a time
      { limit: 1, key: "event.data.installationId" },
    ],
    timeouts: { start: "1m", finish: "5m" },
  },
  { event: "platform/connection.lifecycle" },
  async ({ event, step }) => {
    const { installationId, provider: providerName } = event.data;

    log.info("[connection-lifecycle] starting", {
      installationId,
      provider: providerName,
    });

    // Step 1: Close the ingress gate — all guards check status === 'active',
    // so setting 'revoked' immediately blocks new requests.
    await step.run("close-gate", async () => {
      await db
        .update(gatewayInstallations)
        .set({ status: "revoked", updatedAt: new Date().toISOString() })
        .where(eq(gatewayInstallations.id, installationId));

      await db.insert(gatewayLifecycleLogs).values({
        installationId,
        event: "gate_closed",
        fromStatus: "active",
        toStatus: "revoked",
        reason: "Ingress gate closed by teardown workflow",
        metadata: {
          step: "close-gate",
          workflowContext: "connection-lifecycle",
          triggeredBy: "system",
        },
      });

      log.info("[connection-lifecycle] gate closed", { installationId });
    });

    // Step 2: Cancel any running backfill (best-effort, via Inngest event)
    await step.run("cancel-backfill", async () => {
      try {
        await inngest.send({
          name: "platform/backfill.run.cancelled",
          data: {
            installationId,
          },
        });
        log.info("[connection-lifecycle] backfill cancellation sent", {
          installationId,
        });
      } catch (err) {
        log.warn(
          "[connection-lifecycle] backfill cancellation failed (best-effort)",
          {
            installationId,
            error: err instanceof Error ? err.message : String(err),
          }
        );
      }
    });

    // Step 3: Revoke token at provider (best-effort)
    await step.run("revoke-token", async () => {
      if (providerName === "github") {
        log.info(
          "[connection-lifecycle] skipping token revocation (github uses on-demand JWTs)",
          {
            installationId,
          }
        );
        return;
      }

      const providerDef = getProvider(providerName as SourceType);
      const config = providerConfigs[providerName];

      if (!config) {
        log.warn(
          "[connection-lifecycle] provider not configured, skipping token revocation",
          {
            installationId,
            provider: providerName,
          }
        );
        return;
      }

      const tokenRows = await db
        .select()
        .from(gatewayTokens)
        .where(eq(gatewayTokens.installationId, installationId))
        .limit(1);

      const tokenRow = tokenRows[0];
      if (!tokenRow) {
        log.info(
          "[connection-lifecycle] no token row found, skipping revocation",
          {
            installationId,
          }
        );
        return;
      }

      try {
        const auth = providerDef.auth;
        if (auth.kind === "oauth" && auth.revokeToken) {
          const decryptedToken = await decrypt(
            tokenRow.accessToken,
            getEncryptionKey()
          );
          await auth.revokeToken(config as never, decryptedToken);
        }
        log.info("[connection-lifecycle] token revoked", {
          installationId,
          provider: providerName,
        });
      } catch (err) {
        log.warn(
          "[connection-lifecycle] token revocation failed (best-effort)",
          {
            installationId,
            provider: providerName,
            error: err instanceof Error ? err.message : String(err),
          }
        );
      }
    });

    // Step 4: Disconnect org integrations and log resource disconnection.
    // For user-initiated disconnects the app-layer cascade may have already
    // set orgIntegrations.status → 'disconnected', but for health-check
    // triggers no cascade runs. We update unconditionally (idempotent).
    await step.run("disconnect-resources", async () => {
      const allResources = await db
        .select({ providerResourceId: orgIntegrations.providerResourceId })
        .from(orgIntegrations)
        .where(eq(orgIntegrations.installationId, installationId));

      if (allResources.length > 0) {
        const now = new Date().toISOString();
        await db
          .update(orgIntegrations)
          .set({
            status: "disconnected",
            statusReason: "installation_revoked",
            updatedAt: now,
          })
          .where(eq(orgIntegrations.installationId, installationId));
      }

      const resourceIdMap: Record<string, string> = {};
      for (const r of allResources) {
        resourceIdMap[r.providerResourceId] = "disconnected";
      }

      await db.insert(gatewayLifecycleLogs).values({
        installationId,
        event: "resources_removed",
        fromStatus: "revoked",
        toStatus: "revoked",
        reason: `Disconnected ${allResources.length} linked resource(s) during teardown`,
        resourceIds: resourceIdMap,
        metadata: { step: "disconnect-resources", triggeredBy: "system" },
      });

      log.info("[connection-lifecycle] resources disconnected", {
        installationId,
        count: allResources.length,
      });
    });

    log.info("[connection-lifecycle] teardown complete", {
      installationId,
      provider: providerName,
    });

    return { success: true, installationId };
  }
);

/**
 * Token refresh cron function
 *
 * Ported from apps/gateway/src/functions/token-refresh.ts
 *
 * KEY CHANGES vs gateway service:
 * - Function ID: platform/token.refresh (was apps-gateway/token.refresh)
 * - Uses providerConfigs from memory lib (was gateway env + runtime)
 */

import { db } from "@db/app/client";
import { gatewayInstallations, gatewayTokens } from "@db/app/schema";
import type { SourceType } from "@repo/app-providers";
import { getProvider } from "@repo/app-providers";
import { decrypt } from "@repo/lib";
import { and, eq, isNotNull, lt } from "@vendor/db";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { getEncryptionKey } from "../../lib/encryption";
import { providerConfigs } from "../../lib/provider-configs";
import { updateTokenRecord } from "../../lib/token-store";
import { inngest } from "../client";

/** Refresh tokens expiring within this window. */
const REFRESH_WINDOW_MS = 10 * 60 * 1000; // 10 minutes

export const tokenRefresh = inngest.createFunction(
  {
    id: "platform/token.refresh",
    name: "Token Refresh (5m cron)",
    retries: 2,
    concurrency: [{ limit: 1 }],
  },
  { cron: "*/5 * * * *" },
  async ({ step }) => {
    // -- Step 1: Find installations with expiring tokens --------------------
    const expiringSoon = await step.run("list-expiring-tokens", async () => {
      const cutoff = new Date(Date.now() + REFRESH_WINDOW_MS).toISOString();

      return db
        .select({
          installationId: gatewayTokens.installationId,
          tokenId: gatewayTokens.id,
          encryptedRefreshToken: gatewayTokens.refreshToken,
          expiresAt: gatewayTokens.expiresAt,
          provider: gatewayInstallations.provider,
          externalId: gatewayInstallations.externalId,
          orgId: gatewayInstallations.orgId,
        })
        .from(gatewayTokens)
        .innerJoin(
          gatewayInstallations,
          eq(gatewayTokens.installationId, gatewayInstallations.id)
        )
        .where(
          and(
            eq(gatewayInstallations.status, "active"),
            isNotNull(gatewayTokens.refreshToken),
            isNotNull(gatewayTokens.expiresAt),
            lt(gatewayTokens.expiresAt, cutoff)
          )
        );
    });

    log.info("[token-refresh] tokens expiring soon", {
      count: expiringSoon.length,
    });

    // -- Step 2: Refresh each token -----------------------------------------
    let refreshedCount = 0;

    for (const row of expiringSoon) {
      await step.run(`refresh-${row.installationId}`, async () => {
        const providerName = row.provider as SourceType;
        const providerDef = getProvider(providerName);

        if (!providerDef) {
          return;
        }

        const auth = providerDef.auth;
        if (auth.kind !== "oauth" || !auth.refreshToken) {
          // Provider doesn't support token refresh — skip
          return;
        }

        const config = providerConfigs[providerName];

        if (!config) {
          log.warn("[token-refresh] provider not configured — skipping", {
            provider: providerName,
            installationId: row.installationId,
          });
          return;
        }

        try {
          const decryptedRefresh = await decrypt(
            row.encryptedRefreshToken!,
            getEncryptionKey()
          );
          const refreshed = await auth.refreshToken(
            config as never,
            decryptedRefresh
          );
          await updateTokenRecord(
            row.tokenId,
            refreshed,
            row.encryptedRefreshToken,
            row.expiresAt
          );

          refreshedCount++;
          log.info("[token-refresh] token refreshed", {
            installationId: row.installationId,
            provider: providerName,
          });
        } catch (err) {
          // Refresh failure is logged but not fatal — the request-time refresh
          // path in getActiveTokenForInstallation() is the fallback.
          log.warn("[token-refresh] refresh failed", {
            installationId: row.installationId,
            provider: providerName,
            error: err instanceof Error ? err.message : String(err),
          });
        }
      });
    }

    return { refreshed: refreshedCount };
  }
);

import { db } from "@db/app/client";
import { gatewayTokens } from "@db/app/schema";
import type { OAuthTokens } from "@repo/app-providers";
import { encrypt } from "@repo/lib";
import { eq } from "@vendor/db";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { getEncryptionKey } from "./encryption";

/**
 * Write an encrypted token record for an installation.
 * Used after OAuth code exchange.
 */
export async function writeTokenRecord(
  installationId: string,
  oauthTokens: OAuthTokens
): Promise<void> {
  const encryptedAccess = await encrypt(
    oauthTokens.accessToken,
    getEncryptionKey()
  );
  const encryptedRefresh = oauthTokens.refreshToken
    ? await encrypt(oauthTokens.refreshToken, getEncryptionKey())
    : null;

  const expiresAt = oauthTokens.expiresIn
    ? new Date(Date.now() + oauthTokens.expiresIn * 1000).toISOString()
    : null;

  await db
    .insert(gatewayTokens)
    .values({
      installationId,
      accessToken: encryptedAccess,
      refreshToken: encryptedRefresh,
      expiresAt,
      tokenType: oauthTokens.tokenType,
      scope: oauthTokens.scope,
    })
    .onConflictDoUpdate({
      target: gatewayTokens.installationId,
      set: {
        accessToken: encryptedAccess,
        refreshToken: encryptedRefresh,
        expiresAt,
        tokenType: oauthTokens.tokenType,
        scope: oauthTokens.scope,
        updatedAt: new Date().toISOString(),
      },
    });

  log.info("[token-store] token record written", {
    installationId,
    hasRefreshToken: !!oauthTokens.refreshToken,
    hasExpiry: !!oauthTokens.expiresIn,
  });
}

/** Minimum base64-decoded byte length for a valid AES-GCM encrypted value (12-byte IV + 16-byte tag). */
const MIN_ENCRYPTED_BYTES = 28;

/**
 * Best-effort check that `value` looks like an AES-GCM ciphertext (base64, >= {@link MIN_ENCRYPTED_BYTES} decoded bytes).
 * This is a heuristic — it can admit some plaintext that happens to be valid base64 of sufficient length.
 * For stricter validation consider a versioned prefix or non-printable-byte heuristic.
 */
function assertEncryptedFormat(value: string): void {
  try {
    const decoded = atob(value);
    if (decoded.length < MIN_ENCRYPTED_BYTES) {
      throw new Error("too short");
    }
  } catch (e) {
    const reason = e instanceof Error ? e.message : String(e);
    throw new Error(
      `existingEncryptedRefreshToken does not appear to be an encrypted value — refusing to persist potentially plaintext token (${reason})`
    );
  }
}

/**
 * Update an existing token record after refresh.
 *
 * @param existingEncryptedRefreshToken - The already-encrypted refresh token from the DB.
 *   Must be the raw encrypted (base64) value as stored; never pass a plaintext token.
 */
export async function updateTokenRecord(
  tokenId: string,
  oauthTokens: OAuthTokens,
  existingEncryptedRefreshToken: string | null,
  existingExpiresAt: string | null
): Promise<void> {
  const encryptedAccess = await encrypt(
    oauthTokens.accessToken,
    getEncryptionKey()
  );

  let newEncryptedRefresh: string | null;
  if (oauthTokens.refreshToken) {
    newEncryptedRefresh = await encrypt(
      oauthTokens.refreshToken,
      getEncryptionKey()
    );
  } else if (existingEncryptedRefreshToken) {
    assertEncryptedFormat(existingEncryptedRefreshToken);
    newEncryptedRefresh = existingEncryptedRefreshToken;
  } else {
    newEncryptedRefresh = null;
  }

  const newExpiresAt = oauthTokens.expiresIn
    ? new Date(Date.now() + oauthTokens.expiresIn * 1000).toISOString()
    : existingExpiresAt;

  await db
    .update(gatewayTokens)
    .set({
      accessToken: encryptedAccess,
      refreshToken: newEncryptedRefresh,
      expiresAt: newExpiresAt,
      updatedAt: new Date().toISOString(),
    })
    .where(eq(gatewayTokens.id, tokenId));

  log.info("[token-store] token record updated", {
    tokenId,
    refreshed: true,
    hasNewExpiry: !!oauthTokens.expiresIn,
  });
}

/**
 * Platform service tRPC initialization.
 *
 * Auth model: service-to-service JWT (not Clerk).
 * All callers are internal services (app, platform, inngest, cron).
 */
import { initTRPC, TRPCError } from "@trpc/server";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { createObservabilityMiddleware } from "@vendor/observability/trpc";
import superjson from "superjson";
import { ZodError } from "zod";

import { verifyServiceJWT } from "./lib/jwt";

// -- Auth Context -------------------------------------------------------------

/**
 * Discriminated union for platform service authentication.
 * Every request resolves to exactly one variant.
 */
export type PlatformAuthContext =
  | { type: "service"; caller: string }
  | { type: "webhook"; provider: string }
  | { type: "inngest" }
  | { type: "cron" }
  | { type: "unauthenticated" };

// -- Context Creation ---------------------------------------------------------

/**
 * Create tRPC context for platform service requests.
 *
 * Auth resolution order:
 * 1. Bearer JWT in Authorization header -> service auth
 * 2. x-trpc-source header for internal identification
 * 3. Unauthenticated fallback
 */
export const createPlatformTRPCContext = async (opts: { headers: Headers }) => {
  const source = opts.headers.get("x-trpc-source") ?? "unknown";

  // Check for service JWT in Authorization header
  const authHeader = opts.headers.get("authorization");
  if (authHeader?.startsWith("Bearer ")) {
    const token = authHeader.replace("Bearer ", "");

    try {
      const verified = await verifyServiceJWT(token);
      log.info("[trpc] platform service request", {
        source,
        auth: "service",
        caller: verified.caller,
      });
      return {
        auth: {
          type: "service" as const,
          caller: verified.caller,
        },
        headers: opts.headers,
      };
    } catch (error) {
      log.warn("[trpc] JWT verification error", {
        source,
        error: error instanceof Error ? error.message : String(error),
      });
    }
  }

  // No authentication
  log.info("[trpc] platform service request", {
    source,
    auth: "unauthenticated",
  });
  return {
    auth: { type: "unauthenticated" as const },
    headers: opts.headers,
  };
};

// -- tRPC Initialization ------------------------------------------------------

const isProduction = process.env.NODE_ENV === "production";

const t = initTRPC.context<typeof createPlatformTRPCContext>().create({
  transformer: superjson,
  errorFormatter: ({ shape, error }) => {
    const shouldSanitize =
      isProduction && error.code === "INTERNAL_SERVER_ERROR";

    return {
      ...shape,
      message: shouldSanitize ? "An unexpected error occurred" : shape.message,
      data: {
        ...shape.data,
        zodError:
          error.cause instanceof ZodError ? error.cause.flatten() : null,
      },
    };
  },
});

// -- Middleware ----------------------------------------------------------------

const observabilityMiddleware = t.middleware(
  createObservabilityMiddleware({
    isDev: t._config.isDev,
    extractAuth: (ctx) => ({
      ...(ctx.auth.type === "service" && { caller: ctx.auth.caller }),
    }),
  })
);

// -- Router & Procedure Exports -----------------------------------------------

export const createTRPCRouter = t.router;
export const createCallerFactory = t.createCallerFactory;

/**
 * Public procedure -- no auth required.
 * Use for health checks or publicly accessible endpoints.
 */
export const publicProcedure = t.procedure.use(observabilityMiddleware);

/**
 * Service procedure -- requires valid service JWT.
 * Used by app or other internal services calling platform.
 *
 * Guarantees `ctx.auth.type === "service"` and `ctx.auth.caller` is available.
 */
export const serviceProcedure = t.procedure
  .use(observabilityMiddleware)
  .use(({ ctx, next }) => {
    if (ctx.auth.type !== "service") {
      throw new TRPCError({
        code: "UNAUTHORIZED",
        message:
          "Service authentication required. Provide a valid service JWT in the Authorization header.",
      });
    }

    return next({
      ctx: {
        ...ctx,
        auth: ctx.auth as Extract<PlatformAuthContext, { type: "service" }>,
      },
    });
  });

/**
 * Admin procedure -- requires service JWT from an admin caller.
 * Used for administrative operations (reindex, purge, etc.).
 *
 * Restricts `ctx.auth.caller` to "admin" only.
 */
export const adminProcedure = t.procedure
  .use(observabilityMiddleware)
  .use(({ ctx, next }) => {
    if (ctx.auth.type !== "service") {
      throw new TRPCError({
        code: "UNAUTHORIZED",
        message: "Service authentication required.",
      });
    }

    if (ctx.auth.caller !== "admin") {
      throw new TRPCError({
        code: "FORBIDDEN",
        message:
          "Admin access required. This endpoint is restricted to admin callers.",
      });
    }

    return next({
      ctx: {
        ...ctx,
        auth: ctx.auth as Extract<PlatformAuthContext, { type: "service" }>,
      },
    });
  });

