          installationId,
          provider,
          orgId,
          error: err instanceof Error ? err.message : String(err),
        });
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: `Failed to get token: ${err instanceof Error ? err.message : String(err)}`,
        });
      }

