      if (input.queryParams && Object.keys(input.queryParams).length > 0) {
        url += `?${new URLSearchParams(input.queryParams).toString()}`;
      }

      // Build headers
      const authHeader = api.buildAuthHeader
        ? api.buildAuthHeader(token)
        : `Bearer ${token}`;

      const headers: Record<string, string> = {
        Authorization: authHeader,
        ...(api.defaultHeaders ?? {}),
      };

      // Build fetch options
      const fetchOptions: RequestInit = {
        method: endpoint.method,
        headers,
        signal: AbortSignal.timeout(endpoint.timeout ?? 30_000),
      };

      if (input.body) {
        fetchOptions.body = JSON.stringify(input.body);
        headers["Content-Type"] = "application/json";
      }

      // Execute with 401 retry
      let response = await fetch(url, fetchOptions);

      if (response.status === 401) {
        let freshToken: string | null = null;
        if (endpoint.buildAuth) {
          try {
            freshToken = await endpoint.buildAuth(config);
          } catch (retryErr) {
            log.warn("[proxy] auth rebuild failed during 401 retry", {
              installationId: input.installationId,
              provider: providerName,
              endpointId: input.endpointId,
              error:
                retryErr instanceof Error ? retryErr.message : String(retryErr),
            });
            // fall through without retry
          }
        } else {
          // SAFETY: getProvider() returns the full generic ProviderDefinition<TConfig, ...>
          // but the helper takes the base ProviderDefinition. The generic parameters are
          // erased at runtime -- the cast is safe because the concrete type is a supertype.
          freshToken = await forceRefreshToken(
            installation,
            config,
            providerDef as ProviderDefinition
          );
        }
        if (freshToken && freshToken !== token) {
          headers.Authorization = api.buildAuthHeader
            ? api.buildAuthHeader(freshToken)
            : `Bearer ${freshToken}`;
          response = await fetch(url, { ...fetchOptions, headers });
        }
      }

      // Return raw response -- no parsing, no transformation
      const data = await response.json().catch((parseErr: unknown) => {
        log.warn("[proxy] response body parse failed", {
          installationId: input.installationId,
          provider: providerName,
          endpointId: input.endpointId,
          status: response.status,
          error:
            parseErr instanceof Error ? parseErr.message : String(parseErr),
        });
        return null;
      });
      const responseHeaders: Record<string, string> = {};
      response.headers.forEach((value, key) => {
        responseHeaders[key] = value;
      });

      return {
        status: response.status,
        data,
        headers: responseHeaders,
      };
    }),
} satisfies TRPCRouterRecord;

/**
 * Proxy tRPC sub-router.
 *
 * Ported from apps/gateway/src/routes/connections.ts (proxy endpoints).
 * All procedures use serviceProcedure (JWT auth required).
 *
 * listEndpoints: Returns the provider's API catalog (strips Zod responseSchema).
 * execute: Pure authenticated API proxy with 401-retry pattern.
 */
import { db } from "@db/app/client";
import { gatewayInstallations } from "@db/app/schema";
import type { ProviderApi, ProviderDefinition } from "@repo/app-providers";
import { getProvider } from "@repo/app-providers";
import type { TRPCRouterRecord } from "@trpc/server";
import { TRPCError } from "@trpc/server";
import { eq } from "@vendor/db";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { z } from "zod";
import { providerConfigs } from "../../lib/provider-configs";
import {
  forceRefreshToken,
  getActiveTokenForInstallation,
} from "../../lib/token-helpers";
import { serviceProcedure } from "../../trpc";

// ── Proxy Router ────────────────────────────────────────────────────────────

export const proxyRouter = {
  /**
   * List available API endpoints for a connection's provider.
   * Source: GET /connections/:id/proxy/endpoints
   *
   * Strips responseSchema (Zod types are not JSON-serializable).
   */
  listEndpoints: serviceProcedure
    .input(
      z.object({
        installationId: z.string(),
      })
    )
    .query(async ({ input }) => {
      const installation = await db.query.gatewayInstallations.findFirst({
        where: eq(gatewayInstallations.id, input.installationId),
      });

      if (!installation) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "Connection not found",
        });
      }

      const providerDef = getProvider(installation.provider);
      if (!providerDef) {
        throw new TRPCError({
          code: "BAD_REQUEST",
          message: "Unknown provider",
        });
      }

      // Strip responseSchema (Zod types are not serializable)
      const endpoints: Record<
        string,
        { method: string; path: string; description: string; timeout?: number }
      > = {};
      for (const [key, ep] of Object.entries(providerDef.api.endpoints)) {
        endpoints[key] = {
          method: ep.method,
          path: ep.path,
          description: ep.description,
          ...(ep.timeout ? { timeout: ep.timeout } : {}),
        };
      }

      return {
        provider: installation.provider,
        baseUrl: providerDef.api.baseUrl,
        endpoints,
      };
    }),

  /**
   * Pure authenticated API proxy. Zero domain knowledge.
   * Source: POST /connections/:id/proxy/execute
   *
   * Handles: endpoint validation, auth injection, 401 retry.
   * Returns: raw { status, data, headers }.
   */
  execute: serviceProcedure
    .input(
      z.object({
        installationId: z.string(),
        endpointId: z.string().min(1),
        pathParams: z.record(z.string(), z.string()).optional(),
        queryParams: z.record(z.string(), z.string()).optional(),
        body: z.unknown().optional(),
      })
    )
    .mutation(async ({ input }) => {
      const installation = await db.query.gatewayInstallations.findFirst({
        where: eq(gatewayInstallations.id, input.installationId),
      });

      if (!installation) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "Connection not found",
        });
      }

      if (installation.status !== "active") {
        throw new TRPCError({
          code: "BAD_REQUEST",
          message: `Installation not active (status: ${installation.status})`,
        });
      }

      const providerName = installation.provider;
      const providerDef = getProvider(providerName);
      if (!providerDef) {
        throw new TRPCError({
          code: "BAD_REQUEST",
          message: "Unknown provider",
        });
      }

      const config = providerConfigs[providerName];

      // Widen to base ProviderApi for runtime-dynamic endpoint/header access.
      // Each provider's TApi satisfies ProviderApi -- structural widening, not a cast.
      const api: ProviderApi = providerDef.api;

      // Validate endpoint exists in catalog
      const endpoint = api.endpoints[input.endpointId];
      if (!endpoint) {
        throw new TRPCError({
          code: "BAD_REQUEST",
          message: `Unknown endpoint: ${input.endpointId}. Available: ${Object.keys(api.endpoints).join(", ")}`,
        });
      }

      // Get active token.
      // If the endpoint declares its own buildAuth, use it (e.g. GitHub App JWT for
      // app-level endpoints). Otherwise fall through to the default per-installation token flow.
      let token: string;
      try {
        if (endpoint.buildAuth) {
          token = await endpoint.buildAuth(config);
        } else {
          // SAFETY: getProvider() returns the full generic ProviderDefinition<TConfig, ...>
          // but the helper takes the base ProviderDefinition. The generic parameters are
          // erased at runtime -- the cast is safe because the concrete type is a supertype.
          ({ token } = await getActiveTokenForInstallation(
            installation,
            config,
            providerDef as ProviderDefinition
          ));
        }
      } catch (err) {
        const message = parseError(err);
        log.error("[proxy] token acquisition failed", {
          installationId: input.installationId,
          provider: providerName,
          error: message,
        });
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: `token_error: ${message}`,
        });
      }

      // Build URL
      let path = endpoint.path;
      if (input.pathParams) {
        for (const [key, val] of Object.entries(input.pathParams)) {
          path = path.replace(`{${key}}`, encodeURIComponent(val));
        }
      }

      let url = `${api.baseUrl}${path}`;
      if (input.queryParams && Object.keys(input.queryParams).length > 0) {
        url += `?${new URLSearchParams(input.queryParams).toString()}`;
      }

      // Build headers
      const authHeader = api.buildAuthHeader
        ? api.buildAuthHeader(token)
        : `Bearer ${token}`;

      const headers: Record<string, string> = {
        Authorization: authHeader,
        ...(api.defaultHeaders ?? {}),
      };

      // Build fetch options
      const fetchOptions: RequestInit = {
        method: endpoint.method,
        headers,
        signal: AbortSignal.timeout(endpoint.timeout ?? 30_000),
      };

      if (input.body) {
        fetchOptions.body = JSON.stringify(input.body);
        headers["Content-Type"] = "application/json";
      }

      // Execute with 401 retry
      let response = await fetch(url, fetchOptions);

      if (response.status === 401) {
        let freshToken: string | null = null;
        if (endpoint.buildAuth) {
          try {
            freshToken = await endpoint.buildAuth(config);
          } catch (retryErr) {
            log.warn("[proxy] auth rebuild failed during 401 retry", {
              installationId: input.installationId,
              provider: providerName,
              endpointId: input.endpointId,
              error: parseError(retryErr),
            });
            // fall through without retry
          }
        } else {
          // SAFETY: getProvider() returns the full generic ProviderDefinition<TConfig, ...>
          // but the helper takes the base ProviderDefinition. The generic parameters are
          // erased at runtime -- the cast is safe because the concrete type is a supertype.
          freshToken = await forceRefreshToken(
            installation,
            config,
            providerDef as ProviderDefinition
          );
        }
        if (freshToken && freshToken !== token) {
          headers.Authorization = api.buildAuthHeader
            ? api.buildAuthHeader(freshToken)
            : `Bearer ${freshToken}`;
          response = await fetch(url, { ...fetchOptions, headers });
        }
      }

      // Return raw response -- no parsing, no transformation
      const data = await response.json().catch((parseErr: unknown) => {
        log.warn("[proxy] response body parse failed", {
          installationId: input.installationId,
          provider: providerName,
          endpointId: input.endpointId,
          status: response.status,
          error:
            parseErr instanceof Error ? parseErr.message : String(parseErr),
        });
        return null;
      });
      const responseHeaders: Record<string, string> = {};
      response.headers.forEach((value, key) => {
        responseHeaders[key] = value;
      });

      return {
        status: response.status,
        data,
        headers: responseHeaders,
      };
    }),
} satisfies TRPCRouterRecord;

/**
 * Platform backfill orchestrator
 *
 * Ported from apps/backfill/src/workflows/backfill-orchestrator.ts
 *
 * KEY CHANGES vs backfill service:
 * - Function ID: platform/backfill.orchestrator (was backfill/run.orchestrator)
 * - Trigger: platform/backfill.run.requested (was backfill/run.requested)
 * - cancelOn: platform/backfill.run.cancelled (was backfill/run.cancelled)
 * - Replace createGatewayClient() HTTP calls with direct DB queries
 * - Replace relay.replayCatchup() with direct DB query + inngest.send("platform/webhook.received")
 * - step.invoke() references platformEntityWorker
 */

import { db } from "@db/app/client";
import {
  gatewayBackfillRuns,
  gatewayInstallations,
  gatewayWebhookDeliveries,
  orgIntegrations,
} from "@db/app/schema";
import { getProvider, type ProviderDefinition } from "@repo/app-providers";
import { and, eq, inArray, notInArray } from "@vendor/db";
import { NonRetriableError } from "@vendor/inngest";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { providerConfigs } from "../../lib/provider-configs";
import { getActiveTokenForInstallation } from "../../lib/token-helpers";
import { inngest } from "../client";
import { platformEntityWorker } from "./platform-entity-worker";

export const platformBackfillOrchestrator = inngest.createFunction(
  {
    id: "platform/backfill.orchestrator",
    name: "Platform Backfill Orchestrator",
    retries: 3,
    concurrency: [
      // 1 backfill per connection — prevents duplicate backfills
      { limit: 1, key: "event.data.installationId" },
      // 10 total concurrent orchestrators (each lightweight — just fan-out + wait)
      { limit: 10 },
    ],
    cancelOn: [
      {
        event: "platform/backfill.run.cancelled",
        match: "data.installationId",
      },
    ],
    // Orchestrator waits for all entity workers — must accommodate the longest
    // Worst case: 15 work units (5 repos x 3 entities), 5 concurrent, each 2hr
    // = 15/5 * 2hr = 6hr total. Set to 8hr for safety.
    timeouts: { start: "2m", finish: "8h" },
  },
  { event: "platform/backfill.run.requested" },
  async ({ event, step }) => {
    const {
      installationId,
      provider,
      orgId,
      depth,
      entityTypes,
      holdForReplay,
      correlationId,
    } = event.data;

    log.info("[backfill-orchestrator] starting", {
      installationId,
      provider,
      depth,
      entityTypes,
      correlationId,
    });

    if (depth <= 0) {
      throw new NonRetriableError(
        `Invalid depth: ${depth} — must be a positive number of days`
      );
    }

    // ── Step 1: Fetch connection details from DB (replaces gateway HTTP call) ──
    const connection = await step.run("get-connection", async () => {
      const installationRows = await db
        .select()
        .from(gatewayInstallations)
        .where(eq(gatewayInstallations.id, installationId))
        .limit(1);

      const conn = installationRows[0];
      if (!conn) {
        throw new NonRetriableError(`Connection not found: ${installationId}`);
      }
      if (conn.status !== "active") {
        throw new NonRetriableError(
          `Connection is not active: ${installationId} (status: ${conn.status})`
        );
      }
      // Tenant isolation: verify caller-supplied orgId matches the DB-canonical value
      if (conn.orgId !== orgId) {
        throw new NonRetriableError(
          `orgId mismatch: event has "${orgId}" but connection belongs to "${conn.orgId}"`
        );
      }

      // Fetch linked resources from orgIntegrations
      const resources = await db
        .select({
          providerResourceId: orgIntegrations.providerResourceId,
        })
        .from(orgIntegrations)
        .where(
          and(
            eq(orgIntegrations.installationId, installationId),
            eq(orgIntegrations.status, "active")
          )
        );

      return {
        id: conn.id,
        externalId: conn.externalId,
        provider: conn.provider,
        orgId: conn.orgId,
        status: conn.status,
        resources,
      };
    });

    log.info("[backfill-orchestrator] connection fetched", {
      installationId,
      provider,
      resourceCount: connection.resources.length,
      correlationId,
    });

    // ── Step 1b: Fetch backfill history from DB (replaces gateway HTTP call) ──
    const backfillHistory = await step.run("get-backfill-history", async () => {
      return db
        .select({
          entityType: gatewayBackfillRuns.entityType,
          providerResourceId: gatewayBackfillRuns.providerResourceId,
          since: gatewayBackfillRuns.since,
        })
        .from(gatewayBackfillRuns)
        .where(
          and(
            eq(gatewayBackfillRuns.installationId, installationId),
            eq(gatewayBackfillRuns.status, "completed")
          )
        );
    });

    // ── Step 2: Resolve entity types and validate provider ──
    const providerDef = getProvider(provider);
    if (!providerDef) {
      throw new NonRetriableError(
        `No backfill provider for provider: ${provider}`
      );
    }
    if (!providerDef.backfill) {
      throw new NonRetriableError(
        `Provider "${provider}" does not support backfill`
      );
    }

    const resolvedEntityTypes =
      entityTypes && entityTypes.length > 0
        ? entityTypes
        : [...providerDef.backfill.defaultEntityTypes];

    // Compute `since` inside a step so it's deterministic across retries/replays
    const since = await step.run("compute-since", () =>
      new Date(Date.now() - depth * 24 * 60 * 60 * 1000).toISOString()
    );

    // ── Step 2b: Resolve resource names live from provider API ──
    const resolvedResources = await step.run(
      "resolve-resource-meta",
      async () => {
        const config = providerConfigs[provider];
        const { token } = await getActiveTokenForInstallation(
          {
            id: connection.id,
            externalId: connection.externalId,
            provider: connection.provider,
          },
          config,
          providerDef as ProviderDefinition
        );

        // Providers where resourceName is NOT needed for API routing can fall back
        const resourceNameRequiredForRouting = ["github", "sentry"].includes(
          provider
        );

        return Promise.all(
          connection.resources.map(async (r) => {
            try {
              const resourceName =
                await providerDef.backfill!.resolveResourceMeta({
                  providerResourceId: r.providerResourceId,
                  token,
                });
              return { providerResourceId: r.providerResourceId, resourceName };
            } catch (err) {
              log.warn("[backfill] failed to resolve resource meta", {
                providerResourceId: r.providerResourceId,
                error: err instanceof Error ? err.message : String(err),
              });
              if (resourceNameRequiredForRouting) {
                // GitHub/Sentry: resourceName is used in buildRequest pathParams — must skip
                return null;
              }
              // Linear/Vercel: resourceName is only used in adapter output — fallback is safe
              return {
                providerResourceId: r.providerResourceId,
                resourceName: r.providerResourceId,
              };
            }
          })
        ).then((results) =>
          results.filter((r): r is NonNullable<typeof r> => r !== null)
        );
      }
    );

    // ── Step 3: Enumerate work units (resource x entityType) ──
    const workUnits = resolvedResources.flatMap((resource) => {
      return resolvedEntityTypes.map((entityType: string) => ({
        entityType,
        resource: {
          providerResourceId: resource.providerResourceId,
          resourceName: resource.resourceName,
        },
        workUnitId: `${resource.providerResourceId}-${entityType}`,
      }));
    });

    // ── Gap-aware filtering: skip (resource, entityType) pairs covered by prior runs ──
    const filteredWorkUnits = workUnits.filter((wu) => {
      const priorRun = backfillHistory.find(
        (h) =>
          h.entityType === wu.entityType &&
          h.providerResourceId === wu.resource.providerResourceId
      );
      if (!priorRun) {
        return true; // No prior run — must fetch
      }
      // Prior run's since ≤ requested since → already covered
      return new Date(priorRun.since) > new Date(since);
    });

    log.info("[backfill-orchestrator] work units planned", {
      installationId,
      provider,
      total: workUnits.length,
      afterFilter: filteredWorkUnits.length,
      skippedByGapFilter: workUnits.length - filteredWorkUnits.length,
      since,
      correlationId,
    });

    if (filteredWorkUnits.length === 0) {
      return {
        success: true,
        installationId,
        provider,
        workUnits: workUnits.length,
        skipped: workUnits.length,
        dispatched: 0,
        eventsProduced: 0,
        eventsDispatched: 0,
      };
    }

    log.info("[backfill-orchestrator] dispatching entity workers", {
      installationId,
      provider,
      count: filteredWorkUnits.length,
      workUnitIds: filteredWorkUnits.map((wu) => wu.workUnitId),
      correlationId,
    });

    // ── Step 4: Invoke entity workers directly ──
    const completionResults = await Promise.all(
      filteredWorkUnits.map(async (wu) => {
        try {
          const result = await step.invoke(`invoke-${wu.workUnitId}`, {
            function: platformEntityWorker,
            data: {
              installationId,
              provider,
              orgId,
              entityType: wu.entityType,
              resource: wu.resource,
              since,
              depth,
              holdForReplay,
              correlationId,
            },
            timeout: "4h",
          });
          return {
            entityType: wu.entityType,
            resourceId: wu.resource.providerResourceId,
            success: true,
            eventsProduced: result.eventsProduced,
            eventsDispatched: result.eventsDispatched,
            pagesProcessed: result.pagesProcessed,
          };
        } catch (err) {
          return {
            entityType: wu.entityType,
            resourceId: wu.resource.providerResourceId,
            success: false,
            eventsProduced: 0,
            eventsDispatched: 0,
            pagesProcessed: 0,
            error: err instanceof Error ? err.message : "entity worker failed",
          };
        }
      })
    );

    // ── Step 5: Aggregate results ──
    const succeeded = completionResults.filter((r) => r.success);
    const failed = completionResults.filter((r) => !r.success);

    // ── Step 6: Persist run records — one per (resource, entityType) ──
    if (completionResults.length > 0) {
      await step.run("persist-run-records", async () => {
        const now = new Date().toISOString();
        for (const r of completionResults) {
          const sharedFields = {
            since,
            depth,
            status: r.success ? "completed" : "failed",
            pagesProcessed: r.pagesProcessed,
            eventsProduced: r.eventsProduced,
            eventsDispatched: r.eventsDispatched,
            error: r.success ? null : (r.error ?? null),
            completedAt: now,
            updatedAt: now,
          };

          await db
            .insert(gatewayBackfillRuns)
            .values({
              installationId,
              entityType: r.entityType,
              providerResourceId: r.resourceId,
              ...sharedFields,
              startedAt: now,
            })
            .onConflictDoUpdate({
              target: [
                gatewayBackfillRuns.installationId,
                gatewayBackfillRuns.providerResourceId,
                gatewayBackfillRuns.entityType,
              ],
              set: sharedFields,
            });
        }
      });
    }

    // ── Step 7: Replay held webhooks (replaces relay.replayCatchup) ──
    // When holdForReplay is set, entity workers persist webhooks without delivery.
    // After all workers complete, drain them by querying DB directly and sending
    // platform/webhook.received events so they are processed in chronological order.
    if (holdForReplay && succeeded.length > 0) {
      log.info("[backfill-orchestrator] replaying held webhooks", {
        installationId,
        succeededWorkers: succeeded.length,
        correlationId,
      });
      await step.run("replay-held-webhooks", async () => {
        const BATCH_SIZE = 200;
        const MAX_ITERATIONS = 500; // Safety cap: 500 * 200 = 100k webhooks max
        let iterations = 0;
        const processedIds: string[] = [];

        while (iterations < MAX_ITERATIONS) {
          iterations++;

          // Query un-delivered webhooks for this installation
          const conditions = [
            eq(gatewayWebhookDeliveries.installationId, installationId),
            eq(gatewayWebhookDeliveries.status, "held"),
          ];
          if (processedIds.length > 0) {
            conditions.push(
              notInArray(gatewayWebhookDeliveries.id, processedIds)
            );
          }

          const deliveries = await db
            .select()
            .from(gatewayWebhookDeliveries)
            .where(and(...conditions))
            .orderBy(gatewayWebhookDeliveries.receivedAt)
            .limit(BATCH_SIZE);

          if (deliveries.length === 0) {
            break;
          }

          // Send each delivery as a platform/webhook.received event
          const events = deliveries
            .filter((d) => d.payload)
            .map((d) => ({
              name: "platform/webhook.received" as const,
              data: {
                provider: d.provider,
                deliveryId: d.deliveryId,
                eventType: d.eventType,
                resourceId: null as string | null,
                payload: JSON.parse(d.payload!) as unknown,
                receivedAt: new Date(d.receivedAt).getTime(),
                preResolved: {
                  connectionId: installationId,
                  orgId: connection.orgId,
                },
                correlationId,
              },
            }));

          if (events.length > 0) {
            await inngest.send(events);
          }

          // Mark replayed deliveries so they aren't re-sent on retry (held -> enqueued)
          const replayedIds = deliveries.map((d) => d.id);
          if (replayedIds.length > 0) {
            await db
              .update(gatewayWebhookDeliveries)
              .set({ status: "enqueued" })
              .where(
                and(
                  eq(gatewayWebhookDeliveries.installationId, installationId),
                  inArray(gatewayWebhookDeliveries.id, replayedIds)
                )
              );
          }

          // Track processed IDs to exclude from next batch
          for (const d of deliveries) {
            processedIds.push(d.id);
          }
        }

        if (iterations >= MAX_ITERATIONS) {
          log.error("[backfill] replay-held-webhooks hit iteration cap", {
            installationId,
            iterations,
            correlationId,
          });
        }
      });
    }

    log.info("[backfill-orchestrator] complete", {
      installationId,
      provider,
      completed: succeeded.length,
      failed: failed.length,
      eventsProduced: completionResults.reduce(
        (sum, r) => sum + r.eventsProduced,
        0
      ),
      eventsDispatched: completionResults.reduce(
        (sum, r) => sum + r.eventsDispatched,
        0
      ),
      correlationId,
    });

    return {
      success: failed.length === 0,
      installationId,
      provider,
      workUnits: workUnits.length,
      skipped: workUnits.length - filteredWorkUnits.length,
      dispatched: filteredWorkUnits.length,
      completed: succeeded.length,
      failed: failed.length,
      eventsProduced: completionResults.reduce(
        (sum, r) => sum + r.eventsProduced,
        0
      ),
      eventsDispatched: completionResults.reduce(
        (sum, r) => sum + r.eventsDispatched,
        0
      ),
      results: completionResults,
    };
  }
);

/**
 * Platform backfill orchestrator
 *
 * Ported from apps/backfill/src/workflows/backfill-orchestrator.ts
 *
 * KEY CHANGES vs backfill service:
 * - Function ID: platform/backfill.orchestrator (was backfill/run.orchestrator)
 * - Trigger: platform/backfill.run.requested (was backfill/run.requested)
 * - cancelOn: platform/backfill.run.cancelled (was backfill/run.cancelled)
 * - Replace createGatewayClient() HTTP calls with direct DB queries
 * - Replace relay.replayCatchup() with direct DB query + inngest.send("platform/webhook.received")
 * - step.invoke() references platformEntityWorker
 */

import { db } from "@db/app/client";
import {
  gatewayBackfillRuns,
  gatewayInstallations,
  gatewayWebhookDeliveries,
  orgIntegrations,
} from "@db/app/schema";
import { getProvider, type ProviderDefinition } from "@repo/app-providers";
import { and, eq, inArray, notInArray } from "@vendor/db";
import { NonRetriableError } from "@vendor/inngest";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { providerConfigs } from "../../lib/provider-configs";
import { getActiveTokenForInstallation } from "../../lib/token-helpers";
import { inngest } from "../client";
import { platformEntityWorker } from "./platform-entity-worker";

export const platformBackfillOrchestrator = inngest.createFunction(
  {
    id: "platform/backfill.orchestrator",
    name: "Platform Backfill Orchestrator",
    retries: 3,
    concurrency: [
      // 1 backfill per connection — prevents duplicate backfills
      { limit: 1, key: "event.data.installationId" },
      // 10 total concurrent orchestrators (each lightweight — just fan-out + wait)
      { limit: 10 },
    ],
    cancelOn: [
      {
        event: "platform/backfill.run.cancelled",
        match: "data.installationId",
      },
    ],
    // Orchestrator waits for all entity workers — must accommodate the longest
    // Worst case: 15 work units (5 repos x 3 entities), 5 concurrent, each 2hr
    // = 15/5 * 2hr = 6hr total. Set to 8hr for safety.
    timeouts: { start: "2m", finish: "8h" },
  },
  { event: "platform/backfill.run.requested" },
  async ({ event, step }) => {
    const {
      installationId,
      provider,
      orgId,
      depth,
      entityTypes,
      holdForReplay,
      correlationId,
    } = event.data;

    log.info("[backfill-orchestrator] starting", {
      installationId,
      provider,
      depth,
      entityTypes,
      correlationId,
    });

    if (depth <= 0) {
      throw new NonRetriableError(
        `Invalid depth: ${depth} — must be a positive number of days`
      );
    }

    // ── Step 1: Fetch connection details from DB (replaces gateway HTTP call) ──
    const connection = await step.run("get-connection", async () => {
      const installationRows = await db
        .select()
        .from(gatewayInstallations)
        .where(eq(gatewayInstallations.id, installationId))
        .limit(1);

      const conn = installationRows[0];
      if (!conn) {
        throw new NonRetriableError(`Connection not found: ${installationId}`);
      }
      if (conn.status !== "active") {
        throw new NonRetriableError(
          `Connection is not active: ${installationId} (status: ${conn.status})`
        );
      }
      // Tenant isolation: verify caller-supplied orgId matches the DB-canonical value
      if (conn.orgId !== orgId) {
        throw new NonRetriableError(
          `orgId mismatch: event has "${orgId}" but connection belongs to "${conn.orgId}"`
        );
      }

      // Fetch linked resources from orgIntegrations
      const resources = await db
        .select({
          providerResourceId: orgIntegrations.providerResourceId,
        })
        .from(orgIntegrations)
        .where(
          and(
            eq(orgIntegrations.installationId, installationId),
            eq(orgIntegrations.status, "active")
          )
        );

      return {
        id: conn.id,
        externalId: conn.externalId,
        provider: conn.provider,
        orgId: conn.orgId,
        status: conn.status,
        resources,
      };
    });

    log.info("[backfill-orchestrator] connection fetched", {
      installationId,
      provider,
      resourceCount: connection.resources.length,
      correlationId,
    });

    // ── Step 1b: Fetch backfill history from DB (replaces gateway HTTP call) ──
    const backfillHistory = await step.run("get-backfill-history", async () => {
      return db
        .select({
          entityType: gatewayBackfillRuns.entityType,
          providerResourceId: gatewayBackfillRuns.providerResourceId,
          since: gatewayBackfillRuns.since,
        })
        .from(gatewayBackfillRuns)
        .where(
          and(
            eq(gatewayBackfillRuns.installationId, installationId),
            eq(gatewayBackfillRuns.status, "completed")
          )
        );
    });

    // ── Step 2: Resolve entity types and validate provider ──
    const providerDef = getProvider(provider);
    if (!providerDef) {
      throw new NonRetriableError(
        `No backfill provider for provider: ${provider}`
      );
    }
    if (!providerDef.backfill) {
      throw new NonRetriableError(
        `Provider "${provider}" does not support backfill`
      );
    }

    const resolvedEntityTypes =
      entityTypes && entityTypes.length > 0
        ? entityTypes
        : [...providerDef.backfill.defaultEntityTypes];

    // Compute `since` inside a step so it's deterministic across retries/replays
    const since = await step.run("compute-since", () =>
      new Date(Date.now() - depth * 24 * 60 * 60 * 1000).toISOString()
    );

    // ── Step 2b: Resolve resource names live from provider API ──
    const resolvedResources = await step.run(
      "resolve-resource-meta",
      async () => {
        const config = providerConfigs[provider];
        const { token } = await getActiveTokenForInstallation(
          {
            id: connection.id,
            externalId: connection.externalId,
            provider: connection.provider,
          },
          config,
          providerDef as ProviderDefinition
        );

        // Providers where resourceName is NOT needed for API routing can fall back
        const resourceNameRequiredForRouting = ["github", "sentry"].includes(
          provider
        );

        return Promise.all(
          connection.resources.map(async (r) => {
            try {
              const resourceName =
                await providerDef.backfill!.resolveResourceMeta({
                  providerResourceId: r.providerResourceId,
                  token,
                });
              return { providerResourceId: r.providerResourceId, resourceName };
            } catch (err) {
              log.warn("[backfill] failed to resolve resource meta", {
                providerResourceId: r.providerResourceId,
                error: parseError(err),
              });
              if (resourceNameRequiredForRouting) {
                // GitHub/Sentry: resourceName is used in buildRequest pathParams — must skip
                return null;
              }
              // Linear/Vercel: resourceName is only used in adapter output — fallback is safe
              return {
                providerResourceId: r.providerResourceId,
                resourceName: r.providerResourceId,
              };
            }
          })
        ).then((results) =>
          results.filter((r): r is NonNullable<typeof r> => r !== null)
        );
      }
    );

    // ── Step 3: Enumerate work units (resource x entityType) ──
    const workUnits = resolvedResources.flatMap((resource) => {
      return resolvedEntityTypes.map((entityType: string) => ({
        entityType,
        resource: {
          providerResourceId: resource.providerResourceId,
          resourceName: resource.resourceName,
        },
        workUnitId: `${resource.providerResourceId}-${entityType}`,
      }));
    });

    // ── Gap-aware filtering: skip (resource, entityType) pairs covered by prior runs ──
    const filteredWorkUnits = workUnits.filter((wu) => {
      const priorRun = backfillHistory.find(
        (h) =>
          h.entityType === wu.entityType &&
          h.providerResourceId === wu.resource.providerResourceId
      );
      if (!priorRun) {
        return true; // No prior run — must fetch
      }
      // Prior run's since ≤ requested since → already covered
      return new Date(priorRun.since) > new Date(since);
    });

    log.info("[backfill-orchestrator] work units planned", {
      installationId,
      provider,
      total: workUnits.length,
      afterFilter: filteredWorkUnits.length,
      skippedByGapFilter: workUnits.length - filteredWorkUnits.length,
      since,
      correlationId,
    });

    if (filteredWorkUnits.length === 0) {
      return {
        success: true,
        installationId,
        provider,
        workUnits: workUnits.length,
        skipped: workUnits.length,
        dispatched: 0,
        eventsProduced: 0,
        eventsDispatched: 0,
      };
    }

    log.info("[backfill-orchestrator] dispatching entity workers", {
      installationId,
      provider,
      count: filteredWorkUnits.length,
      workUnitIds: filteredWorkUnits.map((wu) => wu.workUnitId),
      correlationId,
    });

    // ── Step 4: Invoke entity workers directly ──
    const completionResults = await Promise.all(
      filteredWorkUnits.map(async (wu) => {
        try {
          const result = await step.invoke(`invoke-${wu.workUnitId}`, {
            function: platformEntityWorker,
            data: {
              installationId,
              provider,
              orgId,
              entityType: wu.entityType,
              resource: wu.resource,
              since,
              depth,
              holdForReplay,
              correlationId,
            },
            timeout: "4h",
          });
          return {
            entityType: wu.entityType,
            resourceId: wu.resource.providerResourceId,
            success: true,
            eventsProduced: result.eventsProduced,
            eventsDispatched: result.eventsDispatched,
            pagesProcessed: result.pagesProcessed,
          };
        } catch (err) {
          return {
            entityType: wu.entityType,
            resourceId: wu.resource.providerResourceId,
            success: false,
            eventsProduced: 0,
            eventsDispatched: 0,
            pagesProcessed: 0,
            error: err instanceof Error ? err.message : "entity worker failed",
          };
        }
      })
    );

    // ── Step 5: Aggregate results ──
    const succeeded = completionResults.filter((r) => r.success);
    const failed = completionResults.filter((r) => !r.success);

    // ── Step 6: Persist run records — one per (resource, entityType) ──
    if (completionResults.length > 0) {
      await step.run("persist-run-records", async () => {
        const now = new Date().toISOString();
        for (const r of completionResults) {
          const sharedFields = {
            since,
            depth,
            status: r.success ? "completed" : "failed",
            pagesProcessed: r.pagesProcessed,
            eventsProduced: r.eventsProduced,
            eventsDispatched: r.eventsDispatched,
            error: r.success ? null : (r.error ?? null),
            completedAt: now,
            updatedAt: now,
          };

          await db
            .insert(gatewayBackfillRuns)
            .values({
              installationId,
              entityType: r.entityType,
              providerResourceId: r.resourceId,
              ...sharedFields,
              startedAt: now,
            })
            .onConflictDoUpdate({
              target: [
                gatewayBackfillRuns.installationId,
                gatewayBackfillRuns.providerResourceId,
                gatewayBackfillRuns.entityType,
              ],
              set: sharedFields,
            });
        }
      });
    }

    // ── Step 7: Replay held webhooks (replaces relay.replayCatchup) ──
    // When holdForReplay is set, entity workers persist webhooks without delivery.
    // After all workers complete, drain them by querying DB directly and sending
    // platform/webhook.received events so they are processed in chronological order.
    if (holdForReplay && succeeded.length > 0) {
      log.info("[backfill-orchestrator] replaying held webhooks", {
        installationId,
        succeededWorkers: succeeded.length,
        correlationId,
      });
      await step.run("replay-held-webhooks", async () => {
        const BATCH_SIZE = 200;
        const MAX_ITERATIONS = 500; // Safety cap: 500 * 200 = 100k webhooks max
        let iterations = 0;
        const processedIds: string[] = [];

        while (iterations < MAX_ITERATIONS) {
          iterations++;

          // Query un-delivered webhooks for this installation
          const conditions = [
            eq(gatewayWebhookDeliveries.installationId, installationId),
            eq(gatewayWebhookDeliveries.status, "held"),
          ];
          if (processedIds.length > 0) {
            conditions.push(
              notInArray(gatewayWebhookDeliveries.id, processedIds)
            );
          }

          const deliveries = await db
            .select()
            .from(gatewayWebhookDeliveries)
            .where(and(...conditions))
            .orderBy(gatewayWebhookDeliveries.receivedAt)
            .limit(BATCH_SIZE);

          if (deliveries.length === 0) {
            break;
          }

          // Send each delivery as a platform/webhook.received event
          const events = deliveries
            .filter((d) => d.payload)
            .map((d) => ({
              name: "platform/webhook.received" as const,
              data: {
                provider: d.provider,
                deliveryId: d.deliveryId,
                eventType: d.eventType,
                resourceId: null as string | null,
                payload: JSON.parse(d.payload!) as unknown,
                receivedAt: new Date(d.receivedAt).getTime(),
                preResolved: {
                  connectionId: installationId,
                  orgId: connection.orgId,
                },
                correlationId,
              },
            }));

          if (events.length > 0) {
            await inngest.send(events);
          }

          // Mark replayed deliveries so they aren't re-sent on retry (held -> enqueued)
          const replayedIds = deliveries.map((d) => d.id);
          if (replayedIds.length > 0) {
            await db
              .update(gatewayWebhookDeliveries)
              .set({ status: "enqueued" })
              .where(
                and(
                  eq(gatewayWebhookDeliveries.installationId, installationId),
                  inArray(gatewayWebhookDeliveries.id, replayedIds)
                )
              );
          }

          // Track processed IDs to exclude from next batch
          for (const d of deliveries) {
            processedIds.push(d.id);
          }
        }

        if (iterations >= MAX_ITERATIONS) {
          log.error("[backfill] replay-held-webhooks hit iteration cap", {
            installationId,
            iterations,
            correlationId,
          });
        }
      });
    }

    log.info("[backfill-orchestrator] complete", {
      installationId,
      provider,
      completed: succeeded.length,
      failed: failed.length,
      eventsProduced: completionResults.reduce(
        (sum, r) => sum + r.eventsProduced,
        0
      ),
      eventsDispatched: completionResults.reduce(
        (sum, r) => sum + r.eventsDispatched,
        0
      ),
      correlationId,
    });

    return {
      success: failed.length === 0,
      installationId,
      provider,
      workUnits: workUnits.length,
      skipped: workUnits.length - filteredWorkUnits.length,
      dispatched: filteredWorkUnits.length,
      completed: succeeded.length,
      failed: failed.length,
      eventsProduced: completionResults.reduce(
        (sum, r) => sum + r.eventsProduced,
        0
      ),
      eventsDispatched: completionResults.reduce(
        (sum, r) => sum + r.eventsDispatched,
        0
      ),
      results: completionResults,
    };
  }
);

/**
 * Platform backfill entity worker
 *
 * Ported from apps/backfill/src/workflows/entity-worker.ts
 *
 * KEY CHANGES vs backfill service:
 * - Function ID: platform/backfill.entity-worker (was backfill/entity.worker)
 * - Trigger: platform/backfill.entity.requested (was backfill/entity.requested)
 * - cancelOn: platform/backfill.run.cancelled (was backfill/run.cancelled)
 * - Replace gw.executeApi() with direct provider API calls using
 *   getActiveTokenForInstallation() + forceRefreshToken() + direct fetch()
 * - Replace relay.dispatchWebhook() with step.sendEvent("platform/webhook.received")
 * - 401 health check signal uses platform/health.check.requested
 */

import { db } from "@db/app/client";
import { gatewayInstallations, gatewayWebhookDeliveries } from "@db/app/schema";
import type { ProviderApi, ProviderDefinition } from "@repo/app-providers";
import { type BackfillContext, getProvider } from "@repo/app-providers";
import { eq } from "@vendor/db";
import { NonRetriableError } from "@vendor/inngest";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { GITHUB_RATE_LIMIT_BUDGET, MAX_PAGES } from "../../lib/constants";
import { providerConfigs } from "../../lib/provider-configs";
import {
  forceRefreshToken,
  getActiveTokenForInstallation,
} from "../../lib/token-helpers";
import { inngest } from "../client";

export const platformEntityWorker = inngest.createFunction(
  {
    id: "platform/backfill.entity-worker",
    name: "Platform Backfill Entity Worker",
    retries: 3,
    concurrency: [
      // Per-org: max 5 entity workers per organization
      // (one org with multiple connections shares this budget)
      { limit: 5, key: "event.data.orgId" },
      // Global: max 10 entity workers across all orgs
      { limit: 10 },
    ],
    throttle: {
      limit: GITHUB_RATE_LIMIT_BUDGET,
      period: "1h",
      key: "event.data.installationId",
    },
    // Workers must declare their own cancelOn — it does NOT propagate from parent
    cancelOn: [
      {
        event: "platform/backfill.run.cancelled",
        match: "data.installationId",
      },
    ],
    timeouts: { start: "5m", finish: "2h" },
  },
  { event: "platform/backfill.entity.requested" },
  async ({ event, step }) => {
    const {
      installationId,
      provider,
      orgId,
      entityType,
      resource,
      since,
      holdForReplay,
      correlationId,
    } = event.data;

    log.info("[entity-worker] starting", {
      installationId,
      provider,
      entityType,
      resource: resource.providerResourceId,
      since,
      correlationId,
    });

    // ── Resolve provider ──
    const providerDef = getProvider(provider);
    if (!providerDef) {
      throw new NonRetriableError(`Unknown provider: ${provider}`);
    }
    if (!providerDef.backfill) {
      throw new NonRetriableError(
        `Provider "${provider}" does not support backfill`
      );
    }

    const entityHandler = providerDef.backfill.entityTypes[entityType];
    if (!entityHandler) {
      throw new NonRetriableError(
        `Entity type "${entityType}" is not supported for ${provider} backfill`
      );
    }

    const ctx: BackfillContext = {
      installationId,
      resource: {
        providerResourceId: resource.providerResourceId,
        resourceName: resource.resourceName,
      },
      since,
    };

    // ── Pagination loop ──
    let cursor: unknown = null;
    let pageNum = 1;
    let eventsProduced = 0;
    let eventsDispatched = 0;

    while (true) {
      const fetchResult = await step.run(
        `fetch-${entityType}-p${pageNum}`,
        async () => {
          // Get installation for token resolution
          const installationRows = await db
            .select()
            .from(gatewayInstallations)
            .where(eq(gatewayInstallations.id, installationId))
            .limit(1);

          const installation = installationRows[0];
          if (!installation) {
            throw new NonRetriableError(
              `Installation not found: ${installationId}`
            );
          }
          if (installation.status !== "active") {
            throw new NonRetriableError(
              `Installation not active: ${installationId} (status: ${installation.status})`
            );
          }

          const config = providerConfigs[provider];

          // Get active token
          let token: string;
          try {
            ({ token } = await getActiveTokenForInstallation(
              installation,
              config,
              providerDef as ProviderDefinition
            ));
          } catch (err) {
            throw new NonRetriableError(
              `Failed to get token for installation ${installationId}: ${err instanceof Error ? err.message : String(err)}`
            );
          }

          // Build the API request from the entity handler
          const request = entityHandler.buildRequest(ctx, cursor);
          const api: ProviderApi = providerDef.api;
          const endpoint = api.endpoints[entityHandler.endpointId];
          if (!endpoint) {
            throw new NonRetriableError(
              `Unknown endpoint: ${entityHandler.endpointId}`
            );
          }

          // Build URL
          let path = endpoint.path;
          if (request.pathParams) {
            for (const [key, val] of Object.entries(request.pathParams)) {
              path = path.replace(`{${key}}`, encodeURIComponent(val));
            }
          }

          let url = `${api.baseUrl}${path}`;
          if (
            request.queryParams &&
            Object.keys(request.queryParams).length > 0
          ) {
            url += `?${new URLSearchParams(request.queryParams).toString()}`;
          }

          // Build headers
          const authHeader = api.buildAuthHeader
            ? api.buildAuthHeader(token)
            : `Bearer ${token}`;

          const headers: Record<string, string> = {
            Authorization: authHeader,
            ...(api.defaultHeaders ?? {}),
          };

          const fetchOptions: RequestInit = {
            method: endpoint.method,
            headers,
            signal: AbortSignal.timeout(endpoint.timeout ?? 30_000),
          };

          if (request.body) {
            fetchOptions.body = JSON.stringify(request.body);
            headers["Content-Type"] = "application/json";
          }

          // Execute request
          let response = await fetch(url, fetchOptions);

          // 401 retry with force-refresh
          if (response.status === 401) {
            const freshToken = await forceRefreshToken(
              installation,
              config,
              providerDef as ProviderDefinition
            );
            if (freshToken && freshToken !== token) {
              headers.Authorization = api.buildAuthHeader
                ? api.buildAuthHeader(freshToken)
                : `Bearer ${freshToken}`;
              response = await fetch(url, { ...fetchOptions, headers });
            }
          }

          if (response.status === 401) {
            // Token is definitively revoked — fire health-check signal
            return {
              __healthCheckSignal: true as const,
              status: 401,
              events: [] as ReturnType<
                typeof entityHandler.processResponse
              >["events"],
              nextCursor: null,
              rawCount: 0,
              rateLimit: null,
            };
          }

          if (response.status === 403) {
            throw new NonRetriableError(
              `Provider API returned 403 — insufficient scope for installation ${installationId}`
            );
          }

          if (response.status !== 200) {
            throw new Error(`Provider API returned ${response.status}`);
          }

          const data = await response.json();
          const responseHeaders: Record<string, string> = {};
          response.headers.forEach((value, key) => {
            responseHeaders[key] = value;
          });

          const processed = entityHandler.processResponse(
            data,
            ctx,
            cursor,
            responseHeaders
          );

          // Parse rate limits client-side from raw headers
          const rateLimit = providerDef.api.parseRateLimit(
            new Headers(responseHeaders)
          );

          return {
            __healthCheckSignal: false as const,
            status: 200,
            events: processed.events,
            nextCursor: processed.nextCursor,
            rawCount: processed.rawCount,
            rateLimit: rateLimit
              ? {
                  remaining: rateLimit.remaining,
                  resetAt: rateLimit.resetAt.toISOString(),
                  limit: rateLimit.limit,
                }
              : null,
          };
        }
      );

      // Handle 401 health check signal outside of the step
      if (fetchResult.__healthCheckSignal) {
        await step.sendEvent("signal-connection-health-check", {
          name: "platform/health.check.requested",
          data: {
            installationId,
            provider,
            reason: "401_unauthorized" as const,
            correlationId,
          },
        });
        throw new NonRetriableError(
          `Provider API returned 401 — token revoked for installation ${installationId}. Health check signal sent.`
        );
      }

      log.info("[entity-worker] page fetched", {
        installationId,
        entityType,
        resource: resource.providerResourceId,
        page: pageNum,
        events: fetchResult.events.length,
        ...(fetchResult.rateLimit && {
          rateLimitRemaining: fetchResult.rateLimit.remaining,
        }),
        correlationId,
      });

      eventsProduced += fetchResult.events.length;

      // Dispatch each event: hold for replay (DB insert) or send immediately (Inngest)
      const dispatched = await step.run(
        `dispatch-${entityType}-p${pageNum}`,
        async () => {
          const BATCH_SIZE = 5;
          const events = fetchResult.events;
          let count = 0;

          for (let i = 0; i < events.length; i += BATCH_SIZE) {
            const batch = events.slice(i, i + BATCH_SIZE);
            if (batch.length === 0) {
              continue;
            }

            if (holdForReplay) {
              // Persist to DB with status "held" — orchestrator replays after all workers finish
              await db
                .insert(gatewayWebhookDeliveries)
                .values(
                  batch.map((webhookEvent) => ({
                    provider,
                    deliveryId: webhookEvent.deliveryId,
                    eventType: webhookEvent.eventType,
                    installationId,
                    status: "held" as const,
                    payload: JSON.stringify(webhookEvent.payload),
                    receivedAt: new Date().toISOString(),
                  }))
                )
                .onConflictDoNothing();
            } else {
              // Send events to Inngest immediately
              await inngest.send(
                batch.map((webhookEvent) => ({
                  name: "platform/webhook.received" as const,
                  data: {
                    provider,
                    deliveryId: webhookEvent.deliveryId,
                    eventType: webhookEvent.eventType,
                    resourceId: null,
                    payload: webhookEvent.payload,
                    receivedAt: Date.now(),
                    preResolved: {
                      connectionId: installationId,
                      orgId,
                    },
                    correlationId,
                  },
                }))
              );
            }
            count += batch.length;
          }
          return count;
        }
      );

      log.info("[entity-worker] page dispatched", {
        installationId,
        entityType,
        resource: resource.providerResourceId,
        page: pageNum,
        dispatched,
        correlationId,
      });

      eventsDispatched += dispatched;

      // Rate limit sleep if near threshold (dynamic, based on response headers)
      if (fetchResult.rateLimit) {
        const { remaining, resetAt, limit } = fetchResult.rateLimit;
        if (remaining < limit * 0.1) {
          const sleepMs = Math.max(0, new Date(resetAt).getTime() - Date.now());
          if (sleepMs > 0) {
            log.info("[entity-worker] rate limit sleep", {
              installationId,
              entityType,
              resource: resource.providerResourceId,
              sleepMs,
              resetAt,
              correlationId,
            });
            await step.sleep(
              `rate-limit-${entityType}-p${pageNum}`,
              `${Math.ceil(sleepMs / 1000)}s`
            );
          }
        }
      }

      if (!fetchResult.nextCursor) {
        break;
      }
      if (pageNum >= MAX_PAGES) {
        log.warn(`[backfill] entity-worker hit MAX_PAGES cap (${MAX_PAGES})`, {
          installationId,
          entityType,
          resource: resource.providerResourceId,
          correlationId,
        });
        break;
      }
      cursor = fetchResult.nextCursor;
      pageNum++;
    }

    log.info("[entity-worker] complete", {
      installationId,
      provider,
      entityType,
      resource: resource.providerResourceId,
      eventsProduced,
      eventsDispatched,
      pagesProcessed: pageNum,
      correlationId,
    });

    return {
      entityType,
      resource: resource.providerResourceId,
      eventsProduced,
      eventsDispatched,
      pagesProcessed: pageNum,
    };
  }
);

