/**
 * Pinecone client wrapper built on the official SDK.
 *
 * Provides typed vector operations and index name helpers tailored to our store model.
 */

import type { RecordMetadata } from "@pinecone-database/pinecone";
import { Pinecone } from "@pinecone-database/pinecone";

import { env } from "./env";
import {
  PineconeConnectionError,
  PineconeError,
  PineconeInvalidRequestError,
  PineconeNotFoundError,
  PineconeRateLimitError,
} from "./errors";
import type {
  FetchResponse,
  QueryRequest,
  QueryResponse,
  UpdateRequest,
  UpsertRequest,
  UpsertResponse,
} from "./types";

export class PineconeClient {
  private readonly client: Pinecone;

  constructor() {
    this.client = new Pinecone({
      apiKey: env.PINECONE_API_KEY,
    });
  }

  /**
   * Create a new Pinecone index (serverless)
   *
   * All parameters are required - caller must provide explicit configuration.
   * Use application-level wrapper (@repo/app-pinecone) for defaults.
   *
   * @param indexName - Name of the index to create
   * @param dimension - Embedding dimension
   * @param options - Required configuration
   */
  async createIndex(
    indexName: string,
    dimension: number,
    options: {
      metric: "cosine" | "euclidean" | "dotproduct";
      cloud: "aws" | "gcp" | "azure";
      region: string;
    }
  ): Promise<void> {
    try {
      await this.client.createIndex({
        name: indexName,
        dimension,
        metric: options.metric,
        spec: {
          serverless: {
            cloud: options.cloud,
            region: options.region,
          },
        },
        suppressConflicts: true,
        waitUntilReady: true,
      });
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Check if an index exists
   *
   * @param indexName - Name of the index to check
   * @returns true if index exists, false otherwise
   */
  async indexExists(indexName: string): Promise<boolean> {
    try {
      const indexes = await this.client.listIndexes();
      const indexList = indexes.indexes ?? [];
      return indexList.some((index) => index.name === indexName);
    } catch (error) {
      // If list fails, assume index doesn't exist
      console.warn(`Failed to check index existence: ${String(error)}`);
      return false;
    }
  }

  /**
   * Delete a Pinecone index
   */
  async deleteIndex(indexName: string): Promise<void> {
    try {
      await this.client.deleteIndex(indexName);
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Upsert vectors into an index
   *
   * Generic method - works with any metadata type extending RecordMetadata
   *
   * @param indexName - Name of the index
   * @param request - Upsert request with vectors and metadata
   * @param batchSize - Number of vectors to upsert per batch
   * @param namespace - Optional namespace for data isolation
   */
  async upsertVectors<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    request: UpsertRequest<T>,
    batchSize = 100,
    namespace?: string
  ): Promise<UpsertResponse> {
    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      for (let i = 0; i < request.ids.length; i += batchSize) {
        const ids = request.ids.slice(i, i + batchSize);
        const vectors = request.vectors.slice(i, i + batchSize);
        const metadata = request.metadata.slice(i, i + batchSize);

        const records = vectors.map((values, offset) => {
          const id = ids[offset];
          const meta = metadata[offset];
          if (id === undefined || meta === undefined) {
            throw new PineconeInvalidRequestError(
              `Missing id or metadata at offset ${String(offset)}`
            );
          }
          return { id, values, metadata: meta };
        });

        await targetNamespace.upsert(records);
      }

      return { upsertedCount: request.ids.length };
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Delete vectors by IDs
   *
   * @param indexName - Name of the index
   * @param vectorIds - Array of vector IDs to delete
   * @param batchSize - Number of vectors to delete per batch
   * @param namespace - Optional namespace for data isolation
   */
  async deleteVectors(
    indexName: string,
    vectorIds: string[],
    batchSize = 100,
    namespace?: string
  ): Promise<void> {
    if (vectorIds.length === 0) {
      return;
    }

    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      for (let i = 0; i < vectorIds.length; i += batchSize) {
        const batch = vectorIds.slice(i, i + batchSize);
        await targetNamespace.deleteMany(batch);
      }
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Delete vectors matching a metadata filter
   *
   * @param indexName - Name of the index
   * @param filter - Metadata filter object
   * @param namespace - Optional namespace for data isolation
   */
  async deleteByMetadata(
    indexName: string,
    filter: object,
    namespace?: string
  ): Promise<void> {
    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      await targetNamespace.deleteMany(filter);
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Configure index level settings (deletion protection, tags, etc.)
   */
  async configureIndex(
    indexName: string,
    options: {
      deletionProtection?: "enabled" | "disabled";
      tags?: Record<string, string>;
      spec?: unknown;
    }
  ): Promise<void> {
    try {
      await this.client.configureIndex(indexName, {
        deletionProtection: options.deletionProtection,
        spec: options.spec as never,
        tags: options.tags,
      });
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Query similar vectors
   *
   * Generic method - works with any metadata type extending RecordMetadata
   *
   * @param indexName - Name of the index
   * @param request - Query request with vector and filters
   * @param namespace - Optional namespace for data isolation
   */
  async query<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    request: QueryRequest,
    namespace?: string
  ): Promise<QueryResponse<T>> {
    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      const results = await targetNamespace.query({
        vector: request.vector,
        topK: request.topK,
        filter: request.filter,
        includeMetadata: request.includeMetadata ?? true,
      });

      return {
        matches: results.matches.map((match) => ({
          id: match.id,
          score: match.score ?? 0,
          metadata: match.metadata as T,
        })),
      };
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Fetch vectors by IDs
   *
   * @param indexName - Name of the index
   * @param vectorIds - Array of vector IDs to fetch
   * @param namespace - Optional namespace for data isolation
   */
  async fetchVectors<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    vectorIds: string[],
    namespace?: string
  ): Promise<FetchResponse<T>> {
    if (vectorIds.length === 0) {
      return { records: {} };
    }

    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      const result = await targetNamespace.fetch(vectorIds);

      const records: FetchResponse<T>["records"] = {};
      for (const [id, record] of Object.entries(result.records)) {
        if (record.values) {
          records[id] = {
            id: record.id,
            values: record.values,
            metadata: record.metadata as T,
          };
        }
      }

      return { records };
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Update a vector's metadata
   *
   * @param indexName - Name of the index
   * @param request - Update request with vector ID and metadata
   * @param namespace - Optional namespace for data isolation
   */
  async updateVectorMetadata<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    request: UpdateRequest<T>,
    namespace?: string
  ): Promise<void> {
    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      await targetNamespace.update({
        id: request.id,
        metadata: request.metadata,
      });
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Handle and transform errors
   */
  private handleError(error: unknown): never {
    if (error instanceof PineconeError) {
      throw error;
    }

    const message = error instanceof Error ? error.message : String(error);
    const lowerMessage = message.toLowerCase();

    if (lowerMessage.includes("rate limit") || lowerMessage.includes("429")) {
      throw new PineconeRateLimitError("Rate limit exceeded", error);
    }

    if (lowerMessage.includes("not found") || lowerMessage.includes("404")) {
      throw new PineconeNotFoundError("Index or resource not found", error);
    }

    if (
      lowerMessage.includes("invalid") ||
      lowerMessage.includes("dimension") ||
      lowerMessage.includes("400")
    ) {
      throw new PineconeInvalidRequestError("Invalid request", error);
    }

    if (
      lowerMessage.includes("connection") ||
      lowerMessage.includes("network")
    ) {
      throw new PineconeConnectionError("Connection error", error);
    }

    throw new PineconeError("Pinecone operation failed", "UNKNOWN", error);
  }
}

export function createPineconeClient(): PineconeClient {
  return new PineconeClient();
}

export const pineconeClient = new PineconeClient();

"use client";

import type { SearchMode, SearchResponse } from "@repo/app-validation";
import type { PromptInputMessage } from "@repo/ui/components/ai-elements/prompt-input";
import { ScrollArea } from "@repo/ui/components/ui/scroll-area";
import { Separator } from "@repo/ui/components/ui/separator";
import { Skeleton } from "@repo/ui/components/ui/skeleton";
import { useOrganization } from "@vendor/clerk/client";
import { useEffect, useRef, useState } from "react";
import { dateRangeFromPreset } from "./search-constants";
import { SearchFilters } from "./search-filters";
import { SearchPromptInput } from "./search-prompt-input";
import { SearchResultsPanel } from "./search-results-panel";
import { useOrgSearchParams } from "./use-org-search-params";

async function executeSearch(
  body: Record<string, unknown>,
  clerkOrgId: string,
  signal: AbortSignal
): Promise<SearchResponse> {
  const response = await fetch("/v1/search", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "X-Org-ID": clerkOrgId,
    },
    body: JSON.stringify(body),
    signal,
  });

  if (!response.ok) {
    const errorData = (await response
      .json()
      .catch(() => ({ error: undefined, message: undefined }))) as {
      error?: string;
      message?: string;
    };
    throw new Error(
      errorData.message ??
        errorData.error ??
        `Search failed: ${response.status}`
    );
  }

  return (await response.json()) as SearchResponse;
}

interface OrgSearchProps {
  initialQuery: string;
}

/**
 * Org Search Component with Playground Layout
 *
 * Split-panel UI with left panel controls and right panel results.
 * All state persisted to URL via nuqs for shareable links.
 */
export function OrgSearch({ initialQuery }: OrgSearchProps) {
  const { organization } = useOrganization();

  // URL-persisted state via nuqs
  const {
    query,
    setQuery,
    mode,
    setMode,
    sources,
    setSources,
    types,
    setTypes,
    expandedId,
    setExpandedId,
    limit,
    setLimit,
    offset,
    setOffset,
    agePreset,
    setAgePreset,
    activeTab,
    setActiveTab,
    clearFilters,
  } = useOrgSearchParams(initialQuery);

  // Local state for search results and input
  const [searchResults, setSearchResults] = useState<SearchResponse | null>(
    null
  );
  const [isSearching, setIsSearching] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [inputValue, setInputValue] = useState(query);
  const [prevQuery, setPrevQuery] = useState(query);
  useEffect(() => {
    if (prevQuery !== query) {
      setPrevQuery(query);
      setInputValue(query);
    }
  }, [query, prevQuery]);

  const clerkOrgId = organization?.id ?? "";

  // Reference to track current request for cancellation
  const abortControllerRef = useRef<AbortController | null>(null);

  // Abort any in-flight request when the component unmounts
  useEffect(() => {
    return () => {
      abortControllerRef.current?.abort();
    };
  }, []);

  const performSearch = (searchQuery: string) => {
    if (!searchQuery.trim()) {
      setError("Please enter a search query");
      return;
    }

    abortControllerRef.current?.abort();
    abortControllerRef.current = new AbortController();

    setIsSearching(true);
    setError(null);
    // Keep previous results visible during loading to avoid flash of empty state

    const body: Record<string, unknown> = {
      query: searchQuery.trim(),
      limit,
      offset,
      mode,
      ...(sources.length > 0 && { sources }),
      ...(types.length > 0 && { types }),
      ...dateRangeFromPreset(agePreset),
    };

    executeSearch(body, clerkOrgId, abortControllerRef.current.signal)
      .then((data) => {
        setSearchResults(data);
        setIsSearching(false);
      })
      .catch((err: unknown) => {
        if (err instanceof Error && err.name === "AbortError") {
          return;
        }
        setError(err instanceof Error ? err.message : "Search failed");
        setSearchResults(null);
        setIsSearching(false);
      });
  };

  const handleSearch = () => {
    performSearch(inputValue);
  };

  const handlePromptSubmit = async (
    message: PromptInputMessage
  ): Promise<void> => {
    const content = message.text?.trim() ?? "";
    await setQuery(content);
    performSearch(content);
  };

  // Handle Cmd+Enter keyboard shortcut
  const handleKeyDown = (e: React.KeyboardEvent) => {
    if ((e.metaKey || e.ctrlKey) && e.key === "Enter" && !isSearching) {
      e.preventDefault();
      void handleSearch();
    }
  };

  return (
    // biome-ignore lint/a11y/noNoninteractiveElementInteractions: search container handles keyboard navigation
    <search
      className="flex h-full flex-col overflow-hidden"
      onKeyDown={handleKeyDown}
    >
      {/* Split Layout */}
      <div className="flex flex-1 overflow-hidden">
        {/* LEFT PANEL — Controls */}
        <div className="flex flex-1 flex-col overflow-hidden border-border">
          <ScrollArea className="h-full">
            <div className="space-y-5 p-4">
              <h1 className="font-semibold text-2xl">
                Explore your infrastructure
              </h1>
              {/* Query Input */}
              <SearchPromptInput
                clearDisabledReason="No filters applied"
                isClearDisabled={
                  sources.length === 0 &&
                  types.length === 0 &&
                  agePreset === "none"
                }
                isSubmitDisabled={isSearching || !inputValue.trim()}
                mode={mode}
                onChange={setInputValue}
                onClear={clearFilters}
                onModeChange={(v) => setMode(v as SearchMode)}
                onSubmit={handlePromptSubmit}
                placeholder="Ask a question or describe what you're looking for..."
                status={isSearching ? "submitted" : "ready"}
                value={inputValue}
              />

              <div className="mt-12">
                <SearchFilters
                  agePreset={agePreset}
                  limit={limit}
                  observationTypes={types}
                  offset={offset}
                  onAgePresetChange={(v) =>
                    void setAgePreset(v as typeof agePreset)
                  }
                  onLimitChange={setLimit}
                  onObservationTypesChange={setTypes}
                  onOffsetChange={setOffset}
                  onSourceTypesChange={setSources}
                  sourceTypes={sources}
                />
              </div>

              {/* Error Display */}
              {error && (
                <>
                  <Separator />
                  <p className="text-destructive text-sm">{error}</p>
                </>
              )}
            </div>
          </ScrollArea>
        </div>

        {/* RIGHT PANEL — Results */}
        <div className="flex min-h-0 flex-1 flex-col overflow-hidden">
          <SearchResultsPanel
            activeTab={activeTab}
            expandedId={expandedId}
            offset={offset}
            onActiveTabChange={(v) => void setActiveTab(v as typeof activeTab)}
            onExpandedIdChange={setExpandedId}
            searchResults={searchResults}
          />
        </div>
      </div>
    </search>
  );
}

// Loading skeleton
export function OrgSearchSkeleton() {
  return (
    <div className="flex h-[calc(100vh-4rem)] flex-col gap-4">
      {/* Header skeleton */}
      <div className="flex items-center gap-2">
        <Skeleton className="h-7 w-20" />
        <Skeleton className="h-5 w-24" />
      </div>
      {/* Panel skeleton */}
      <div className="flex flex-1 rounded-lg border">
        <div className="w-[35%] space-y-4 border-r p-4">
          <Skeleton className="h-20 w-full" />
          <Skeleton className="h-8 w-full" />
          <Skeleton className="h-8 w-full" />
          <Skeleton className="h-8 w-full" />
        </div>
        <div className="flex-1 space-y-4 p-4">
          <Skeleton className="h-10 w-32" />
          <Skeleton className="h-40 w-full" />
        </div>
      </div>
    </div>
  );
}

