import { randomUUID } from "node:crypto";
import { OpenAPIHandler } from "@orpc/openapi/fetch";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { router } from "../../lib/orpc-router";

const handler = new OpenAPIHandler(router);

async function handleRequest(request: Request) {
  const requestId = randomUUID();

  try {
    const { matched, response } = await handler.handle(request, {
      context: {
        headers: request.headers,
        requestId,
      },
    });

    if (matched) {
      const enriched = new Response(response.body, response);
      enriched.headers.set("X-Request-ID", requestId);
      return enriched;
    }

    return Response.json(
      {
        defined: false,
        code: "NOT_FOUND",
        status: 404,
        message: "Endpoint not found",
      },
      { status: 404, headers: { "X-Request-ID": requestId } }
    );
  } catch (error) {
    log.error("oRPC handler error", {
      error: error instanceof Error ? error.message : String(error),
      requestId,
    });
    return Response.json(
      {
        defined: false,
        code: "INTERNAL_SERVER_ERROR",
        status: 500,
        message: "Internal server error",
      },
      { status: 500, headers: { "X-Request-ID": requestId } }
    );
  }
}

export const GET = handleRequest;
export const POST = handleRequest;
export const PUT = handleRequest;
export const DELETE = handleRequest;
export const PATCH = handleRequest;

/**
 * API Key Authentication Middleware for v1 Routes
 *
 * SECURITY: Validates org-scoped API keys.
 * Keys authenticate the org and can access all resources within it.
 */

import { db } from "@db/app/client";
import { orgApiKeys } from "@db/app/schema";
import { hashApiKey, isValidApiKeyFormat } from "@repo/app-api-key";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { and, eq, sql } from "drizzle-orm";
import type { NextRequest } from "next/server";

export interface ApiKeyAuthContext {
  apiKeyId: string; // publicId
  clerkOrgId: string; // same as orgId, kept for backward compat
  orgId: string; // clerkOrgId — sole scoping mechanism
  userId: string; // createdByUserId for audit
}

export interface AuthSuccess {
  auth: ApiKeyAuthContext;
  success: true;
}

export interface AuthError {
  error: {
    code: string;
    message: string;
  };
  status: number;
  success: false;
}

export type AuthResult = AuthSuccess | AuthError;

/**
 * Verify org-scoped API key
 *
 * Required headers:
 * - Authorization: Bearer <api-key>
 *
 * The org is determined by the key binding.
 * This prevents unauthorized access to other orgs.
 *
 * @returns AuthResult with org context from the key binding
 */
export async function withApiKeyAuth(
  request: NextRequest,
  requestId?: string
): Promise<AuthResult> {
  // 1. Extract Authorization header
  const authHeader = request.headers.get("authorization");
  if (!authHeader?.startsWith("Bearer ")) {
    log.warn("Missing or invalid Authorization header", { requestId });
    return {
      success: false,
      error: {
        code: "UNAUTHORIZED",
        message:
          "API key required. Provide 'Authorization: Bearer <api-key>' header.",
      },
      status: 401,
    };
  }

  const apiKey = authHeader.slice(7); // Remove "Bearer " prefix

  // 2. Validate key format (prefix and length)
  if (!isValidApiKeyFormat(apiKey)) {
    log.warn("Invalid API key format", { requestId });
    return {
      success: false,
      error: {
        code: "UNAUTHORIZED",
        message: "Invalid API key format.",
      },
      status: 401,
    };
  }

  // 3. Hash and verify API key
  try {
    const keyHash = hashApiKey(apiKey);

    const [foundKey] = await db
      .select({
        id: orgApiKeys.id,
        publicId: orgApiKeys.publicId,
        clerkOrgId: orgApiKeys.clerkOrgId,
        createdByUserId: orgApiKeys.createdByUserId,
        isActive: orgApiKeys.isActive,
        expiresAt: orgApiKeys.expiresAt,
      })
      .from(orgApiKeys)
      .where(
        and(eq(orgApiKeys.keyHash, keyHash), eq(orgApiKeys.isActive, true))
      )
      .limit(1);

    if (!foundKey) {
      log.warn("Invalid API key", { requestId });
      return {
        success: false,
        error: {
          code: "UNAUTHORIZED",
          message: "Invalid API key",
        },
        status: 401,
      };
    }

    // 4. Check expiration
    if (foundKey.expiresAt && new Date(foundKey.expiresAt) < new Date()) {
      log.warn("Expired API key", { requestId, apiKeyId: foundKey.publicId });
      return {
        success: false,
        error: {
          code: "UNAUTHORIZED",
          message: "API key expired",
        },
        status: 401,
      };
    }

    // 5. Get client IP for tracking
    const clientIp =
      request.headers.get("x-forwarded-for")?.split(",")[0]?.trim() ??
      request.headers.get("x-real-ip") ??
      "unknown";

    // 6. Update last used timestamp and IP (non-blocking)
    void db
      .update(orgApiKeys)
      .set({
        lastUsedAt: sql`CURRENT_TIMESTAMP`,
        lastUsedFromIp: clientIp.substring(0, 45),
      })
      .where(eq(orgApiKeys.id, foundKey.id))
      .catch((err: unknown) => {
        log.error("Failed to update API key lastUsedAt", {
          error: err instanceof Error ? err.message : String(err),
          apiKeyId: foundKey.publicId,
        });
      });

    log.info("API key verified", {
      requestId,
      apiKeyId: foundKey.publicId,
      orgId: foundKey.clerkOrgId,
    });

    return {
      success: true,
      auth: {
        orgId: foundKey.clerkOrgId,
        userId: foundKey.createdByUserId,
        apiKeyId: foundKey.publicId,
        clerkOrgId: foundKey.clerkOrgId, // same value as orgId, kept for backward compat
      },
    };
  } catch (error) {
    log.error("API key verification failed", { requestId, error });
    return {
      success: false,
      error: {
        code: "INTERNAL_ERROR",
        message: "Authentication failed",
      },
      status: 500,
    };
  }
}

/**
 * Helper to create error response from AuthError
 */
export function createAuthErrorResponse(
  result: AuthError,
  requestId: string
): Response {
  return Response.json(
    {
      error: result.error.code,
      message: result.error.message,
      requestId,
    },
    { status: result.status }
  );
}

"use server";

import { captureException } from "@sentry/nextjs";
import { isClerkAPIResponseError } from "@vendor/clerk";
import { clerkClient } from "@vendor/clerk/server";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import {
  ARCJET_KEY,
  arcjet,
  detectBot,
  fixedWindow,
  request,
  shield,
  slidingWindow,
  validateEmail,
} from "@vendor/security";
import { redis } from "@vendor/upstash";
import { isRedirectError } from "next/dist/client/components/redirect-error";
import { redirect } from "next/navigation";
import { after } from "next/server";
import { z } from "zod";
import { env } from "~/env";
import { getAuthTraceContext } from "~/lib/observability";
import { serializeEarlyAccessParams } from "../_lib/search-params";

const earlyAccessSchema = z.object({
  email: z
    .string()
    .min(1, "Email is required")
    .email("Please enter a valid email address")
    .toLowerCase()
    .trim(),
  companySize: z.string().min(1, "Company size is required"),
  sources: z.array(z.string()).min(1, "Please select at least one data source"),
});

const EARLY_ACCESS_EMAILS_SET_KEY = "early-access:emails";

// Configure Arcjet protection for early access signup
const aj = arcjet({
  key: ARCJET_KEY,
  characteristics: ["ip.src"],
  rules: [
    validateEmail({
      mode: "LIVE",
      deny: ["DISPOSABLE", "INVALID", "NO_MX_RECORDS"],
    }),
    shield({
      mode: env.NODE_ENV === "production" ? "LIVE" : "DRY_RUN",
    }),
    detectBot({
      mode: "LIVE",
      allow: ["CATEGORY:SEARCH_ENGINE", "CATEGORY:MONITOR"],
    }),
    slidingWindow({
      mode: "LIVE",
      interval: "1h",
      max: 10,
    }),
    slidingWindow({
      mode: "LIVE",
      interval: "24h",
      max: 50,
    }),
    fixedWindow({
      mode: "LIVE",
      window: "10s",
      max: 3,
    }),
  ],
});

export async function joinEarlyAccessAction(
  formData: FormData
): Promise<never> {
  // Hoisted before try so catch block can preserve form state on error redirects
  const rawEmail = (formData.get("email") as string | null) ?? "";
  const rawCompanySize = (formData.get("companySize") as string | null) ?? "";
  const rawSources = (formData.get("sources") as string | null) ?? "";

  try {
    // Validate form data
    const validatedFields = earlyAccessSchema.safeParse({
      email: rawEmail,
      companySize: rawCompanySize,
      sources: rawSources.split(",").filter(Boolean),
    });

    // Redirect with field errors if validation fails
    if (!validatedFields.success) {
      const fieldErrors = validatedFields.error.flatten().fieldErrors;
      log.warn("Early access form validation failed", {
        errors: fieldErrors,
        ...getAuthTraceContext(),
      });
      redirect(
        serializeEarlyAccessParams("/early-access", {
          email: rawEmail,
          companySize: rawCompanySize,
          sources: rawSources,
          emailError: fieldErrors.email?.[0] ?? null,
          companySizeError: fieldErrors.companySize?.[0] ?? null,
          sourcesError: fieldErrors.sources?.[0] ?? null,
        })
      );
    }

    // Fields have been validated
    const { email, companySize, sources } = validatedFields.data;
    const sourcesStr = sources.join(",");

    // Check Arcjet protection with the validated email
    const req = await request();
    const decision = await aj.protect(req, { email });

    // Handle denied requests from Arcjet
    if (decision.isDenied()) {
      const reason = decision.reason;
      log.warn("Early access blocked by Arcjet", {
        reason: reason.type,
        ...getAuthTraceContext(),
      });

      if (reason.isRateLimit()) {
        redirect(
          serializeEarlyAccessParams("/early-access", {
            error: "Too many signup attempts. Please try again later.",
            isRateLimit: true,
            email,
            companySize,
            sources: sourcesStr,
          })
        );
      }

      let errorMessage =
        "Your request could not be processed. Please try again.";
      if (reason.isBot()) {
        errorMessage =
          "Automated signup detected. Please complete the form manually.";
      } else if (reason.isShield()) {
        errorMessage =
          "Request blocked for security reasons. Please try again.";
      } else if (
        "isEmail" in reason &&
        typeof reason.isEmail === "function" &&
        reason.isEmail()
      ) {
        errorMessage =
          "Please use a valid email address. Temporary or disposable email addresses are not allowed.";
      }

      redirect(
        serializeEarlyAccessParams("/early-access", {
          error: errorMessage,
          email,
          companySize,
          sources: sourcesStr,
        })
      );
    }

    // Check if email already exists in Redis for fast duplicate detection
    try {
      const emailExists = await redis.sismember(
        EARLY_ACCESS_EMAILS_SET_KEY,
        email
      );
      if (emailExists) {
        // Already registered — show success state (they're already on the list)
        log.info("Early access duplicate email", {
          ...getAuthTraceContext(),
        });
        redirect(
          serializeEarlyAccessParams("/early-access", {
            success: true,
            email,
          })
        );
      }
    } catch (redisError) {
      if (isRedirectError(redisError)) {
        throw redisError;
      }
      log.error("Redis early-access check failed", {
        error: String(redisError),
        ...getAuthTraceContext(),
      });
      captureException(redisError, {
        tags: { action: "joinEarlyAccess:redis-check", email },
      });
    }

    // Add to Clerk waitlist via SDK
    const clerk = await clerkClient();
    await clerk.waitlistEntries.create({ emailAddress: email });
    log.info("Early access waitlist entry created", {
      ...getAuthTraceContext(),
    });

    // Track in Redis after response is sent (non-blocking)
    after(async () => {
      try {
        await redis.sadd(EARLY_ACCESS_EMAILS_SET_KEY, email);
      } catch (redisError) {
        log.error("Redis early-access tracking failed", {
          error: String(redisError),
          ...getAuthTraceContext(),
        });
        captureException(redisError, {
          tags: { action: "joinEarlyAccess:redis-add", email },
        });
      }
    });

    // Success — redirect with success state
    redirect(
      serializeEarlyAccessParams("/early-access", {
        success: true,
        email,
      })
    );
  } catch (error) {
    // redirect() throws NEXT_REDIRECT — must re-throw
    if (isRedirectError(error)) {
      throw error;
    }

    // Handle Clerk SDK errors with typed error checking
    if (isClerkAPIResponseError(error)) {
      const code = error.errors[0]?.code;

      if (
        code === "email_address_exists" ||
        code === "form_identifier_exists"
      ) {
        // Already registered — show success state (they're already on the list)
        redirect(
          serializeEarlyAccessParams("/early-access", {
            success: true,
            email: rawEmail,
          })
        );
      }

      if (
        error.status === 429 ||
        code === "too_many_requests" ||
        code === "rate_limit_exceeded"
      ) {
        redirect(
          serializeEarlyAccessParams("/early-access", {
            error: "Too many signup attempts. Please try again later.",
            isRateLimit: true,
            email: rawEmail,
            companySize: rawCompanySize,
            sources: rawSources,
          })
        );
      }

      if (code === "user_locked") {
        const seconds = (error.errors[0]?.meta as Record<string, unknown>)
          ?.lockout_expires_in_seconds as number | undefined;
        redirect(
          serializeEarlyAccessParams("/early-access", {
            error: seconds
              ? `Your account is temporarily locked. Please try again in ${Math.ceil(seconds / 60)} minutes.`
              : "Your account is temporarily locked. Please try again later.",
            email: rawEmail,
            companySize: rawCompanySize,
            sources: rawSources,
          })
        );
      }

      // All other Clerk errors: log + generic message
      captureException(error, {
        tags: { action: "joinEarlyAccess:clerk" },
      });
      log.error("Clerk waitlist error", {
        code: error.errors[0]?.code,
        message: error.errors[0]?.longMessage,
        ...getAuthTraceContext(),
      });
      redirect(
        serializeEarlyAccessParams("/early-access", {
          error:
            error.errors[0]?.longMessage ??
            "An unexpected error occurred. Please try again.",
          email: rawEmail,
          companySize: rawCompanySize,
          sources: rawSources,
        })
      );
    }

    // Non-Clerk errors
    captureException(error);
    log.error("Early access signup error", {
      error: error instanceof Error ? error.message : String(error),
      ...getAuthTraceContext(),
    });
    redirect(
      serializeEarlyAccessParams("/early-access", {
        error: "An error occurred. Please try again.",
        email: rawEmail,
        companySize: rawCompanySize,
        sources: rawSources,
      })
    );
  }
}

