      input,
      context.requestId
    );

    return result;
  }),

  proxy: {
    search: impl.proxy.search.handler(async ({ context }) => {
      log.info("Proxy search request (oRPC)", {
        requestId: context.requestId,
      });

      return proxySearchLogic(
        {
          clerkOrgId: context.clerkOrgId,
          userId: context.userId,
          authType: context.authType,
          apiKeyId: context.apiKeyId,
        },
        context.requestId
      );
    }),

    call: impl.proxy.call.handler(async ({ input, context }) => {
      log.info("Proxy call request (oRPC)", {
        requestId: context.requestId,
        action: input.action,
      });

      try {
        return await proxyCallLogic(
          {
            clerkOrgId: context.clerkOrgId,
            userId: context.userId,
            authType: context.authType,
            apiKeyId: context.apiKeyId,
          },
          input,
          context.requestId
        );
      } catch (error) {
        const message =
          error instanceof Error ? error.message : "Proxy call failed";

        if (
          message.includes("not found") ||
          message.includes("access denied")
        ) {
          throw new ORPCError("NOT_FOUND", { message });
        }
        if (
          message.includes("not active") ||
          message.includes("not connected") ||
          message.includes("Invalid action") ||
          message.includes("Unknown") ||
          message.includes("mismatch")
        ) {
          throw new ORPCError("BAD_REQUEST", { message });
        }
        throw error;
      }
    }),
  },
});

import { db } from "@db/app/client";
import { gatewayInstallations, orgIntegrations } from "@db/app/schema";
import { getProvider, type SourceType } from "@repo/app-providers";
import type {
  ProxyCall,
  ProxyCallResponse,
  ProxySearchResponse,
} from "@repo/app-validation/api";
import { createPlatformCaller } from "@repo/platform-trpc/caller";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { and, eq } from "drizzle-orm";
import type { AuthContext } from "./types";

const CONN_PREFIX = "conn_";

function extractPathParams(path: string): string[] {
  const matches = path.match(/\{(\w+)\}/g);
  return matches ? matches.map((m) => m.slice(1, -1)) : [];
}

export async function proxySearchLogic(
  auth: AuthContext,
  requestId: string
): Promise<ProxySearchResponse> {
  const installations = await db
    .select()
    .from(gatewayInstallations)
    .where(
      and(
        eq(gatewayInstallations.orgId, auth.clerkOrgId),
        eq(gatewayInstallations.status, "active")
      )
    );

  // Create caller once — it's stateless w.r.t. installations.
  // installationId is passed as procedure input at call time.
  const platform = await createPlatformCaller();

  const connections = await Promise.all(
    installations.map(async (inst) => {
      // Cast to string to use the wide getProvider overload — avoids
      // union-of-function parameter intersection issues with TAccountInfo.
      const providerDef = getProvider(inst.provider as string);
      if (!providerDef) {
        return null;
      }

      // Query connected resources for this installation
      const integrations = await db
        .select()
        .from(orgIntegrations)
        .where(
          and(
            eq(orgIntegrations.installationId, inst.id),
            eq(orgIntegrations.status, "active")
          )
        );

      // Build executeApi callback for this installation
      const executeApi = async (req: {
        endpointId: string;
        pathParams?: Record<string, string>;
        queryParams?: Record<string, string>;
        body?: unknown;
      }) =>
        platform.proxy.execute({
          installationId: inst.id,
          endpointId: req.endpointId,
          pathParams: req.pathParams,
          queryParams: req.queryParams,
          body: req.body,
        });

      // Resolve all resources (1 batch API call per provider)
      // On failure, fall back to using providerResourceId as the display name
      // so connected resources still appear (with opaque IDs instead of names).
      let resolvedResources: Awaited<
        ReturnType<typeof providerDef.resourcePicker.resolveProxyResources>
      > = [];
      try {
        resolvedResources =
          await providerDef.resourcePicker.resolveProxyResources(executeApi, {
            id: inst.id,
            externalId: inst.externalId,
            providerAccountInfo: inst.providerAccountInfo!,
          });
      } catch (err) {
        log.warn("Failed to resolve proxy resources, falling back to IDs", {
          requestId,
          provider: inst.provider,
          error: err instanceof Error ? err.message : String(err),
        });
        // Degraded mode: use orgIntegrations data directly so resources
        // still appear with providerResourceId as name and empty params.
        resolvedResources = integrations.map((i) => ({
          providerResourceId: i.providerResourceId,
          name: i.providerResourceId,
          params: {},
        }));
      }

      // Build a lookup set of connected providerResourceIds
      const connectedSet = new Map(
        integrations.map((i) => [i.providerResourceId, i])
      );

      // Filter to connected resources and merge sync events
      const resources = resolvedResources
        .filter((r) => connectedSet.has(r.providerResourceId))
        .map((r) => {
          const integration = connectedSet.get(r.providerResourceId);
          const config = integration?.providerConfig as {
            sync?: { events?: string[] };
          } | null;
          return {
            name: r.name,
            params: r.params,
            ...(config?.sync?.events?.length
              ? { syncing: config.sync.events }
              : {}),
          };
        });

      // Build action catalog from endpoint definitions
      const actions = Object.entries(providerDef.api.endpoints).map(
        ([key, ep]) => {
          const params = extractPathParams(ep.path);
          return {
            action: `${inst.provider}.${key}`,
            ...(params.length > 0 ? { params } : {}),
            description: ep.description,
          };
        }
      );

      return {
        id: `${CONN_PREFIX}${inst.id}`,
        provider: inst.provider,
        resources,
        actions,
      };
    })
  );

  const filtered = connections.filter(
    (c): c is NonNullable<typeof c> => c !== null
  );

  log.info("Proxy search complete", {
    requestId,
    connectionCount: filtered.length,
  });

  return { connections: filtered };
}

export async function proxyCallLogic(
  auth: AuthContext,
  request: ProxyCall,
  requestId: string
): Promise<ProxyCallResponse> {
  // Parse action → provider + endpointId
  const dotIndex = request.action.indexOf(".");
  if (dotIndex === -1) {
    throw new Error(
      `Invalid action format: "${request.action}". Expected "provider.endpointId"`
    );
  }
  const providerName = request.action.slice(0, dotIndex);
  const endpointId = request.action.slice(dotIndex + 1);

  // Resolve installation
  let installationId: string;

  if (request.connection) {
    // Validate provided connection
    installationId = request.connection.startsWith(CONN_PREFIX)
      ? request.connection.slice(CONN_PREFIX.length)
      : request.connection;

    const installation = await db.query.gatewayInstallations.findFirst({
      where: and(
        eq(gatewayInstallations.id, installationId),
        eq(gatewayInstallations.orgId, auth.clerkOrgId)
      ),
    });

    if (!installation) {
      throw new Error("Connection not found or access denied");
    }
    if (installation.status !== "active") {
      throw new Error(`Connection not active (status: ${installation.status})`);
    }
    if (installation.provider !== providerName) {
      throw new Error(
        `Connection provider mismatch: expected ${providerName}, got ${installation.provider}`
      );
    }
  } else {
    // Auto-resolve: find single active installation for this provider
    const installations = await db
      .select()
      .from(gatewayInstallations)
      .where(
        and(
          eq(gatewayInstallations.orgId, auth.clerkOrgId),
          eq(gatewayInstallations.provider, providerName as SourceType),
          eq(gatewayInstallations.status, "active")
        )
      );

    if (installations.length === 0) {
      throw new Error(`Provider "${providerName}" is not connected`);
    }
    installationId = installations[0]!.id;
  }

  // Validate endpoint exists
  const providerDef = getProvider(providerName);
  if (!providerDef) {
    throw new Error(`Unknown provider: ${providerName}`);
  }
  const endpoint = providerDef.api.endpoints[endpointId];
  if (!endpoint) {
    throw new Error(
      `Unknown action: ${request.action}. Available: ${Object.keys(
        providerDef.api.endpoints
      )
        .map((k) => `${providerName}.${k}`)
        .join(", ")}`
    );
  }

  // Route flat params → pathParams / queryParams / body
  const pathParamNames = new Set(extractPathParams(endpoint.path));
  const flatParams = (request.params ?? {}) as Record<string, unknown>;

  const pathParams: Record<string, string> = {};
  const remaining: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(flatParams)) {
    if (pathParamNames.has(key)) {
      pathParams[key] = String(value);
    } else {
      remaining[key] = value;
    }
  }

  let queryParams: Record<string, string> | undefined;
  let body: unknown | undefined;

  const hasRemaining = Object.keys(remaining).length > 0;

  if (endpoint.method === "GET" && hasRemaining) {
    // GET: remaining → query params
    queryParams = {};
    for (const [key, value] of Object.entries(remaining)) {
      queryParams[key] = String(value);
    }
  } else if (hasRemaining) {
    // POST: remaining → body
    body = remaining;
  }

  // Execute via platform proxy
  const platform = await createPlatformCaller();
  const result = await platform.proxy.execute({
    installationId,
    endpointId,
    pathParams: Object.keys(pathParams).length > 0 ? pathParams : undefined,
    queryParams,
    body,
  });

  log.info("Proxy call complete", {
    requestId,
    action: request.action,
    installationId,
    status: result.status,
  });

  return {
    status: result.status,
    data: result.data,
    headers: result.headers,
  };
}

import { clerkClient } from "@vendor/clerk/server";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { redis } from "@vendor/upstash";
import { getUserOrgsCacheKey } from "./keys";
import type { CachedUserOrgMembership, GetMembershipsResult } from "./types";

/** Cache TTL in seconds (5 minutes) */
const CACHE_TTL_SECONDS = 300;

/**
 * Get user's organization memberships with Redis caching.
 *
 * Strategy: User-centric lookup - fetches user's orgs (typically 1-5)
 * instead of org's members (could be 100+). This is O(user_orgs) vs O(org_size).
 *
 * Flow:
 * 1. Try Redis cache lookup
 * 2. On hit: return cached data
 * 3. On miss: fetch from Clerk API, cache result, return
 * 4. On error: log warning, fall back to direct Clerk API
 *
 * @param userId - Clerk user ID
 * @returns Array of user's organization memberships (empty if none)
 */
export async function getCachedUserOrgMemberships(
  userId: string
): Promise<GetMembershipsResult> {
  const cacheKey = getUserOrgsCacheKey(userId);

  // 1. Try cache lookup
  try {
    const cached = await redis.get<CachedUserOrgMembership[]>(cacheKey);

    if (cached !== null) {
      log.debug("Clerk membership cache hit", { userId, count: cached.length });
      return cached;
    }

    log.debug("Clerk membership cache miss", { userId });
  } catch (cacheError) {
    // Cache read failed - log and continue to Clerk API
    log.warn("Clerk membership cache read failed", {
      userId,
      error:
        cacheError instanceof Error ? cacheError.message : String(cacheError),
    });
  }

  // 2. Fetch from Clerk API
  const memberships = await fetchUserOrgMembershipsFromClerk(userId);

  // 3. Cache the result (fire-and-forget, don't block response)
  cacheUserOrgMemberships(userId, memberships).catch((cacheError) => {
    log.warn("Clerk membership cache write failed", {
      userId,
      error:
        cacheError instanceof Error ? cacheError.message : String(cacheError),
    });
  });

  return memberships;
}

/**
 * Fetch user's organization memberships directly from Clerk API.
 * Used on cache miss or as fallback on cache failure.
 */
async function fetchUserOrgMembershipsFromClerk(
  userId: string
): Promise<CachedUserOrgMembership[]> {
  const clerk = await clerkClient();

  const response = await clerk.users.getOrganizationMembershipList({
    userId,
  });

  return response.data.map((membership) => ({
    organizationId: membership.organization.id,
    organizationSlug: membership.organization.slug,
    organizationName: membership.organization.name,
    role: membership.role,
    imageUrl: membership.organization.imageUrl,
  }));
}

/**
 * Cache user's organization memberships in Redis.
 */
async function cacheUserOrgMemberships(
  userId: string,
  memberships: CachedUserOrgMembership[]
): Promise<void> {
  const cacheKey = getUserOrgsCacheKey(userId);
  await redis.set(cacheKey, memberships, { ex: CACHE_TTL_SECONDS });
  log.debug("Clerk membership cached", { userId, count: memberships.length });
}

/**
 * Invalidate cached memberships for a user.
 * Call this when membership changes are detected (e.g., via webhooks).
 *
 * TODO: Integrate with Clerk webhook handler when implemented
 */
export async function invalidateUserOrgMemberships(
  userId: string
): Promise<void> {
  const cacheKey = getUserOrgsCacheKey(userId);
  await redis.del(cacheKey);
  log.info("Clerk membership cache invalidated", { userId });
}

/**
 * Config file parsing utilities
 *
 * @see docs/architecture/phase1/dx-configuration.md
 */

import { readFile } from "node:fs/promises";
import { join } from "node:path";
import { parseError } from "@vendor/observability/error/next";
import type { Result } from "neverthrow";
import { err, ok } from "neverthrow";
import { parse as parseYAML } from "yaml";
import type { ZodError } from "zod";
import type { LightfastConfig } from "./schema";
import { LightfastConfigSchema } from "./schema";

/**
 * Error types for configuration loading and parsing
 */
export class ConfigError extends Error {
  constructor(
    message: string,
    public readonly code:
      | "FILE_NOT_FOUND"
      | "INVALID_YAML"
      | "VALIDATION_ERROR"
      | "READ_ERROR",
    public readonly cause?: unknown
  ) {
    super(message);
    this.name = "ConfigError";
  }
}

/**
 * Load and parse lightfast.yml configuration from a repository path
 *
 * @param repoPath - Absolute path to the repository root
 * @returns Result containing parsed config or error
 *
 * @example
 * ```typescript
 * const result = await loadConfig("/path/to/repo");
 * result.match(
 *   (config) => console.log("Loaded config:", config),
 *   (error) => console.error("Failed to load config:", error.message)
 * );
 * ```
 */
export async function loadConfig(
  repoPath: string
): Promise<Result<LightfastConfig, ConfigError>> {
  const configPath = join(repoPath, "lightfast.yml");

  // Read the file
  let fileContent: string;
  try {
    fileContent = await readFile(configPath, "utf-8");
  } catch (error) {
    if (
      error &&
      typeof error === "object" &&
      "code" in error &&
      error.code === "ENOENT"
    ) {
      return err(
        new ConfigError(
          `Configuration file not found: ${configPath}`,
          "FILE_NOT_FOUND",
          error
        )
      );
    }
    return err(
      new ConfigError(
        `Failed to read configuration file: ${configPath}`,
        "READ_ERROR",
        error
      )
    );
  }

  // Parse YAML
  let parsedYAML: unknown;
  try {
    parsedYAML = parseYAML(fileContent);
  } catch (error) {
    return err(
      new ConfigError(
        `Invalid YAML syntax in ${configPath}: ${error instanceof Error ? error.message : String(error)}`,
        "INVALID_YAML",
        error
      )
    );
  }

  // Validate against schema
  return validateConfig(parsedYAML);
}

/**
 * Validate configuration structure against Zod schema
 *
 * @param config - Parsed YAML configuration (unknown type)
 * @returns Result containing validated config or error
 *
 * @example
 * ```typescript
 * const result = validateConfig({ version: 1, store: "docs", include: ["*.md"] });
 * ```
 */
export function validateConfig(
  config: unknown
): Result<LightfastConfig, ConfigError> {
  const parseResult = LightfastConfigSchema.safeParse(config);

  if (!parseResult.success) {
    const zodError = parseResult.error as ZodError;
    const errorMessages = zodError.issues
      .map((e) => `${e.path.join(".")}: ${e.message}`)
      .join("; ");

    return err(
      new ConfigError(
        `Configuration validation failed: ${errorMessages}`,
        "VALIDATION_ERROR",
        zodError
      )
    );
  }

  return ok(parseResult.data);
}

/**
 * Glob pattern utilities for file matching
 *
 * @see docs/architecture/phase1/dx-configuration.md
 */

import fg from "fast-glob";
import { parseError } from "@vendor/observability/error/next";

/**
 * Match files in a repository against glob patterns
 *
 * Uses fast-glob to efficiently match files against multiple patterns.
 * Patterns are repo-relative and use standard glob syntax:
 * - `*` matches any characters except /
 * - `**` matches any characters including /
 * - `?` matches any single character except /
 * - `[abc]` matches any character in the set
 *
 * @param repoPath - Absolute path to the repository root
 * @param globs - Array of glob patterns (repo-relative)
 * @returns Promise resolving to array of matched file paths (repo-relative)
 *
 * @example
 * ```typescript
 * const files = await matchFiles("/path/to/repo", [
 *   "apps/docs/src/content/**\/*.mdx",
 *   "packages/**\/*.md"
 * ]);
 * // Returns: ["apps/docs/src/content/api/search.mdx", ...]
 * ```
 */
export async function matchFiles(
  repoPath: string,
  globs: string[]
): Promise<string[]> {
  try {
    // Use fast-glob to match files
    // cwd: repoPath ensures patterns are resolved relative to repo root
    // ignore: common directories that should be excluded
    const files = await fg(globs, {
      cwd: repoPath,
      ignore: [
        "**/node_modules/**",
        "**/.git/**",
        "**/dist/**",
        "**/build/**",
        "**/.next/**",
        "**/.turbo/**",
      ],
      onlyFiles: true,
      dot: false, // Don't match dotfiles
    });

    // fast-glob returns paths relative to cwd, which is what we want
    return files.sort();
  } catch (error) {
    // If glob matching fails, throw a helpful error
    throw new Error(
      `Failed to match files with globs ${JSON.stringify(globs)}: ${error instanceof Error ? error.message : String(error)}`
    );
  }
}

/**
 * Validate glob patterns for common issues
 *
 * Checks for:
 * - Empty patterns
 * - Absolute paths (patterns should be repo-relative)
 * - Patterns starting with / (should be relative)
 *
 * @param globs - Array of glob patterns to validate
 * @returns Array of error messages (empty if all patterns are valid)
 *
 * @example
 * ```typescript
 * const errors = validateGlobPatterns(["*.md", "/absolute/path/*.md"]);
 * // Returns: ["Pattern '/absolute/path/*.md' should not start with /"]
 * ```
 */
export function validateGlobPatterns(globs: string[]): string[] {
  const errors: string[] = [];

  for (const glob of globs) {
    if (glob.trim().length === 0) {
      errors.push("Glob pattern must not be empty");
      continue;
    }

    if (glob.startsWith("/")) {
      errors.push(
        `Pattern '${glob}' should not start with / (use repo-relative paths)`
      );
    }

    // Check for absolute path indicators on Windows
    if (/^[a-zA-Z]:/.test(glob)) {
      errors.push(
        `Pattern '${glob}' appears to be an absolute path (use repo-relative paths)`
      );
    }
  }

  return errors;
}

/**
 * Check if a file path matches any of the given glob patterns
 *
 * Useful for filtering files during ingestion when you already have a file path
 * and want to check if it matches the configured globs.
 *
 * @param filePath - File path (repo-relative)
 * @param globs - Array of glob patterns
 * @returns true if the file matches any pattern
 *
 * @example
 * ```typescript
 * const matches = matchesGlobs("apps/docs/content/api.mdx", ["**\/*.mdx"]);
 * // Returns: true
 * ```
 */
export function matchesGlobs(filePath: string, globs: string[]): boolean {
  // Check if the file matches any of the patterns
  for (const glob of globs) {
    try {
      // Simple check: does the pattern match the file path?
      // For a more accurate check, we can use micromatch directly
      if (fg.isDynamicPattern(glob)) {
        // Use fast-glob's internal matcher
        const pattern = new RegExp(
          glob
            // 1. Mark glob wildcards with placeholders
            .replace(/\*\*/g, "\0GLOBSTAR\0")
            .replace(/\*/g, "\0STAR\0")
            .replace(/\?/g, "\0QUESTION\0")
            // 2. Escape all regex-special characters in the remaining literal text
            .replace(/[.+^${}()|[\]\\]/g, "\\$&")
            // 3. Restore glob wildcards as regex equivalents
            .replace(/\0GLOBSTAR\0/g, ".*")
            .replace(/\0STAR\0/g, "[^/]*")
            .replace(/\0QUESTION\0/g, "[^/]")
        );
        if (pattern.test(filePath)) {
          return true;
        }
      } else if (filePath === glob) {
        // Exact match
        return true;
      }
    } catch {
      // Ignore invalid glob patterns
    }
  }

  return false;
}

#!/usr/bin/env npx tsx

/**
 * Dataset Verification (Pre-flight Check)
 *
 * Validates all sandbox datasets for:
 * - Required fields on every event
 * - Test data markers (:test: suffix, testData metadata)
 * - Chronological timeline ordering
 * - Cross-source reference consistency (SHAs, issue numbers, identifiers)
 * - Title format correctness per source type
 * - Source distribution sanity
 *
 * Usage:
 *   pnpm --filter @repo/app-test-data verify
 *   npx tsx src/cli/verify-datasets.ts [dataset-name]
 */

import { EVENT_REGISTRY } from "@repo/app-providers";
import type { PostTransformEvent } from "@repo/app-providers/contracts";
import { parseError } from "@vendor/observability/error/next";
import { listDatasets, loadDataset } from "../loader/index.js";

interface VerifyResult {
  dataset: string;
  errors: string[];
  eventCount: number;
  sources: Record<string, number>;
  warnings: string[];
}

function verifyDataset(name: string): VerifyResult {
  const result: VerifyResult = {
    dataset: name,
    eventCount: 0,
    errors: [],
    warnings: [],
    sources: {},
  };

  let ds;
  try {
    ds = loadDataset(name);
  } catch (err: unknown) {
    const message = err instanceof Error ? err.message : String(err);
    result.errors.push(`Failed to load: ${message}`);
    return result;
  }

  result.eventCount = ds.events.length;

  // === Required fields ===
  for (let i = 0; i < ds.events.length; i++) {
    const e = ds.events[i];
    if (!e) {
      continue;
    }
    const prefix = `event[${i}]`;

    // Cast to partial to validate fields that the type claims are required
    const raw = e as Partial<PostTransformEvent>;
    if (!raw.provider) {
      result.errors.push(`${prefix}: missing provider`);
    }
    if (!raw.eventType) {
      result.errors.push(`${prefix}: missing eventType`);
    }
    if (!raw.sourceId) {
      result.errors.push(`${prefix}: missing sourceId`);
    }
    if (!raw.title?.length) {
      result.errors.push(`${prefix}: missing or empty title`);
    }
    if (!raw.body?.length) {
      result.errors.push(`${prefix}: missing or empty body`);
    }

    // Test data markers
    if (!e.sourceId.includes(":test:")) {
      result.errors.push(
        `${prefix}: sourceId missing :test: suffix (got: ${e.sourceId})`
      );
    }
    if (!e.attributes.testData) {
      result.errors.push(`${prefix}: missing testData: true in attributes`);
    }

    // Track source distribution
    result.sources[e.provider] = (result.sources[e.provider] ?? 0) + 1;
  }

  // === Title format checks (derived from EVENT_REGISTRY labels) ===
  // Uses startsWith("[{label}") to handle action-suffixed titles
  // e.g., registry label "Metric Alert" matches both "[Metric Alert Triggered]" and "[Metric Alert Resolved]"
  const titlePrefixCache = new Map<string, string[]>();
  function getTitlePrefixes(source: string): string[] {
    const cached = titlePrefixCache.get(source);
    if (cached !== undefined) {
      return cached;
    }
    const prefixes = [
      ...new Set(
        Object.values(EVENT_REGISTRY)
          .filter((e) => e.source === source)
          .map((e) => `[${e.label}`)
      ),
    ];
    titlePrefixCache.set(source, prefixes);
    return prefixes;
  }

  for (let i = 0; i < ds.events.length; i++) {
    const e = ds.events[i];
    if (!e) {
      continue;
    }
    const prefix = `event[${i}]`;
    const validPrefixes = getTitlePrefixes(e.provider);

    if (
      validPrefixes.length > 0 &&
      !validPrefixes.some((p) => e.title.startsWith(p))
    ) {
      result.errors.push(
        `${prefix}: ${e.provider} title has unexpected format: "${e.title.slice(0, 50)}"`
      );
    }
  }

  // === Chronological ordering ===
  const timestamps = ds.events
    .map((e, i) => ({
      index: i,
      time: e.occurredAt ? new Date(e.occurredAt).getTime() : Number.NaN,
      raw: e.occurredAt,
    }))
    .filter((t) => !Number.isNaN(t.time));

  for (let i = 1; i < timestamps.length; i++) {
    const prev = timestamps[i - 1];
    const curr = timestamps[i];
    if (prev && curr && curr.time < prev.time) {
      result.errors.push(
        `Timeline out of order: event[${prev.index}] (${prev.raw}) > event[${curr.index}] (${curr.raw})`
      );
    }
  }

  // === Cross-source reference consistency ===
  verifyCrossReferences(ds.events, result);

  return result;
}

/**
 * Extract identifiers mentioned across all events and verify consistency
 */
function verifyCrossReferences(
  events: PostTransformEvent[],
  result: VerifyResult
): void {
  // Collect all identifiers mentioned in titles, bodies, and references
  const allText = events
    .map((e) => `${e.title} ${e.body} ${JSON.stringify(e.relations)}`)
    .join(" ");

  // Extract SHA patterns (16+ hex chars that appear in multiple events)
  const shaPattern = /\b([a-f0-9]{16,40})\b/gi;
  const shaMatches = allText.match(shaPattern) ?? [];
  const shaCounts = new Map<string, number>();
  for (const sha of shaMatches) {
    shaCounts.set(sha, (shaCounts.get(sha) ?? 0) + 1);
  }

  // SHAs that appear in multiple places should be consistent
  const crossRefShas = [...shaCounts.entries()].filter(
    ([, count]) => count >= 2
  );
  if (crossRefShas.length > 0) {
    for (const [sha] of crossRefShas) {
      const eventsWithSha = events.filter(
        (e) =>
          e.title.includes(sha) ||
          e.body.includes(sha) ||
          JSON.stringify(e.relations).includes(sha) ||
          JSON.stringify(e.attributes).includes(sha)
      );
      if (eventsWithSha.length < 2) {
        result.warnings.push(
          `SHA ${sha.slice(0, 12)}... appears in text but only ${eventsWithSha.length} event(s) reference it in structured data`
        );
      }
    }
  }

  // Extract issue/PR number patterns like #NNN
  const issuePattern = /#(\d{2,4})\b/g;
  const issueNumbers = new Set<string>();
  let match;
  while ((match = issuePattern.exec(allText)) !== null) {
    const num = match[1];
    if (num) {
      issueNumbers.add(num);
    }
  }

  // For each issue number, verify it appears in at least 2 events (cross-referenced)
  for (const num of issueNumbers) {
    const eventsWithNum = events.filter(
      (e) =>
        e.title.includes(`#${num}`) ||
        e.body.includes(`#${num}`) ||
        JSON.stringify(e.attributes).includes(`"${num}"`)
    );
    if (eventsWithNum.length < 2) {
      result.warnings.push(
        `Issue/PR #${num} only referenced in ${eventsWithNum.length} event(s) - may lack cross-source linking`
      );
    }
  }

  // Extract Linear identifiers like LF-NNN
  const linearPattern = /\b([A-Z]{2,}-\d+)\b/g;
  const linearIds = new Set<string>();
  while ((match = linearPattern.exec(allText)) !== null) {
    const id = match[1];
    if (id) {
      linearIds.add(id);
    }
  }

  for (const id of linearIds) {
    const eventsWithId = events.filter(
      (e) =>
        e.title.includes(id) ||
        e.body.includes(id) ||
        JSON.stringify(e.relations).includes(id)
    );
    if (eventsWithId.length < 2) {
      result.warnings.push(
        `Linear identifier ${id} only referenced in ${eventsWithId.length} event(s)`
      );
    }
  }

  // Extract Sentry short IDs like NEURAL-847
  const sentryPattern = /\b([A-Z]+-\d{3,})\b/g;
  const sentryIds = new Set<string>();
  while ((match = sentryPattern.exec(allText)) !== null) {
    const id = match[1];
    // Filter out Linear identifiers (already tracked)
    if (id && !linearIds.has(id)) {
      sentryIds.add(id);
    }
  }

  for (const id of sentryIds) {
    const eventsWithId = events.filter(
      (e) =>
        e.title.includes(id) ||
        e.body.includes(id) ||
        JSON.stringify(e.relations).includes(id) ||
        JSON.stringify(e.attributes).includes(id)
    );
    if (eventsWithId.length < 2) {
      result.warnings.push(
        `Sentry identifier ${id} only referenced in ${eventsWithId.length} event(s)`
      );
    }
  }
}

// === Main ===
function main() {
  const targetDataset = process.argv[2];
  const names = targetDataset ? [targetDataset] : listDatasets();

  console.log(`\nVerifying ${names.length} dataset(s)...\n`);

  let totalErrors = 0;
  let totalWarnings = 0;

  for (const name of names) {
    const result = verifyDataset(name);

    const status =
      result.errors.length === 0
        ? "\x1b[32mPASS\x1b[0m"
        : "\x1b[31mFAIL\x1b[0m";
    console.log(`${status} ${result.dataset} (${result.eventCount} events)`);

    if (Object.keys(result.sources).length > 0) {
      const sourceSummary = Object.entries(result.sources)
        .map(([s, c]) => `${s}:${c}`)
        .join(", ");
      console.log(`     Sources: ${sourceSummary}`);
    }

    for (const err of result.errors) {
      console.log(`     \x1b[31mERROR\x1b[0m ${err}`);
    }
    for (const warn of result.warnings) {
      console.log(`     \x1b[33mWARN\x1b[0m  ${warn}`);
    }

    totalErrors += result.errors.length;
    totalWarnings += result.warnings.length;
    console.log();
  }

  console.log("---");
  console.log(
    `Total: ${names.length} dataset(s), ${totalErrors} error(s), ${totalWarnings} warning(s)`
  );

  if (totalErrors > 0) {
    console.log("\n\x1b[31mVerification FAILED\x1b[0m");
    process.exit(1);
  } else {
    console.log("\n\x1b[32mAll datasets verified successfully\x1b[0m");
  }
}

main();

import { parseError } from "@vendor/observability/error/next";
import type {
  LanguageModel,
  ModelMessage,
  PrepareStepFunction,
  StopCondition,
  StreamTextOnChunkCallback,
  StreamTextOnFinishCallback,
  StreamTextOnStepFinishCallback,
  StreamTextTransform,
  streamText,
  ToolChoice,
  ToolSet,
  UIMessage,
  UIMessageStreamWriter,
} from "ai";
import { convertToModelMessages } from "ai";
import type { Memory } from "../memory";
import type { RuntimeContext, SystemContext } from "../server/adapters/types";
import {
  AgentConfigurationError,
  CacheOperationError,
  ContextCreationError,
  MessageConversionError,
  NoMessagesError,
  ToolExecutionError,
} from "../server/errors";
import type { ProviderCache } from "./cache";
import type { ToolFactorySet } from "./tool";

// Extract the base streamText parameters type
type StreamTextParams = Parameters<typeof streamText>[0];

// Vercel AI SDK configuration - derived from actual streamText parameters
// We omit the fields that Lightfast handles (messages, tools, system) and re-type with proper generics
export type VercelAIConfig<TOOLS extends ToolSet = ToolSet> = Omit<
  StreamTextParams,
  | "messages"
  | "tools"
  | "system"
  | "prompt"
  | "toolChoice"
  | "stopWhen"
  | "onChunk"
  | "onFinish"
  | "onStepFinish"
  | "prepareStep"
  | "experimental_transform"
> & {
  // Re-type the generic-dependent fields with our TOOLS type
  toolChoice?: ToolChoice<TOOLS>;
  stopWhen?: StopCondition<TOOLS> | StopCondition<TOOLS>[];
  onChunk?: StreamTextOnChunkCallback<TOOLS>;
  onFinish?: StreamTextOnFinishCallback<TOOLS>;
  onStepFinish?: StreamTextOnStepFinishCallback<TOOLS>;
  prepareStep?: PrepareStepFunction<TOOLS>;
  experimental_transform?:
    | StreamTextTransform<TOOLS>
    | StreamTextTransform<TOOLS>[];
};

// Lightfast-specific configuration
export interface LightfastConfig<
  TRuntimeContext = {},
  TTools extends ToolFactorySet<
    RuntimeContext<TRuntimeContext>
  > = ToolFactorySet<RuntimeContext<TRuntimeContext>>,
> {
  // Optional Lightfast features
  cache?: ProviderCache;
  createRuntimeContext?: (params: {
    // Optional - user might not need runtime context
    sessionId: string;
    resourceId: string;
  }) => TRuntimeContext;
  // Required Lightfast fields
  name: string;
  system: string;
  tools?: TTools | ((context: TRuntimeContext) => TTools); // Optional - user might not have tools
}

export interface StreamOptions<
  TMessage extends UIMessage = UIMessage,
  TRequestContext = {},
  TMemoryContext = {},
> {
  dataStream?: UIMessageStreamWriter<TMessage>; // UIMessageStreamWriter for artifact support with proper generic
  memory: Memory<TMessage, TMemoryContext>;
  messages: TMessage[];
  requestContext: TRequestContext;
  resourceId: string;
  sessionId: string;
  systemContext: SystemContext;
}

// Combined options for creating an agent
export interface AgentOptions<
  TRuntimeContext = {},
  TTools extends ToolFactorySet<
    RuntimeContext<TRuntimeContext>
  > = ToolFactorySet<RuntimeContext<TRuntimeContext>>,
> extends LightfastConfig<TRuntimeContext, TTools>,
    VercelAIConfig<ToolSet> {
  // All fields are inherited from the two interfaces
  // Note: VercelAIConfig uses ToolSet since factories are resolved to tools at runtime
}

export class Agent<
  TRuntimeContext = {},
  TTools extends ToolFactorySet<
    RuntimeContext<TRuntimeContext>
  > = ToolFactorySet<RuntimeContext<TRuntimeContext>>,
> {
  // Clean separation: Vercel AI SDK config vs Lightfast config
  private readonly vercelConfig: VercelAIConfig<ToolSet>;
  private readonly lightfastConfig: LightfastConfig<TRuntimeContext, TTools>;

  constructor(options: AgentOptions<TRuntimeContext, TTools>) {
    // Destructure into Lightfast and Vercel configs
    const {
      // Lightfast-specific fields
      name,
      system,
      tools,
      createRuntimeContext,
      cache,
      // Everything else is Vercel AI SDK config
      ...vercelConfig
    } = options;

    // Store Lightfast configuration
    this.lightfastConfig = {
      name,
      system,
      tools,
      createRuntimeContext,
      cache,
    };

    // Store Vercel AI SDK configuration
    this.vercelConfig = vercelConfig as VercelAIConfig<ToolSet>;
  }

  // Public getter for agent name
  get name(): string {
    return this.lightfastConfig.name;
  }

  // Public getter for the model (commonly needed)
  get model(): LanguageModel {
    return this.vercelConfig.model;
  }

  /**
   * Builds parameters for streamText for the given messages and context
   * Returns an object that can be directly passed to streamText
   * Does not actually call streamText - that's handled by runtime.ts
   */
  buildStreamParams<
    TMessage extends UIMessage = UIMessage,
    TRequestContext = {},
    TMemoryContext = {},
  >({
    sessionId,
    messages,
    memory: _memory,
    resourceId,
    systemContext,
    requestContext,
    dataStream,
  }: StreamOptions<TMessage, TRequestContext, TMemoryContext>): Parameters<
    typeof streamText
  >[0] {
    // IMPORTANT: Do NOT refactor to `messages?.length === 0` — optional chaining returns
    // undefined for null/undefined, which !== 0, silently bypassing this guard.
    if (!messages || messages.length === 0) {
      throw new NoMessagesError();
    }

    // Create agent-specific runtime context if provided
    let agentContext: TRuntimeContext | {} = {};
    if (this.lightfastConfig.createRuntimeContext) {
      try {
        agentContext = this.lightfastConfig.createRuntimeContext({
          sessionId,
          resourceId,
        });
      } catch (error) {
        throw new ContextCreationError(
          "runtime",
          error instanceof Error ? error.message : String(error),
          error instanceof Error ? error : undefined
        );
      }
    }

    // Merge all context levels: system -> request -> agent -> dataStream
    // The merged context is what tools actually receive
    const mergedContext: SystemContext &
      TRequestContext &
      TRuntimeContext & { dataStream?: UIMessageStreamWriter<TMessage> } = {
      ...systemContext,
      ...requestContext,
      ...agentContext,
      ...(dataStream && { dataStream }), // Add dataStream if provided
    } as SystemContext &
      TRequestContext &
      TRuntimeContext & { dataStream?: UIMessageStreamWriter<TMessage> };

    // Resolve tool factories into actual tools by injecting merged context
    const resolvedTools: ToolSet = {};
    if (this.lightfastConfig.tools) {
      const tools =
        typeof this.lightfastConfig.tools === "function"
          ? this.lightfastConfig.tools(mergedContext as TRuntimeContext)
          : this.lightfastConfig.tools;

      // Validate tools is a valid object
      if (!tools || typeof tools !== "object") {
        throw new ToolExecutionError(
          "tools",
          "Tools resolution returned null, undefined, or non-object value"
        );
      }

      for (const [name, factory] of Object.entries(tools)) {
        try {
          resolvedTools[name] = factory(
            mergedContext as unknown as RuntimeContext<TRuntimeContext>
          );
        } catch (error) {
          throw new ToolExecutionError(
            name,
            `Failed to resolve tool factory '${name}': ${error instanceof Error ? error.message : String(error)}`,
            error instanceof Error ? error : undefined
          );
        }
      }
    }

    // Ensure model is set
    if (!this.vercelConfig.model) {
      throw new AgentConfigurationError("model", "Model must be configured");
    }

    // Convert system config to messages with cache control
    let systemMessages: ModelMessage[] = [];
    let modelMessages: ModelMessage[];

    if (this.lightfastConfig.cache) {
      try {
        // Use provider cache implementation
        systemMessages = this.lightfastConfig.cache.applySystemCaching(
          this.lightfastConfig.system
        );

        // Convert messages to model messages
        const baseModelMessages = convertToModelMessages(messages, {
          tools: resolvedTools,
        });

        // Apply message caching
        modelMessages = this.lightfastConfig.cache.applyMessageCaching(
          baseModelMessages,
          messages
        );
      } catch (error) {
        throw new CacheOperationError(
          "system and message caching",
          error instanceof Error ? error.message : String(error),
          error instanceof Error ? error : undefined
        );
      }
    } else {
      try {
        // No cache provider - use simple system message
        systemMessages.push({
          role: "system",
          content: this.lightfastConfig.system,
        });

        // Convert messages without caching
        modelMessages = convertToModelMessages(messages, {
          tools: resolvedTools,
        });
      } catch (error) {
        throw new MessageConversionError(
          "convert to model messages",
          error instanceof Error ? error.message : String(error),
          error instanceof Error ? error : undefined
        );
      }
    }

    // Prepend system messages to the model messages
    // This way we maintain proper typing
    const allModelMessages = [...systemMessages, ...modelMessages];

    // Return the parameters for streamText
    // The actual streaming is handled by runtime.ts
    return {
      // Spread all Vercel AI SDK config
      ...this.vercelConfig,
      // Override with our specific runtime values
      messages: allModelMessages,
      tools: resolvedTools,
    } as Parameters<typeof streamText>[0];
  }

  // Expose config for testing or inspection
  get config(): LightfastConfig<TRuntimeContext, TTools> &
    VercelAIConfig<ToolSet> {
    return {
      ...this.lightfastConfig,
      ...this.vercelConfig,
    };
  }
}

/**
 * Factory function to create an agent with proper type inference
 * All tools must be created using createTool() which returns ToolFactory functions
 */
export function createAgent<
  TRuntimeContext = {},
  TTools extends ToolFactorySet<
    RuntimeContext<TRuntimeContext>
  > = ToolFactorySet<RuntimeContext<TRuntimeContext>>,
>(
  options: AgentOptions<TRuntimeContext, TTools>
): Agent<TRuntimeContext, TTools> {
  return new Agent(options);
}

import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { isContractProcedure } from "@orpc/contract";
import { parseError } from "@vendor/observability/error/next";

// ---------------------------------------------------------------------------
// Re-exports — MCP SDK essentials
// ---------------------------------------------------------------------------

export { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
export { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";

// ---------------------------------------------------------------------------
// Contract-to-MCP adapter
// ---------------------------------------------------------------------------

export interface RegisterContractToolsOptions {
  /** Prefix for all tool names (e.g. "lightfast" -> "lightfast_search"). */
  prefix?: string;
  /** Separator between key path segments. Default: "_" */
  separator?: string;
}

/**
 * Walk an oRPC contract router and register each procedure as an MCP tool.
 *
 * Tool names are derived from the router key path joined with the separator.
 * Input schemas from the contract are passed directly to `registerTool` —
 * the MCP SDK validates incoming tool calls against the same Zod schemas
 * used by the API.
 *
 * @example
 * ```ts
 * registerContractTools(server, apiContract, client, { prefix: "lightfast" });
 * // Registers: lightfast_search, lightfast_proxy_search, lightfast_proxy_execute
 * ```
 */
export function registerContractTools(
  server: McpServer,
  contract: Record<string, unknown>,
  client: Record<string, unknown>,
  options?: RegisterContractToolsOptions
): void {
  const prefix = options?.prefix;
  const sep = options?.separator ?? "_";

  function walk(
    contractNode: unknown,
    clientNode: unknown,
    keyPath: string[]
  ): void {
    if (isContractProcedure(contractNode)) {
      const def = (
        contractNode as {
          "~orpc": {
            route?: { description?: string; summary?: string };
            inputSchema?: unknown;
            outputSchema?: unknown;
          };
        }
      )["~orpc"];

      const toolName = prefix
        ? [prefix, ...keyPath].join(sep)
        : keyPath.join(sep);

      const description =
        def.route?.description ?? def.route?.summary ?? toolName;

      const fn = clientNode as (...args: unknown[]) => Promise<unknown>;

      const handle = async (...args: unknown[]) => {
        try {
          // With inputSchema: args = [parsedInput, extra]
          // Without inputSchema: args = [extra]
          const input = def.inputSchema ? args[0] : undefined;
          const result = input !== undefined ? await fn(input) : await fn();
          return {
            structuredContent: result as Record<string, unknown>,
          };
        } catch (error) {
          return {
            content: [
              {
                type: "text" as const,
                text: error instanceof Error ? error.message : String(error),
              },
            ],
            isError: true,
          };
        }
      };

      const config: Record<string, unknown> = { description };
      if (def.inputSchema) {
        config.inputSchema = def.inputSchema;
      }
      if (def.outputSchema) {
        config.outputSchema = def.outputSchema;
      }

      server.registerTool(toolName, config as any, handle as any);
      return;
    }

    // Recurse into nested router objects
    if (contractNode && typeof contractNode === "object") {
      for (const key in contractNode as Record<string, unknown>) {
        if (Object.hasOwn(contractNode as Record<string, unknown>, key)) {
          walk(
            (contractNode as Record<string, unknown>)[key],
            (clientNode as Record<string, unknown>)[key],
            [...keyPath, key]
          );
        }
      }
    }
  }

  walk(contract, client, []);
}

/**
 * Pinecone client wrapper built on the official SDK.
 *
 * Provides typed vector operations and index name helpers tailored to our store model.
 */

import type { RecordMetadata } from "@pinecone-database/pinecone";
import { Pinecone } from "@pinecone-database/pinecone";
import { parseError } from "@vendor/observability/error/next";

import { env } from "./env";
import {
  PineconeConnectionError,
  PineconeError,
  PineconeInvalidRequestError,
  PineconeNotFoundError,
  PineconeRateLimitError,
} from "./errors";
import type {
  FetchResponse,
  QueryRequest,
  QueryResponse,
  UpdateRequest,
  UpsertRequest,
  UpsertResponse,
} from "./types";

export class PineconeClient {
  private readonly client: Pinecone;

  constructor() {
    this.client = new Pinecone({
      apiKey: env.PINECONE_API_KEY,
    });
  }

  /**
   * Create a new Pinecone index (serverless)
   *
   * All parameters are required - caller must provide explicit configuration.
   * Use application-level wrapper (@repo/app-pinecone) for defaults.
   *
   * @param indexName - Name of the index to create
   * @param dimension - Embedding dimension
   * @param options - Required configuration
   */
  async createIndex(
    indexName: string,
    dimension: number,
    options: {
      metric: "cosine" | "euclidean" | "dotproduct";
      cloud: "aws" | "gcp" | "azure";
      region: string;
    }
  ): Promise<void> {
    try {
      await this.client.createIndex({
        name: indexName,
        dimension,
        metric: options.metric,
        spec: {
          serverless: {
            cloud: options.cloud,
            region: options.region,
          },
        },
        suppressConflicts: true,
        waitUntilReady: true,
      });
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Check if an index exists
   *
   * @param indexName - Name of the index to check
   * @returns true if index exists, false otherwise
   */
  async indexExists(indexName: string): Promise<boolean> {
    try {
      const indexes = await this.client.listIndexes();
      const indexList = indexes.indexes ?? [];
      return indexList.some((index) => index.name === indexName);
    } catch (error) {
      // If list fails, assume index doesn't exist
      console.warn(`Failed to check index existence: ${String(error)}`);
      return false;
    }
  }

  /**
   * Delete a Pinecone index
   */
  async deleteIndex(indexName: string): Promise<void> {
    try {
      await this.client.deleteIndex(indexName);
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Upsert vectors into an index
   *
   * Generic method - works with any metadata type extending RecordMetadata
   *
   * @param indexName - Name of the index
   * @param request - Upsert request with vectors and metadata
   * @param batchSize - Number of vectors to upsert per batch
   * @param namespace - Optional namespace for data isolation
   */
  async upsertVectors<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    request: UpsertRequest<T>,
    batchSize = 100,
    namespace?: string
  ): Promise<UpsertResponse> {
    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      for (let i = 0; i < request.ids.length; i += batchSize) {
        const ids = request.ids.slice(i, i + batchSize);
        const vectors = request.vectors.slice(i, i + batchSize);
        const metadata = request.metadata.slice(i, i + batchSize);

        const records = vectors.map((values, offset) => {
          const id = ids[offset];
          const meta = metadata[offset];
          if (id === undefined || meta === undefined) {
            throw new PineconeInvalidRequestError(
              `Missing id or metadata at offset ${String(offset)}`
            );
          }
          return { id, values, metadata: meta };
        });

        await targetNamespace.upsert(records);
      }

      return { upsertedCount: request.ids.length };
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Delete vectors by IDs
   *
   * @param indexName - Name of the index
   * @param vectorIds - Array of vector IDs to delete
   * @param batchSize - Number of vectors to delete per batch
   * @param namespace - Optional namespace for data isolation
   */
  async deleteVectors(
    indexName: string,
    vectorIds: string[],
    batchSize = 100,
    namespace?: string
  ): Promise<void> {
    if (vectorIds.length === 0) {
      return;
    }

    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      for (let i = 0; i < vectorIds.length; i += batchSize) {
        const batch = vectorIds.slice(i, i + batchSize);
        await targetNamespace.deleteMany(batch);
      }
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Delete vectors matching a metadata filter
   *
   * @param indexName - Name of the index
   * @param filter - Metadata filter object
   * @param namespace - Optional namespace for data isolation
   */
  async deleteByMetadata(
    indexName: string,
    filter: object,
    namespace?: string
  ): Promise<void> {
    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      await targetNamespace.deleteMany(filter);
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Configure index level settings (deletion protection, tags, etc.)
   */
  async configureIndex(
    indexName: string,
    options: {
      deletionProtection?: "enabled" | "disabled";
      tags?: Record<string, string>;
      spec?: unknown;
    }
  ): Promise<void> {
    try {
      await this.client.configureIndex(indexName, {
        deletionProtection: options.deletionProtection,
        spec: options.spec as never,
        tags: options.tags,
      });
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Query similar vectors
   *
   * Generic method - works with any metadata type extending RecordMetadata
   *
   * @param indexName - Name of the index
   * @param request - Query request with vector and filters
   * @param namespace - Optional namespace for data isolation
   */
  async query<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    request: QueryRequest,
    namespace?: string
  ): Promise<QueryResponse<T>> {
    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      const results = await targetNamespace.query({
        vector: request.vector,
        topK: request.topK,
        filter: request.filter,
        includeMetadata: request.includeMetadata ?? true,
      });

      return {
        matches: results.matches.map((match) => ({
          id: match.id,
          score: match.score ?? 0,
          metadata: match.metadata as T,
        })),
      };
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Fetch vectors by IDs
   *
   * @param indexName - Name of the index
   * @param vectorIds - Array of vector IDs to fetch
   * @param namespace - Optional namespace for data isolation
   */
  async fetchVectors<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    vectorIds: string[],
    namespace?: string
  ): Promise<FetchResponse<T>> {
    if (vectorIds.length === 0) {
      return { records: {} };
    }

    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      const result = await targetNamespace.fetch(vectorIds);

      const records: FetchResponse<T>["records"] = {};
      for (const [id, record] of Object.entries(result.records)) {
        if (record.values) {
          records[id] = {
            id: record.id,
            values: record.values,
            metadata: record.metadata as T,
          };
        }
      }

      return { records };
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Update a vector's metadata
   *
   * @param indexName - Name of the index
   * @param request - Update request with vector ID and metadata
   * @param namespace - Optional namespace for data isolation
   */
  async updateVectorMetadata<T extends RecordMetadata = RecordMetadata>(
    indexName: string,
    request: UpdateRequest<T>,
    namespace?: string
  ): Promise<void> {
    const index = this.client.index(indexName);
    const targetNamespace = namespace ? index.namespace(namespace) : index;

    try {
      await targetNamespace.update({
        id: request.id,
        metadata: request.metadata,
      });
    } catch (error) {
      this.handleError(error);
    }
  }

  /**
   * Handle and transform errors
   */
  private handleError(error: unknown): never {
    if (error instanceof PineconeError) {
      throw error;
    }

    const message = error instanceof Error ? error.message : String(error);
    const lowerMessage = message.toLowerCase();

    if (lowerMessage.includes("rate limit") || lowerMessage.includes("429")) {
      throw new PineconeRateLimitError("Rate limit exceeded", error);
    }

    if (lowerMessage.includes("not found") || lowerMessage.includes("404")) {
      throw new PineconeNotFoundError("Index or resource not found", error);
    }

    if (
      lowerMessage.includes("invalid") ||
      lowerMessage.includes("dimension") ||
      lowerMessage.includes("400")
    ) {
      throw new PineconeInvalidRequestError("Invalid request", error);
    }

    if (
      lowerMessage.includes("connection") ||
      lowerMessage.includes("network")
    ) {
      throw new PineconeConnectionError("Connection error", error);
    }

    throw new PineconeError("Pinecone operation failed", "UNKNOWN", error);
  }
}

export function createPineconeClient(): PineconeClient {
  return new PineconeClient();
}

